function buildFrontendActivityOverrideKey(activityId?: string, skuKey?: string) {
  const normalizedSkuKey = String(skuKey || '').trim()
  const normalizedActivityId = String(activityId || '').trim()
  if (!normalizedActivityId) return normalizedSkuKey
  return `${normalizedActivityId}::${normalizedSkuKey}`
}

function buildPhoneDisplayMeta(customerPhone?: string, agentPhone?: string) {
  const normalizedCustomerPhone = String(customerPhone || '').trim()
  const normalizedAgentPhone = String(agentPhone || '').trim()
  const primaryPhone = normalizedCustomerPhone || normalizedAgentPhone || '待补'
  const secondaryPhone = normalizedCustomerPhone && normalizedAgentPhone && normalizedCustomerPhone !== normalizedAgentPhone
    ? `代扫电话 ${normalizedAgentPhone}`
    : ''
  return { primaryPhone, secondaryPhone }
}

function buildPhoneDisplayMetaFromList(customerPhones: string[], agentPhones: string[]) {
  const normalizedCustomerPhone = customerPhones.filter(Boolean).join(' / ')
  const normalizedAgentPhone = agentPhones.filter(Boolean).join(' / ')
  const primaryPhone = normalizedCustomerPhone || normalizedAgentPhone || '待补'
  const secondaryPhone = normalizedCustomerPhone && normalizedAgentPhone && normalizedCustomerPhone !== normalizedAgentPhone
    ? `代扫电话 ${normalizedAgentPhone}`
    : ''
  return { primaryPhone, secondaryPhone }
}

function joinDisplayParts(parts: Array<string | null | undefined>) {
  return parts.map((entry) => String(entry || '').trim()).filter(Boolean).join(' · ')
}

function summarizeAuditMessage(message?: string) {
  const normalized = String(message || '').replace(/\s+/g, ' ').trim()
  if (!normalized) return '待补说明'
  const firstSentence = normalized.split(/[。；;]/)[0]?.trim() || normalized
  return firstSentence.length > 30 ? `${firstSentence.slice(0, 30)}...` : firstSentence
}

