function readPersistedUiState(): PersistedUiState {
  if (typeof window === 'undefined') return {}
  try {
    const raw = window.localStorage.getItem(uiStateStorageKey)
    return raw ? JSON.parse(raw) as PersistedUiState : {}
  } catch (error) {
    console.warn('读取界面状态失败', error)
    return {}
  }
}

function writePersistedUiState(nextState: PersistedUiState) {
  if (typeof window === 'undefined') return
  try {
    const current = readPersistedUiState()
    window.localStorage.setItem(uiStateStorageKey, JSON.stringify({ ...current, ...nextState }))
  } catch (error) {
    console.warn('保存界面状态失败', error)
  }
}

function getPersistedUiValue<T>(key: keyof PersistedUiState, fallback: T) {
  const value = readPersistedUiState()[key]
  return (value ?? fallback) as T
}

function preserveScrollPosition(work: () => void) {
  if (typeof window === 'undefined') return work()
  const scrollY = window.scrollY
  work()
  window.requestAnimationFrame(() => {
    if (Math.abs(window.scrollY - scrollY) > 12) {
      window.scrollTo(window.scrollX, scrollY)
    }
  })
}

