        const settlementMode: CrossOutboundCheckMode = row.settlementMode === 'perUnitAmount' ? 'perUnitAmount' : 'priceDiff'
        const calculationBasis: CrossOutboundCheckCalculationBasis = row.calculationBasis === 'salesPrice' ? 'salesPrice' : 'purchaseCost'
