function mergeCrossOutboundCheckRules(
  primary: CrossOutboundCheckRule[],
  fallback: CrossOutboundCheckRule[],
): CrossOutboundCheckRule[] {
  const merged = new Map<string, CrossOutboundCheckRule>()
  const upsert = (item: CrossOutboundCheckRule) => {
    const current = merged.get(item.id)
    if (!current) {
      merged.set(item.id, item)
      return
    }
    const currentUpdatedAt = Date.parse(current.updatedAt || '')
    const nextUpdatedAt = Date.parse(item.updatedAt || '')
    if (Number.isFinite(nextUpdatedAt) && (!Number.isFinite(currentUpdatedAt) || nextUpdatedAt >= currentUpdatedAt)) {
      merged.set(item.id, item)
    }
  }
  fallback.forEach(upsert)
  primary.forEach(upsert)
  return Array.from(merged.values()).sort((a, b) => {
    const diff = Date.parse(b.updatedAt || '') - Date.parse(a.updatedAt || '')
    if (Number.isFinite(diff) && diff !== 0) return diff
    return a.id.localeCompare(b.id)
  })
}

