function readPromptWorkspaceKitJson<T>(key: string, fallback: T): T {
  if (typeof window === 'undefined') return fallback
  try {
    const raw = window.localStorage.getItem(key)
    return raw ? JSON.parse(raw) as T : fallback
  } catch (error) {
    console.warn('读取提问工作台本地数据失败', error)
    return fallback
  }
}

function writePromptWorkspaceKitJson<T>(key: string, value: T) {
  if (typeof window === 'undefined') return
  try {
    window.localStorage.setItem(key, JSON.stringify(value))
  } catch (error) {
    console.warn('写入提问工作台本地数据失败', error)
  }
}

function createPromptWorkspaceKitDraft(projectName = '联想智慧零售系统'): PromptWorkspaceKitDraft {
  return {
    title: '高精度任务提问模板',
    primaryCategory: '主提问内容',
    secondaryCategory: '默认流程',
    sequenceNo: 10,
    projectName,
    systemPurpose: '完成整个店面的智能化经营',
    existingContext: '已经有完善的运行逻辑和商业化规则化',
    taskGoal: '',
    agentTarget: 'Codex + OpenClaw',
    taskType: 'UI/UX 重构',
    repoScope: '当前前端工程 / 提问工作台模块',
    constraints: '',
    outputFormat: '先给修改计划，再给文件级改动，最后给测试与验收清单。',
    manualContext: '',
    keywords: '',
    acceptanceFocus: '',
  }
}

function createPromptWorkspaceKitDefaultState(projectId: string, projectName: string): PromptWorkspaceKitProjectState {
  return {
    projectId,
    knowledge: [
      {
        id: createPromptWorkspaceKitId('knowledge'),
        title: '移动端布局规则',
        tags: ['mobile', 'ui', 'responsive'],
        body: '移动端使用单列结构，答题输入、生成结果、会话看板依次堆叠；底部使用固定导航；任何面板宽度不得依赖桌面固定值。',
        createdAt: new Date().toISOString(),
      },
      {
        id: createPromptWorkspaceKitId('knowledge'),
        title: '项目级知识隔离规则',
        tags: ['project-isolation', 'storage', 'namespace'],
        body: '所有知识库、会话、提示词版本和任务卡都必须以 projectId 作为命名空间保存。切换项目时只能读取当前项目的数据。',
        createdAt: new Date().toISOString(),
      },
    ],
    sessions: [
      {
        id: createPromptWorkspaceKitId('session'),
        role: 'system',
        title: '系统初始化',
        body: '已创建当前项目独立命名空间，可开始写入知识、生成提示词和拆分任务卡。',
        createdAt: new Date().toISOString(),
      },
    ],
    prompts: [],
    taskCards: [],
    moduleConfigs: promptWorkspaceKitModuleCatalog.map((item) => ({
      moduleId: item.moduleId,
      label: item.label,
      provider: item.provider,
      endpoint: item.endpoint,
      apiKey: '',
      description: item.description,
      updatedAt: new Date().toISOString(),
    })),
    lastDraft: createPromptWorkspaceKitDraft(projectName),
  }
}

function readPromptWorkspaceKitRegistry() {
  return readPromptWorkspaceKitJson<PromptWorkspaceKitRegistry>(promptWorkspaceKitRegistryKey, {
    activeProjectId: '',
    projects: [],
  })
}

function writePromptWorkspaceKitRegistry(projects: PromptWorkspaceKitProjectMeta[], activeProjectId: string) {
  writePromptWorkspaceKitJson(promptWorkspaceKitRegistryKey, { projects, activeProjectId })
  writePromptWorkspaceKitJson(promptWorkspaceKitProjectsKey, projects)
  if (typeof window !== 'undefined' && activeProjectId) {
    window.localStorage.setItem(promptWorkspaceKitActiveProjectKey, activeProjectId)
  }
}

function ensurePromptWorkspaceKitProjects() {
  const registry = readPromptWorkspaceKitRegistry()
  const existingProjects = registry.projects.length
    ? registry.projects
    : readPromptWorkspaceKitJson<PromptWorkspaceKitProjectMeta[]>(promptWorkspaceKitProjectsKey, [])
  if (existingProjects.length) return existingProjects
  const defaultProjectId = createPromptWorkspaceKitId('project')
  const defaultProject: PromptWorkspaceKitProjectMeta = {
    id: defaultProjectId,
    name: '联想智慧零售系统',
    description: '默认提示词工程',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  }
  writePromptWorkspaceKitRegistry([defaultProject], defaultProjectId)
  writePromptWorkspaceKitJson(
    getPromptWorkspaceKitProjectStorageKey(defaultProjectId),
    createPromptWorkspaceKitDefaultState(defaultProjectId, defaultProject.name),
  )
  return [defaultProject]
}

function readPromptWorkspaceKitProjects() {
  return ensurePromptWorkspaceKitProjects()
}

function readPromptWorkspaceKitActiveProjectId(projects = readPromptWorkspaceKitProjects()) {
  if (typeof window === 'undefined') return projects[0]?.id ?? ''
  const registry = readPromptWorkspaceKitRegistry()
  const activeProjectId = registry.activeProjectId || window.localStorage.getItem(promptWorkspaceKitActiveProjectKey)
  if (activeProjectId && projects.some((item) => item.id === activeProjectId)) return activeProjectId
  const fallbackId = projects[0]?.id ?? ''
  if (fallbackId) writePromptWorkspaceKitRegistry(projects, fallbackId)
  return fallbackId
}

function readPromptWorkspaceKitProjectState(projectId: string, projectName = '联想智慧零售系统') {
  const fallback = createPromptWorkspaceKitDefaultState(projectId, projectName)
  const state = readPromptWorkspaceKitJson<PromptWorkspaceKitProjectState>(
    getPromptWorkspaceKitProjectStorageKey(projectId),
    fallback,
  )
  return {
    ...fallback,
    ...state,
    knowledge: Array.isArray(state.knowledge) ? state.knowledge : fallback.knowledge,
    sessions: Array.isArray(state.sessions) ? state.sessions : fallback.sessions,
    prompts: Array.isArray(state.prompts) ? state.prompts : fallback.prompts,
    taskCards: Array.isArray(state.taskCards) ? state.taskCards : fallback.taskCards,
    moduleConfigs: promptWorkspaceKitModuleCatalog.map((item) => {
      const existing = Array.isArray(state.moduleConfigs)
        ? state.moduleConfigs.find((config) => config?.moduleId === item.moduleId)
        : null
      return {
        moduleId: item.moduleId,
        label: item.label,
        provider: item.provider,
        endpoint: existing?.endpoint?.trim() || item.endpoint,
        apiKey: existing?.apiKey ?? '',
        description: existing?.description?.trim() || item.description,
        updatedAt: existing?.updatedAt || new Date().toISOString(),
      } satisfies PromptWorkspaceKitModuleConfig
    }),
    lastDraft: state.lastDraft ?? fallback.lastDraft,
  } satisfies PromptWorkspaceKitProjectState
}

function savePromptWorkspaceKitProjectState(state: PromptWorkspaceKitProjectState) {
  writePromptWorkspaceKitJson(getPromptWorkspaceKitProjectStorageKey(state.projectId), state)
}

function retrievePromptWorkspaceKitKnowledge(
  state: PromptWorkspaceKitProjectState,
  draft: PromptWorkspaceKitDraft,
) {
  const terms = [
    draft.title,
    draft.primaryCategory,
    draft.secondaryCategory,
    draft.taskGoal,
    draft.constraints,
    draft.manualContext,
    draft.keywords,
  ]
    .join('\n')
    .toLowerCase()
    .split(/[\s,，。；;:：/\\|]+/)
    .filter((item) => item.length > 1)
  return state.knowledge
    .map((item) => {
      const haystack = `${item.title} ${item.tags.join(' ')} ${item.body}`.toLowerCase()
      const score = terms.reduce((total, term) => total + (haystack.includes(term) ? 1 : 0), 0)
      return { item, score }
    })
    .sort((left, right) => right.score - left.score || right.item.createdAt.localeCompare(left.item.createdAt))
    .filter((item) => item.score > 0)
    .slice(0, 5)
    .map((item) => item.item)
}

function buildPromptWorkspaceKitPrompt(
  project: PromptWorkspaceKitProjectMeta,
  state: PromptWorkspaceKitProjectState,
  draft: PromptWorkspaceKitDraft,
) {
  const knowledgeItems = retrievePromptWorkspaceKitKnowledge(state, draft)
  const knowledgeBlock = knowledgeItems.length
    ? knowledgeItems
        .map((item, index) => `${index + 1}. [${item.tags.join(', ') || 'untagged'}] ${item.title}: ${item.body}`)
        .join('\n')
    : '当前项目知识库暂无命中内容，请先从当前仓库和已知规则中补齐上下文。'
  const hardConstraints = splitMultilineInput(draft.constraints).length
    ? splitMultilineInput(draft.constraints)
    : [
        '不允许破坏现有项目。',
        '先分析需求，再执行。',
        '输出必须包含验收清单、回滚方案和测试命令。',
      ]
  const acceptanceItems = splitMultilineInput(draft.acceptanceFocus).length
    ? splitMultilineInput(draft.acceptanceFocus)
    : [
        '不能有占位内容。',
        '不能有空页面。',
        '不能把未完成说成已完成。',
      ]
  return [
    `# ${draft.agentTarget} 可执行任务提示词`,
    '',
    '## 1. 背景',
    `- 当前项目是：${draft.projectName}`,
    `- 系统用途：${draft.systemPurpose}`,
    `- 已有内容：${draft.existingContext}`,
    `- 项目命名空间：${getPromptWorkspaceKitProjectStorageKey(project.id)}`,
    `- 主分类：${draft.primaryCategory}`,
    `- 次分类：${draft.secondaryCategory}`,
    `- 序号：${formatPromptWorkspaceSequence(draft.sequenceNo)}`,
    '',
    '## 2. 任务定义',
    `- 标题：${draft.title}`,
    `- 任务类型：${draft.taskType}`,
    `- 执行对象：${draft.agentTarget}`,
    `- 仓库范围：${draft.repoScope}`,
    '',
    '## 3. 目标',
    draft.taskGoal || '请根据当前项目需要输出完整的执行方案与代码改动。',
    '',
    '## 4. 当前项目知识库检索结果',
    '以下知识只允许来自当前项目，禁止跨项目读取或污染：',
    knowledgeBlock,
    '',
    '## 5. 人工补充上下文',
    draft.manualContext.trim() || '无额外人工上下文。',
    '',
    '## 6. 硬性约束',
    ...hardConstraints.map((item) => `- ${item}`),
    '',
    '## 7. 执行步骤',
    '1. 先分析需求，明确本轮只做什么、不做什么、改哪些文件、如何验证。',
    '2. 先检查现有入口页面、样式结构、状态管理和数据存储逻辑。',
    '3. 按“项目隔离 -> 答题板 -> 会话看板 -> 知识库 -> 验收看板 -> 移动端适配”的顺序实施。',
    '4. 所有知识、会话、提示词版本、任务卡都必须绑定 projectId 命名空间。',
    '5. 生成内容必须可直接执行，不要只给建议和空泛说明。',
    '',
    '## 8. 输出格式',
    draft.outputFormat.trim() || '输出：修改计划、文件级改动、关键代码、验收步骤、回滚方案。',
    '',
    '## 9. 验收标准',
    ...acceptanceItems.map((item) => `- ${item}`),
    '',
    '## 10. 失败修复与回滚',
    '- 如果布局溢出、数据跨项目污染或提示词内容缺字段，立即回退最近一次相关改动。',
    '- 补充断点验证、命名空间断言和验收记录后再重新生成。',
    '- 输出本轮失败原因、修复补丁和最终验证结果。',
  ].join('\n')
}

