function shortFileName(filePath?: string) {
  if (!filePath) return '未找到文件'
  return filePath.split('/').at(-1) ?? filePath
}

const inventoryCategoryDisplayNameMap: Record<string, string> = {
  商务台式: '办公电脑',
}

const inventoryCategoryAliasMap: Record<string, string> = {
  办公电脑: '商务台式',
  耳机耳麦: '耳机音箱',
  耳机: '耳机音箱',
  音箱: '耳机音箱',
  Lenovo显示器: '显示器',
  拯救者显示器: '显示器',
  小新平板: '平板电脑',
  拯救者平板: '平板电脑',
  YOGA平板: '平板电脑',
  '拯救者火力强化（UIY管控）': '游戏笔记本',
}

const inventoryCategoryPrimaryOrder = [
  '游戏笔记本',
  '轻薄笔记本',
  '游戏主机',
  '一体机',
  '商务台式',
  '平板电脑',
  '平板配件',
  '手机',
  '电脑配件',
  '显示器',
  '耳机音箱',
  '打印机',
  '智能生活',
] as const

function getInventoryCategoryKey(category?: string) {
  if (!category) return '未分类'
  return inventoryCategoryAliasMap[category] ?? category
}

function getInventoryCategoryDisplayName(category?: string) {
  const key = getInventoryCategoryKey(category)
  return inventoryCategoryDisplayNameMap[key] ?? key
}

function normalizeInventoryCategoryByText(input?: { category?: string; productName?: string }) {
  const rawCategory = String(input?.category ?? '').trim()
  const aliasedCategory = getInventoryCategoryKey(rawCategory)
  const text = `${aliasedCategory} ${String(input?.productName ?? '')}`
  if (!text.trim()) return '未分类'
  if (/小新\s*PRO\s*16|小新PRO16|PRO\s*16C|PRO16C|PRO\s*16GT|PRO16GT/i.test(text)) return '轻薄笔记本'
  if (/小新\s*PRO\s*14|小新PRO14|PRO\s*14C|PRO14C|PRO\s*14GT|PRO14GT/i.test(text)) return '轻薄笔记本'
  if (/游戏主机|主机/i.test(text)) return '游戏主机'
  if (/打印机|喷墨|激光|鲸鱼|PANDA|CM408/i.test(text)) return '打印机'
  if (/一体机|AIO|27-ILL|F0J|F0H/i.test(text)) return '一体机'
  if (/商务台式|办公电脑|台式|天逸/i.test(text)) return '商务台式'
  if (/平板|\bTAB\b|\bPAD\b|(?:拯救者\s*)?Y700(?!0)|\bTB[0-9A-Z]{4,}\b/i.test(text)) return '平板电脑'
  if (/手机|moto|razr|edge|PHN|XT\d+|折叠机|直板机/i.test(text)) return '手机'
  if (/显示器/i.test(text)) return '显示器'
  if (/耳机|音箱/i.test(text)) return '耳机音箱'
  if (/打印机/i.test(text)) return '打印机'
  if (/智能|摄像头|路由|音箱|智控/i.test(text) && !/耳机/i.test(text)) return '智能生活'
  if (/鼠标|键盘|套装|支架|适配器|箱包|保护|钢化膜|配件|手写笔|贴膜|线材|耗材/i.test(text)) return '电脑配件'
  if (/拯救者|Legion|Y7000|Y9000|斗战者|战7000|游戏笔记本|RTX|显卡/i.test(text)) return '游戏笔记本'
  if (/小新|YOGA|ThinkPad|ThinkBook|来酷|Lecoo|轻薄笔记本|笔记本|电脑/i.test(text)) return '轻薄笔记本'
  return aliasedCategory || '未分类'
}

function compareInventoryCategoryPriority(leftCategory?: string, rightCategory?: string) {
  const left = getInventoryCategoryKey(leftCategory)
  const right = getInventoryCategoryKey(rightCategory)
  const leftPrimaryIndex = inventoryCategoryPrimaryOrder.indexOf(left as typeof inventoryCategoryPrimaryOrder[number])
  const rightPrimaryIndex = inventoryCategoryPrimaryOrder.indexOf(right as typeof inventoryCategoryPrimaryOrder[number])
  if (leftPrimaryIndex !== -1 || rightPrimaryIndex !== -1) {
    if (leftPrimaryIndex === -1) return 1
    if (rightPrimaryIndex === -1) return -1
    return leftPrimaryIndex - rightPrimaryIndex
  }
  return left.localeCompare(right, 'zh-CN')
}

function getDisplayTotalStock(row: { currentStock?: number; physicalHoldStock?: number; totalStock?: number } | null | undefined) {
  const storeStock = Number(row?.currentStock ?? 0)
  const holdStock = Number(row?.physicalHoldStock ?? 0)
  const computedTotal = Math.max(storeStock, 0) + Math.max(holdStock, 0)
  const explicitTotal = Number(row?.totalStock ?? 0)
  if (!Number.isFinite(explicitTotal) || explicitTotal <= 0) return computedTotal
  return Math.max(explicitTotal, computedTotal)
}

function getDisplaySellableStock(row: { category?: string; productName?: string; sellableStock?: number; serialCount?: number; currentStock?: number; physicalHoldStock?: number; totalStock?: number }) {
  return Math.max(Number(row.sellableStock ?? 0), getDisplayTotalStock(row))
}

function getInventoryLedgerCategory(row: Pick<StandardInventorySku, 'category' | 'productName' | 'spec' | 'pnMtm' | 'skuCode' | 'jdSubcategory' | 'sourceCategory'>) {
  const rawCategory = row.category || '未分类'
  if (isTabletAccessoryUnder500(row)) return '平板配件'
  return normalizeInventoryCategoryByText({ category: rawCategory, productName: row.productName })
}

function getMissingSerialCount(row: { currentStock?: number; physicalHoldStock?: number; totalStock?: number; serialCount: number }) {
  return Math.max(getDisplayTotalStock(row) - (row.serialCount ?? 0), 0)
}

const beijingTimeZone = 'Asia/Shanghai'
const salesProtectionRetentionDays = 7
const salesProtectionHistoryStartDate = '2026-05-15'

function getBeijingTodayDateString() {
  return new Intl.DateTimeFormat('en-CA', {
    timeZone: beijingTimeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).format(new Date())
}

function addDaysToDateString(date: string, delta: number) {
  const matched = String(date).match(/^(\d{4})-(\d{2})-(\d{2})$/)
  if (!matched) return date
  const year = Number(matched[1])
  const month = Number(matched[2])
  const day = Number(matched[3])
  if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) return date
  const utcMs = Date.UTC(year, month - 1, day) + delta * 86400000
  const next = new Date(utcMs)
  const y = next.getUTCFullYear()
  const m = String(next.getUTCMonth() + 1).padStart(2, '0')
  const d = String(next.getUTCDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}

function isNonDeviceEducationGapProduct(productName?: string, skuKey?: string) {
  const text = `${productName || ''} ${skuKey || ''}`.toLowerCase()
  return [
    'lenovo care',
    '延保',
    '保修',
    '碎屏',
    '会员',
    '礼包',
    '权益',
    '服务',
    '智惠',
  ].some((keyword) => text.includes(keyword.toLowerCase()))
}

const educationAgentPlaceholderLabels = new Set(['待补商品', '待补型号', '手机', '机型', '待补'])

function normalizeEducationAgentDisplayText(value?: string | null) {
  return String(value || '').trim()
}

function normalizeEducationAgentSerialNumbers(serialNumbers?: string[] | null) {
  return Array.from(new Set((serialNumbers ?? []).map((item) => String(item || '').trim()).filter(Boolean)))
    .sort((left, right) => left.localeCompare(right))
}

function isMeaningfulEducationAgentProductName(productName?: string | null) {
  const normalized = normalizeEducationAgentDisplayText(productName)
  if (!normalized) return false
  if (educationAgentPlaceholderLabels.has(normalized)) return false
  return !isNonDeviceEducationGapProduct(normalized)
}

function isDisplayReadyEducationAgentScanRow(item: Pick<
  EducationSubsidyAgentScanRow,
  'productName' | 'skuKey' | 'sourceSkuKey' | 'orderNumber' | 'serialNumbers' | 'sourceFile' | 'reportStatus'
>) {
  const sourceFile = normalizeEducationAgentDisplayText(item.sourceFile)
  if (sourceFile.includes('latest-education-agent-scan-sync-gap.json')) return false
  if (normalizeEducationAgentDisplayText(item.reportStatus) === '待补采') return false
  const hasMeaningfulProduct = isMeaningfulEducationAgentProductName(item.productName)
    || Boolean(normalizeEducationAgentDisplayText(item.skuKey || item.sourceSkuKey))
  if (!hasMeaningfulProduct) return false
  const hasOrderNumber = Boolean(normalizeEducationAgentDisplayText(item.orderNumber))
  const hasSerialNumbers = normalizeEducationAgentSerialNumbers(item.serialNumbers).length > 0
  return hasOrderNumber || hasSerialNumbers
}

function getEducationAgentDisplayRowScore(item: Pick<
  EducationSubsidyAgentScanRow,
  'productName' | 'orderNumber' | 'serialNumbers' | 'customerPhone' | 'agentPhone' | 'customerName' | 'outboundDate' | 'scanDate' | 'lockedDisplayDate' | 'status'
>) {
  let score = 0
  if (isMeaningfulEducationAgentProductName(item.productName)) score += 20
  if (normalizeEducationAgentDisplayText(item.orderNumber)) score += 50
  score += normalizeEducationAgentSerialNumbers(item.serialNumbers).length * 20
  if (normalizeEducationAgentDisplayText(item.customerPhone)) score += 8
  if (normalizeEducationAgentDisplayText(item.agentPhone)) score += 6
  if (normalizeEducationAgentDisplayText(item.customerName) && !educationAgentPlaceholderLabels.has(normalizeEducationAgentDisplayText(item.customerName))) score += 6
  if (normalizeEducationAgentDisplayText(item.outboundDate)) score += 5
  if (normalizeEducationAgentDisplayText(item.scanDate || item.lockedDisplayDate)) score += 4
  if (normalizeEducationAgentDisplayText(item.status) && normalizeEducationAgentDisplayText(item.status) !== '待出库同步') score += 3
  return score
}

function dedupeEducationAgentDisplayRows(rows: EducationSubsidyAgentScanRow[]) {
  const deduped = new Map<string, EducationSubsidyAgentScanRow>()
  for (const row of rows) {
    const serialNumbers = normalizeEducationAgentSerialNumbers(row.serialNumbers)
    const identityDate = normalizeEducationAgentDisplayText(row.outboundDate || row.scanDate || row.lockedDisplayDate)
    const identityProduct = normalizeEducationAgentDisplayText(row.productName || row.skuKey || row.sourceSkuKey)
    const identityPhone = normalizeEducationAgentDisplayText(row.customerPhone || row.agentPhone)
    const identityOrder = normalizeEducationAgentDisplayText(row.orderNumber)
    const identityKey = identityOrder
      || [identityPhone, identityProduct, identityDate].filter(Boolean).join('|')
      || [identityProduct, identityDate, serialNumbers.join('|')].filter(Boolean).join('|')
      || row.id
    const key = [normalizeEducationAgentDisplayText(row.sourceGroupName || row.collectionSource), identityKey].join('::')
    const current = deduped.get(key)
    if (!current) {
      deduped.set(key, { ...row, serialNumbers })
      continue
    }
    const currentScore = getEducationAgentDisplayRowScore(current)
    const nextScore = getEducationAgentDisplayRowScore(row)
    const preferred = nextScore >= currentScore ? row : current
    const fallback = preferred === row ? current : row
    deduped.set(key, {
      ...fallback,
      ...preferred,
      serialNumbers: normalizeEducationAgentSerialNumbers([
        ...(preferred.serialNumbers ?? []),
        ...(fallback.serialNumbers ?? []),
      ]),
    })
  }
  return Array.from(deduped.values())
}

function getMonthStartDateString(date: string) {
  const matched = String(date).match(/^(\d{4})-(\d{2})-(\d{2})$/)
  if (!matched) return date
  return `${matched[1]}-${matched[2]}-01`
}

function formatDateTime(value: string) {
  if (!value) return '待补'
  return new Date(value).toLocaleString('zh-CN', {
    timeZone: beijingTimeZone,
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  })
}

function formatFullDateTime(value?: string) {
  if (!value) return '待补'
  return new Date(value).toLocaleString('zh-CN', {
    timeZone: beijingTimeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  })
}

function formatPrice(value?: number, fallback = '待匹配') {
  if (value === undefined || value === null || Number.isNaN(value)) return fallback
  return `￥${Math.round(value).toLocaleString()}`
}

function formatPricePrecise(value?: number, fallback = '待匹配') {
  if (value === undefined || value === null || Number.isNaN(value)) return fallback
  const normalized = Number(value.toFixed(1))
  const text = Number.isInteger(normalized)
    ? Math.round(normalized).toLocaleString()
    : normalized.toLocaleString(undefined, { minimumFractionDigits: 1, maximumFractionDigits: 1 })
  return `￥${text}`
}

function formatMovementPurchasePriceLabel(value?: number, fallback = '待补') {
  return `进货成本价 ${formatPrice(value, fallback)}`
}

function normalizeInboundMovementCost(value?: number) {
  if (typeof value !== 'number' || !Number.isFinite(value) || value <= 0) return undefined
  const normalized = Math.abs(value) >= 50000 ? value / 100 : value
  return Number(normalized.toFixed(2))
}

function normalizeSalesMoneyUnit(rawAmount?: number | null, baselineAmount?: number | null) {
  if (typeof rawAmount !== 'number' || !Number.isFinite(rawAmount) || rawAmount <= 0) return undefined
  if (typeof baselineAmount !== 'number' || !Number.isFinite(baselineAmount) || baselineAmount <= 0) return rawAmount
  const tolerance = Math.max(1, baselineAmount * 0.05)
  if (Math.abs(rawAmount * 100 - baselineAmount) <= tolerance) return rawAmount * 100
  if (Math.abs(rawAmount - baselineAmount * 100) <= tolerance) return rawAmount / 100
  if (rawAmount < baselineAmount * 0.2 && baselineAmount >= 1000) return rawAmount * 100
  return rawAmount
}

function shouldScaleSalesAmountBy100(
  amount?: number,
  productName?: string,
  category?: string,
) {
  if (typeof amount !== 'number' || !Number.isFinite(amount) || amount <= 0) return false
  if (amount >= 1000) return false
  const text = `${category ?? ''} ${productName ?? ''}`.toLowerCase()
  if (/智惠|服务|延保|保险|碎屏|会员|代扫/.test(text)) return false
  if (/配件|耳机|音箱|鼠标|键盘|显示器支架|打印耗材/.test(text)) return false
  return true
}

function formatSourcePrice(value?: number, fallback = '—') {
  if (value === undefined || value === null || Number.isNaN(value)) return fallback
  return formatPrice(value)
}

function formatPrecisePrice(value?: number, fallback = '待匹配') {
  if (value === undefined || value === null || Number.isNaN(value)) return fallback
  return `￥${value.toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
}

function normalizeTo99EndingRetailPrice(value?: number) {
  if (!value || !Number.isFinite(value)) return undefined
  const normalized = Math.ceil((value + 1) / 100) * 100 - 1
  return Math.max(normalized, 99)
}

function getMaskedWholesaleEstimate(maskedPriceText?: string) {
  if (!maskedPriceText || !maskedPriceText.includes('*')) return undefined
  const normalized = maskedPriceText.replace(/[^\d*]/g, '')
  if (!normalized || !/\d/.test(normalized)) return undefined
  const estimated = Number(normalized.replace(/\*/g, '5'))
  return Number.isFinite(estimated) && estimated > 0 ? estimated : undefined
}

function getGrayWholesaleBasis(quote: { marketWholesalePrice?: number; maskedPriceText?: string }) {
  return quote.marketWholesalePrice ?? getMaskedWholesaleEstimate(quote.maskedPriceText)
}

function getTabletAccessoryPriceHint(input: {
  recommendedPreSubsidyPrice?: number
  displayPrice?: number
  jdPrice?: number
  lenovoOfficialPrice?: number
  taobaoPrice?: number
  graySuggestedRetailPrice?: number
  agentPrice?: number
  salesCostPrice?: number
}) {
  return input.recommendedPreSubsidyPrice
    ?? input.displayPrice
    ?? input.jdPrice
    ?? input.lenovoOfficialPrice
    ?? input.taobaoPrice
    ?? input.graySuggestedRetailPrice
    ?? input.agentPrice
    ?? input.salesCostPrice
}

function isTabletAccessoryUnder500(input: {
  productName?: string
  category?: string
  spec?: string
  pnMtm?: string
  skuCode?: string
  jdSubcategory?: string
  sourceCategory?: string
  recommendedPreSubsidyPrice?: number
  displayPrice?: number
  jdPrice?: number
  lenovoOfficialPrice?: number
  taobaoPrice?: number
  graySuggestedRetailPrice?: number
  agentPrice?: number
  salesCostPrice?: number
}) {
  const text = [
    input.category,
    input.productName,
    input.spec,
    input.pnMtm,
    input.skuCode,
    input.jdSubcategory,
    input.sourceCategory,
  ].filter(Boolean).join(' ').toUpperCase()
  if (/平板配件/.test(text)) return true
  if (!/平板|\bTAB\b|\bPAD\b|Y700(?!0)|TB\d+/i.test(text)) return false
  if (!/配件|键盘|磁吸键盘|手写笔|触控笔|触控手写笔|保护套|保护壳|保护夹|钢化膜|贴膜|支架|KB\b|PEN\b|CASE\b|FILM\b|底座|散热壳|妙想键盘|笔尖|套装/i.test(text)) return false
  const price = getTabletAccessoryPriceHint(input)
  return typeof price === 'number' && Number.isFinite(price) && price > 0 && price < 500
}

function isTabletQuote(input: { productName: string; category?: string; series?: string }) {
  const text = `${input.category ?? ''} ${input.series ?? ''} ${String(input.productName ?? '')}`.toUpperCase()
  return /平板|\bTAB\b|\bPAD\b|Y700(?!0)|TB\d+/i.test(text)
}

function getGraySuggestedRetailPrice(
  wholesalePrice: number | undefined,
  input: { productName: string; category?: string; series?: string },
) {
  if (!wholesalePrice) return undefined
  return normalizeTo99EndingRetailPrice(wholesalePrice * (isTabletQuote(input) ? 1.15 : 1.13))
}

function getGraySuggestedSubsidyPrice(
  retailPrice: number | undefined,
  input: { productName: string; category?: string; series?: string },
) {
  if (!retailPrice) return undefined
  if (isTabletQuote(input)) return Number((retailPrice * 0.85).toFixed(2))
  return calculateFullServiceSubsidyPriceForProduct(retailPrice, input)
}

function normalizeTo9EndingRetailPrice(value?: number) {
  if (!value || !Number.isFinite(value)) return undefined
  const rounded = Math.max(Math.round(value), 0)
  return Math.floor(rounded / 10) * 10 + 9
}

function minDefinedNumber(values: Array<number | undefined>) {
  const available = values.filter((value): value is number => typeof value === 'number' && Number.isFinite(value) && value > 0)
  return available.length ? Math.min(...available) : undefined
}

function getMarketplaceRetailNote(record?: NonNullable<MarketplacePriceSnapshot['records']>[number]) {
  if (!record) return undefined
  const raw = record.raw ?? {}
  const educationAmount = typeof raw.educationDiscountAmount === 'number' ? raw.educationDiscountAmount : undefined
  const platformAmount = typeof raw.platformCouponAmount === 'number' ? raw.platformCouponAmount : undefined
  const governmentAmount = typeof raw.governmentSubsidyAmount === 'number' ? raw.governmentSubsidyAmount : undefined
  const couponAlreadyIncluded = record.priceType === 'coupon_adjusted_price'
  if (record.source === 'lenovo_official' && educationAmount) return `教育补 ￥${educationAmount}`
  const amountNotes = [
    educationAmount ? `教育补 -${educationAmount}` : undefined,
    couponAlreadyIncluded ? undefined : platformAmount ? `平台券 -${platformAmount}` : undefined,
    governmentAmount ? `国补 -${governmentAmount}` : undefined,
  ].filter(Boolean)
  if (amountNotes.length) return amountNotes.join('；')
  if (raw.couponAmountCaptureStatus === 'amount_not_expanded') return '教育补/平台券金额待展开采集，不覆盖主零售价'
  const rawNotes = [
    ...(record.raw?.educationDiscountNotes ?? []),
    ...(couponAlreadyIncluded ? [] : (record.raw?.platformCouponNotes ?? [])),
    ...(record.raw?.governmentSubsidyNotes ?? []),
    ...((record.raw?.discountNotes ?? []).filter((note) => !couponAlreadyIncluded || !/平台券|优惠券|领券|满减|红包/.test(note))),
  ]
  const notes = Array.from(new Set(rawNotes.filter(Boolean).map((note) => note.replace(/¥/g, '￥')))).slice(0, 2)
  if (notes.length) return notes.join('；')
  if (record.postSubsidyPrice) return `采集到补贴/优惠后价 ${formatPrecisePrice(record.postSubsidyPrice)}，不覆盖主零售价`
  if (record.couponAdjustedPrice) return `采集到券后价 ${formatPrecisePrice(record.couponAdjustedPrice)}，不覆盖主零售价`
  return record.evidence?.note?.includes('优惠') ? record.evidence.note.replace(/¥/g, '￥') : undefined
}

function getRetailActivityTone(category: string) {
  if (category === 'po_boost' || category === 'po') return 'marketing'
  if (category === 'education_discount' || category === 'education') return 'education'
  if (category === 'designated_ai_campaign' || category === 'ai') return 'ai'
  if (category === 'aipc_campaign' || category === 'aipc') return 'aipc'
  if (category === 'bundle_gift' || category === 'gift') return 'gift'
  if (category === 'jd') return 'jd'
  if (category === 'lenovo_official') return 'lenovo'
  if (category === 'taobao_subsidy') return 'tmall'
  return 'generic'
}

function formatDate(value?: string) {
  if (!value) return '待补'
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return value.replace(/-/g, '/')
  }
  const parsed = new Date(value)
  if (Number.isNaN(parsed.getTime())) return value
  return parsed.toLocaleDateString('zh-CN', {
    timeZone: beijingTimeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  })
}

function formatShortDate(value?: string) {
  if (!value) return '待补'
  const text = String(value).trim()
  const direct = text.match(/^(\d{4})-(\d{2})-(\d{2})$/)
  if (direct) return `${direct[1].slice(-2)}/${direct[2]}/${direct[3]}`
  const parsed = new Date(text)
  if (Number.isNaN(parsed.getTime())) return text.replace(/-/g, '/').replace(/^20/, '')
  return parsed.toLocaleDateString('zh-CN', {
    timeZone: beijingTimeZone,
    year: '2-digit',
    month: '2-digit',
    day: '2-digit',
  }).replace(/\//g, '/')
}

function formatActivityWindow(validFrom?: string, validTo?: string) {
  return [validFrom ? formatShortDate(validFrom) : '', validTo ? formatShortDate(validTo) : ''].filter(Boolean).join(' - ')
}

function toDateOnly(value?: string) {
  if (!value) return ''
  const text = String(value).trim()
  if (!text) return ''
  const direct = text.match(/20\d{2}-\d{2}-\d{2}/)?.[0]
  if (direct) return direct
  const parsed = Date.parse(text.replace(' ', 'T'))
  return Number.isFinite(parsed) ? new Date(parsed).toISOString().slice(0, 10) : text
}

function diffDays(from?: string, to?: string) {
  if (!from || !to) return undefined
  const left = new Date(from)
  const right = new Date(to)
  if (Number.isNaN(left.getTime()) || Number.isNaN(right.getTime())) return undefined
  left.setHours(0, 0, 0, 0)
  right.setHours(0, 0, 0, 0)
  return Math.round((right.getTime() - left.getTime()) / 86400000)
}

function getMarketingBoostCountdown(validTo?: string) {
  const days = diffDays(getBeijingTodayDateString(), validTo)
  if (days === undefined) return '待补截止'
  if (days < 0) return `已结束 ${Math.abs(days)} 天`
  if (days === 0) return '今天截止'
  return `剩余 ${days} 天`
}

function getMarketingBoostTone(boostAmount?: number, index = 0) {
  if ((boostAmount ?? 0) >= 1000) return 'critical'
  if ((boostAmount ?? 0) >= 500) return 'high'
  if ((boostAmount ?? 0) >= 200) return 'medium'
  return ['low', 'blue', 'green', 'violet'][index % 4]
}

function getMarketingBoostSourceLabel(sourceType?: string) {
  if (sourceType === 'distributor_remark') return '群报价备注'
  if (sourceType === 'manual_activity') return '活动库直录'
  return '手工识别'
}

function getMarketingBoostCategoryLabel(category?: string) {
  if (category === 'education_discount') return '教育补贴'
  if (category === 'bundle_gift') return '买赠活动'
  if (category === 'aipc_campaign') return 'AIPC活动'
  if (category === 'designated_ai_campaign') return '指定AI活动'
  if (category === 'po_boost') return 'PO加磅'
  return '营销活动'
}

function getMarketingHistoryProductLine(category?: string, productName?: string, spec?: string, pnMtm?: string) {
  if (isTabletAccessoryUnder500({ category, productName, spec, pnMtm })) return 'computer'
  const categoryText = category ?? ''
  const normalized = [category, productName, spec, pnMtm]
    .filter(Boolean)
    .join(' ')
    .trim()
  if (/配件|键盘|手写笔|触控笔|保护套|保护壳|钢化膜|贴膜|支架|KB\b|套装/i.test(normalized)) return 'computer'
  if (/平板|Pad|pad|moto|手机/i.test(normalized)) return 'mobileTablet'
  if (/^TB\d/i.test((pnMtm ?? '').trim())) return 'mobileTablet'
  if (/TAB/i.test(categoryText) || /TAB/i.test(productName ?? '')) return 'mobileTablet'
  return 'computer'
}

function isGenericOtherComputerCrossCheckRow(input: { category?: string; productName?: string; spec?: string; pnMtm?: string }) {
  const categoryText = String(input.category ?? '').trim()
  const categoryDisplay = getInventoryCategoryDisplayName(categoryText)
  const productSeries = getProductSeries({ productName: String(input.productName ?? ''), category: categoryText })
  if (categoryDisplay === '未分类' && productSeries === '其它电脑') return true
  const productText = [input.productName, input.spec, input.pnMtm].filter(Boolean).join(' ').trim()
  if ((categoryText === '未分类' || /未分类/.test(categoryText)) && /(?:其它|其他)电脑/.test(productText)) return true
  if (/^(?:其它|其他)电脑$/i.test(String(input.productName ?? '').trim())) return true
  return false
}

function isCrossOutboundCheckRowWithinRuleWindow(
  row: { outboundDate: string; ruleId: string },
  rules: CrossOutboundCheckRule[],
) {
  const rule = rules.find((item) => item.id === row.ruleId)
  if (!rule) return true
  if (rule.validFrom && row.outboundDate && row.outboundDate < rule.validFrom) return false
  if (rule.validTo && row.outboundDate && row.outboundDate > rule.validTo) return false
  return true
}

function formatBusinessDate(value?: string) {
  if (!value) return '待补'
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value.replace(/-/g, '/')
  const parsed = new Date(value.replace(' ', 'T'))
  if (Number.isNaN(parsed.getTime())) return value
  return parsed.toLocaleString('zh-CN', {
    timeZone: beijingTimeZone,
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  })
}

function formatDateInputValue(value?: string) {
  if (!value) return ''
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value
  const parsed = new Date(value)
  if (Number.isNaN(parsed.getTime())) return ''
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: beijingTimeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(parsed)
  const year = parts.find((item) => item.type === 'year')?.value ?? ''
  const month = parts.find((item) => item.type === 'month')?.value ?? ''
  const day = parts.find((item) => item.type === 'day')?.value ?? ''
  return `${year}-${month}-${day}`
}

function isPhysicalHoldManagedBusinessDate(value?: string) {
  const normalized = formatDateInputValue(value)
  return Boolean(normalized && normalized >= '2026-05-01')
}

function parsePreciseBusinessTimestamp(value?: string) {
  if (!value || /^\d{4}-\d{2}-\d{2}$/.test(value)) return null
  const parsed = new Date(value.replace(' ', 'T'))
  return Number.isNaN(parsed.getTime()) ? null : parsed.getTime()
}

function parseTimestamp(value?: string) {
  if (!value) return null
  const parsed = new Date(value)
  return Number.isNaN(parsed.getTime()) ? null : parsed.getTime()
}

function extractOrderNumber(note?: string) {
  if (!note) return '待补'
  const matched = note.match(/订单\s+([A-Z0-9]+)/i)
  return matched?.[1] ?? note
}

function extractSalesOrderSequence(value?: string) {
  if (!value) return null
  const matched = String(value).match(/XS(\d{14,})/i)
  if (!matched) return null
  const sequence = Number(matched[1])
  return Number.isFinite(sequence) ? sequence : null
}

function isReadableBusinessName(value?: string) {
  const text = String(value ?? '').trim()
  if (!text) return false
  if (/^STORE[-_A-Z0-9]+$/i.test(text)) return false
  if (/^[A-Z0-9_-]{10,}$/i.test(text)) return false
  return true
}

function extractLineSerialNumbers(line?: NonNullable<RetailCoreSalesOrder['lines']>[number]) {
  if (!line) return [] as string[]
  const values: string[] = []
  try {
    const parsed = JSON.parse(line.serial_numbers_json || '[]')
    if (Array.isArray(parsed)) {
      values.push(...parsed.filter((value): value is string => typeof value === 'string' && value.trim().length > 0))
    }
  } catch {
    // ignore broken json and keep scalar fallback
  }
  if (line.serial_number && line.serial_number.trim()) values.push(line.serial_number.trim())
  return Array.from(new Set(values.map((item) => item.trim()).filter(Boolean)))
}

function buildSalesOrderRichnessScore(order: RetailCoreSalesOrder) {
  const lines = order.lines ?? []
  const serialCount = lines.reduce((sum, line) => sum + extractLineSerialNumbers(line).length, 0)
  const amountCount = lines.reduce((sum, line) => sum + ((Number(line.deal_price ?? line.pay_amount ?? 0) > 0) ? 1 : 0), 0)
  return {
    xsPriority: extractSalesOrderSequence(order.id) !== null ? 1 : 0,
    externalAliasPriority: String(order.external_order_no ?? '').trim() ? 1 : 0,
    amountPriority: Number(order.total_amount ?? order.pay_amount ?? 0) > 0 ? 1 : 0,
    lineAmountPriority: amountCount,
    serialPriority: serialCount,
    businessNamePriority: isReadableBusinessName(order.shop_name || order.store_code) ? 1 : 0,
    timePriority: parseTimestamp(order.pay_time || order.business_date || order.created_time || order.created_at || '') ?? -1,
  }
}

function shouldPreferSalesOrderCandidate(
  candidate: RetailCoreSalesOrder,
  existing?: RetailCoreSalesOrder | null,
) {
  if (!existing) return true
  const left = buildSalesOrderRichnessScore(candidate)
  const right = buildSalesOrderRichnessScore(existing)
  if (left.xsPriority !== right.xsPriority) return left.xsPriority > right.xsPriority
  if (left.externalAliasPriority !== right.externalAliasPriority) return left.externalAliasPriority > right.externalAliasPriority
  if (left.amountPriority !== right.amountPriority) return left.amountPriority > right.amountPriority
  if (left.lineAmountPriority !== right.lineAmountPriority) return left.lineAmountPriority > right.lineAmountPriority
  if (left.serialPriority !== right.serialPriority) return left.serialPriority > right.serialPriority
  if (left.businessNamePriority !== right.businessNamePriority) return left.businessNamePriority > right.businessNamePriority
  return left.timePriority > right.timePriority
}

function extractBusinessNumber(note?: string) {
  if (!note) return '待补'
  const matched = note.match(/业务单\s+([A-Z0-9]+)/i)
  return matched?.[1] ?? note
}

function resolveMovementDocumentNumber(input: {
  documentNumber?: string
  sourceRef?: string
  id?: string
  note?: string
  sales?: boolean
}) {
  const documentNumber = String(input.documentNumber ?? '').trim()
  if (documentNumber) return documentNumber
  const sourceRef = String(input.sourceRef ?? '').trim()
  if (sourceRef) return sourceRef
  const id = String(input.id ?? '').trim()
  if (id) return id
  return input.sales ? extractOrderNumber(input.note) : extractBusinessNumber(input.note)
}

function splitMovementSerialNumbers(value?: string) {
  return Array.from(new Set(
    String(value ?? '')
      .split(/[,\n/，、\s]+/)
      .map((item) => item.trim())
      .filter(Boolean),
  ))
}

function normalizeMovementDocumentLookupKey(value?: string) {
  return String(value ?? '')
    .trim()
    .replace(/^ZDT-/i, '')
    .replace(/\s+/g, '')
    .toUpperCase()
}

function extractMovementDocumentPrefix(value?: string) {
  const normalized = String(value ?? '').trim().toUpperCase()
  if (!normalized) return 'UNKNOWN'
  const alphaNum = normalized.match(/^([A-Z]+)\d+/)
  if (alphaNum?.[1]) return alphaNum[1]
  const alphaHyphen = normalized.match(/^([A-Z]+)-/)
  if (alphaHyphen?.[1]) return alphaHyphen[1]
  return 'UNKNOWN'
}

function buildMovementSerialDetailKey(documentNumber?: string, skuKey?: string) {
  const documentKey = normalizeMovementDocumentLookupKey(documentNumber)
  const sku = String(skuKey ?? '').trim()
  if (!documentKey || !sku) return ''
  return `${documentKey}|${sku}`
}

function buildInboundSerialDetailMap(params: {
  serialItems?: RetailCoreSerialItems | null
  movements?: InventoryMovementRecord[] | null
  inventoryRows?: InventoryMasterRow[] | null
}) {
  const map = new Map<string, RetailCoreSerialItem[]>()
  const isInStockSerial = (status?: string) => {
    const normalized = String(status ?? '').trim().toLowerCase()
    if (!normalized) return true
    if (normalized === 'in_stock' || normalized === 'instock' || normalized === 'available') return true
    if (normalized.includes('在库')) return true
    return false
  }
  const push = (row: RetailCoreSerialItem) => {
    const key = buildMovementSerialDetailKey(row.inbound_document_no, row.sku_key)
    if (!key || !row.serial_number) return
    if (!isInStockSerial(row.status)) return
    const current = map.get(key) ?? []
    if (!current.some((item) => item.serial_number === row.serial_number)) {
      current.push(row)
    }
    map.set(key, current)
  }

  for (const serial of params.serialItems?.items ?? []) push(serial)

  for (const row of params.inventoryRows ?? []) {
    if (!row.serialNumber) continue
    push({
      serial_number: row.serialNumber,
      sku_key: row.skuKey,
      product_name: row.productName ?? '',
      pn_mtm: row.pnMtm ?? '',
      spec: row.spec ?? '',
      status: row.inStock === false ? 'sold' : 'in_stock',
      warehouse_code: row.organizationCode ?? '',
      location_code: row.locationName ?? '',
      cost_amount: row.purchaseCost ?? undefined,
      inbound_date: row.inboundDate ?? '',
      inbound_document_no: row.inboundDocumentNumber ?? '',
      operator_name: row.inboundOperatorName ?? '',
      supplier_name: row.supplierName ?? '',
      warranty_status: 'unknown',
      warranty_checked_at: '',
      official_warranty_start: row.warrantyStart ?? '',
      official_warranty_end: row.warrantyEnd ?? '',
      warranty_service_plan: '',
      warranty_official_product_name: '',
      warranty_official_lookup_url: '',
      warranty_evidence_screenshot_path: '',
      warranty_evidence_text_path: '',
      warranty_failure_reason: '',
      updated_at: row.inboundDate ?? '',
    })
  }

  // 注意：不要把 inventory movements 的 serialNumber 混入入库 SN 明细。
  // movements 包含销售/其它出库，会把已出库 SN 误并回采购入库单据，产生“脏数据”。

  map.forEach((rows) => rows.sort((left, right) => {
    const leftTime = new Date(left.inbound_date ?? left.updated_at ?? '').getTime()
    const rightTime = new Date(right.inbound_date ?? right.updated_at ?? '').getTime()
    if (Number.isFinite(leftTime) || Number.isFinite(rightTime)) return (rightTime || 0) - (leftTime || 0)
    return left.serial_number.localeCompare(right.serial_number)
  }))
  return map
}

function resolvePlaceholderOrderId(input: {
  documentNumber?: string
  sourceRef?: string
  note?: string
}) {
  const documentNumber = String(input.documentNumber ?? '').trim()
  if (documentNumber) return documentNumber
  const sourceRef = String(input.sourceRef ?? '').trim()
  if (sourceRef) return sourceRef
  const noteOrderNumber = extractOrderNumber(input.note)
  return noteOrderNumber === '待补' ? '' : noteOrderNumber
}

function isLocalPlaceholderSalesOrder(orderNumber?: string, sourceNote?: string, outboundDocumentNumber?: string) {
  const normalizedOrderNumber = String(orderNumber ?? '').trim().toUpperCase()
  const normalizedSourceNote = String(sourceNote ?? '')
  const normalizedOutboundDocumentNumber = String(outboundDocumentNumber ?? '').trim().toUpperCase()
  return normalizedOrderNumber.startsWith('SO-')
    || normalizedOutboundDocumentNumber.startsWith('SO-')
    || normalizedSourceNote.includes('本地销售单')
}

function removePosStagedOrderMirror(orderId: string) {
  if (typeof window === 'undefined') return
  try {
    const key = 'lenovo-pos-staged-orders'
    const parsed = JSON.parse(window.localStorage.getItem(key) || '[]') as Array<Record<string, unknown>>
    const next = parsed.filter((item) => String(item.backendOrderId ?? '') !== orderId)
    window.localStorage.setItem(key, JSON.stringify(next))
  } catch (error) {
    console.warn('清理收银端占位镜像失败', error)
  }
}

function isInboundStyleDocumentNumber(value?: string) {
  const normalized = String(value ?? '').trim().toUpperCase()
  if (!normalized) return false
  return /^CGR\d+/.test(normalized)
}

function isPurchasePlaceholderDocumentNumber(value?: string) {
  const normalized = String(value ?? '').trim().toUpperCase()
  if (!normalized) return false
  return /^PURCHASEQ-/.test(normalized)
}

function isHistoricalInboundImportDocumentNumber(value?: string) {
  const normalized = String(value ?? '').trim().toUpperCase()
  if (!normalized) return false
  return /^TDR\d+/.test(normalized) || /^T\d+/.test(normalized)
}

function isNonNormalPurchaseInboundMovement(item: InventoryMovementRecord) {
  if (item.isNonNormalPurchaseInbound) return true
  const documentNumber = resolveMovementDocumentNumber({
    documentNumber: item.documentNumber,
    sourceRef: item.sourceRef,
    id: item.id,
    note: item.note,
  }).trim().toUpperCase()
  const noteText = String(item.note ?? '')
  const sourceType = String(item.sourceDocumentType ?? '')
  if (isPurchasePlaceholderDocumentNumber(documentNumber)) return true
  if (isHistoricalInboundImportDocumentNumber(documentNumber)) return true
  if (/openclaw\.full_db\.purchase_inbound/i.test(noteText)) return true
  if (/重复占位采购行|库存流水导出导入/.test(noteText)) return true
  if (/采购入库/.test(sourceType) && (isHistoricalInboundImportDocumentNumber(documentNumber) || isPurchasePlaceholderDocumentNumber(documentNumber))) return true
  return false
}

function isSalesStyleDocumentNumber(value?: string) {
  const normalized = String(value ?? '').trim().toUpperCase()
  if (!normalized) return false
  return /^(XS|SO)\d+/.test(normalized)
}

function hasInboundMovementHint(note?: string, sourceDocumentType?: string) {
  const noteText = String(note ?? '')
  const sourceType = String(sourceDocumentType ?? '')
  return /入库|采购|进货/.test(noteText) || /入库|采购/.test(sourceType)
}

function classifyInboundMovement(item: InventoryMovementRecord) {
  if (item.movementType === 'purchase_inbound' || item.movementType === 'transfer_inbound') return true
  const documentNumber = item.documentNumber || extractBusinessNumber(item.note)
  if (isInboundStyleDocumentNumber(documentNumber)) return true
  return hasInboundMovementHint(item.note, item.sourceDocumentType)
}

function classifySalesOutboundMovement(item: InventoryMovementRecord) {
  if (item.movementType !== 'sales_outbound') return false
  if (classifyInboundMovement(item)) return false
  const sourceType = String(item.sourceDocumentType ?? '')
  const documentNumber = resolveMovementDocumentNumber({
    documentNumber: item.documentNumber,
    sourceRef: item.sourceRef,
    id: item.id,
    note: item.note,
    sales: true,
  }).trim().toUpperCase()
  if (/采购入库|订单退货入库|调拨入库|同店换库位入库/.test(sourceType)) return false
  if (isInboundStyleDocumentNumber(documentNumber) || /^ZDT-CGR|^PURCHASEQ-CGR|^PURCHASE-CGR/.test(documentNumber)) return false
  if (isSalesStyleDocumentNumber(documentNumber)) return true
  if (/业务订单|门店出库|待商确认|销售出库/.test(sourceType)) return true
  return !hasInboundMovementHint(item.note, item.sourceDocumentType)
}

function isTransferDocument(note?: string, sourceDocumentType?: string, documentNumber?: string) {
  const joined = `${String(note ?? '')} ${String(sourceDocumentType ?? '')} ${String(documentNumber ?? '')}`
  return /调拨/.test(joined)
}

function classifyPurchaseInboundMovement(item: InventoryMovementRecord) {
  const documentNumber = resolveMovementDocumentNumber({
    documentNumber: item.documentNumber,
    sourceRef: item.sourceRef,
    id: item.id,
    note: item.note,
  })
  const sourceType = String(item.sourceDocumentType ?? '')
  if (isTransferDocument(item.note, item.sourceDocumentType, documentNumber)) return false
  if (/退货/.test(sourceType)) return false
  if (isNonNormalPurchaseInboundMovement(item)) return false
  if (item.movementType === 'purchase_inbound') {
    return isInboundStyleDocumentNumber(documentNumber)
  }
  if (/采购入库|purchase_inbound/i.test(sourceType) && (isInboundStyleDocumentNumber(documentNumber) || /^ZDT-CGR|^PURCHASEQ-CGR|^PURCHASE-CGR/i.test(documentNumber))) return true
  return false
}

function classifyTransferInboundMovement(item: InventoryMovementRecord) {
  const documentNumber = item.documentNumber || extractBusinessNumber(item.note)
  if (item.movementType === 'transfer_inbound') return true
  return classifyInboundMovement(item) && isTransferDocument(item.note, item.sourceDocumentType, documentNumber)
}

function classifyTransferOutboundMovement(item: InventoryMovementRecord) {
  const documentNumber = item.documentNumber || extractBusinessNumber(item.note)
  if (item.movementType !== 'transfer_outbound') return false
  return isTransferDocument(item.note, item.sourceDocumentType, documentNumber)
}

function classifyOtherOutboundMovement(item: InventoryMovementRecord) {
  if (isNonNormalPurchaseInboundMovement(item)) return true
  if (item.movementType === 'transfer_outbound') return !classifyTransferOutboundMovement(item)
  if (item.movementType !== 'manual_adjustment') return false
  const text = `${String(item.note ?? '')} ${String(item.sourceDocumentType ?? '')}`
  return /出库|报损|领用|赠品|借出|盘亏/.test(text)
}

function formatPlainAmount(value?: number) {
  return value === undefined ? '待匹配' : `${value}`
}

function buildMovementSearchText(fields: Array<string | number | undefined>) {
  return fields
    .filter((item) => item !== undefined && item !== null && item !== '')
    .join(' ')
    .toLowerCase()
}

function escapeCsvValue(value: string | number | undefined) {
  const text = String(value ?? '')
  if (!/[",\n]/.test(text)) return text
  return `"${text.replace(/"/g, '""')}"`
}

function escapeHtml(value: string | number | undefined) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;')
}

function formatSalesProtectionHistoryStatus(status?: string) {
  if (!status) return '价保申请'
  if (status === 'pending') return '价保申请'
  if (status === 'blocked_missing_cost') return '待补进货成本'
  if (status === 'blocked_missing_quote') return '待补报价凭证'
  if (status === 'no_need') return '无需价保'
  if (status === 'completed') return '已完成'
  return '价保处理中'
}

function getSalesProtectionHistoryStatusTone(status?: string) {
  if (!status) return 'pending'
  if (status === 'pending') return 'pending'
  if (status === 'blocked_missing_cost' || status === 'blocked_missing_quote') return 'blocked'
  if (status === 'no_need') return 'neutral'
  if (status === 'completed') return 'done'
  return 'pending'
}

function getWarrantyRemainingDays(warrantyEnd?: string) {
  if (!warrantyEnd) return undefined
  const end = new Date(warrantyEnd)
  if (Number.isNaN(end.getTime())) return undefined
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  end.setHours(23, 59, 59, 999)
  return Math.ceil((end.getTime() - today.getTime()) / 86400000)
}

function formatWarrantyRemaining(warrantyEnd?: string) {
  const days = getWarrantyRemainingDays(warrantyEnd)
  if (days === undefined) return '待官网校验'
  if (days < 0) return `已过保 ${Math.abs(days)} 天`
  return `剩余 ${days} 天`
}

function hasWarrantyDate(start?: string, end?: string) {
  return Boolean(start || end)
}

function getWarrantyStatusMeta(record?: WarrantyRecordItem, queued = false, hasDisplayableWarrantyDate = false) {
  if (hasDisplayableWarrantyDate) {
    return record?.status === 'success'
      ? { label: '已同步', tone: 'success' as const, detail: '联想官网已回填保修结果' }
      : { label: '已同步', tone: 'success' as const, detail: '已固化质保时间，后续无需重复采集' }
  }
  if (!record) {
    return queued
      ? { label: '待后台补齐', tone: 'pending' as const, detail: '不阻塞库存与报价主链' }
      : { label: '待排队', tone: 'pending' as const, detail: '等待进入后台补齐' }
  }
  if (record.status === 'success') return { label: '已同步', tone: 'success' as const, detail: '联想官网已回填保修结果' }
  if (record.status === 'captcha_required') return { label: '验证码阻塞', tone: 'warn' as const, detail: '需等待下次后台重试' }
  if (record.status === 'not_found') return { label: '官网未命中', tone: 'warn' as const, detail: '官网未返回该 SN 保修信息' }
  return queued
    ? { label: '未固化质保', tone: 'pending' as const, detail: '数据库暂无质保日期，等待后台补齐后固化' }
    : { label: '未固化质保', tone: 'pending' as const, detail: '数据库暂无质保日期' }
}

function formatWarrantyCheckedAt(record?: WarrantyRecordItem, hasLocalWarrantyDate = false) {
  if (!record?.checkedAt) return hasLocalWarrantyDate ? '已固化，无需重采' : '待后台补齐'
  return formatDateTime(record.checkedAt)
}

function getWarrantyRecordPriority(record: WarrantyRecordItem) {
  if (record.status === 'success' && (record.officialWarrantyStart || record.officialWarrantyEnd)) return 5
  if (record.status === 'success') return 4
  if (record.status === 'not_found') return 3
  if (record.status === 'captcha_required') return 2
  return 1
}

function getProductFamily(input: { productName: string; category?: string; recommendedPreSubsidyPrice?: number; displayPrice?: number; jdPrice?: number; lenovoOfficialPrice?: number; taobaoPrice?: number; graySuggestedRetailPrice?: number; agentPrice?: number; salesCostPrice?: number }) {
  if (isTabletAccessoryUnder500(input)) return '其它'
  const text = `${input.category ?? ''} ${input.productName}`
  if (/显示器|打印机|喷墨|墨仓|打印|复印|扫描|CM408|电脑配件|耳机音箱|键盘|鼠标|适配器|支架|保护夹|钢化膜|背包|耗材|手写笔|散热|贴膜/i.test(text)) return '其它'
  if (/平板|\bTAB\b|\bPAD\b|(?<![0-9A-Z])TB\d+|(?:拯救者\s*)?Y700(?!0)/i.test(text)) return '平板'
  if (/手机|moto|razr|edge|PHN|XT\d+|折叠机|直板机/i.test(text)) return '手机'
  if (/游戏笔记本|轻薄笔记本|一体机|商务台式|游戏主机|笔记本|电脑|拯救者|LEGION|小新|YOGA|来酷|LECOO|斗战者|ThinkPad|ThinkBook|GeekPro|天逸|台式/i.test(text)) return '电脑'
  return '其它'
}

function getSubsidyEligibilityPrice(input: {
  recommendedPreSubsidyPrice?: number
  lenovoOfficialPrice?: number
  jdPrice?: number
  taobaoPrice?: number
}) {
  return input.recommendedPreSubsidyPrice ?? input.jdPrice ?? input.lenovoOfficialPrice ?? input.taobaoPrice
}

function isSubsidyEligibleProduct(input: {
  productName: string
  category?: string
  recommendedPreSubsidyPrice?: number
  lenovoOfficialPrice?: number
  jdPrice?: number
  taobaoPrice?: number
}) {
  const family = getProductFamily(input)
  if (family === '其它') return false
  if (family === '电脑') return true
  const price = getSubsidyEligibilityPrice(input)
  return price === undefined || price < 6000
}

function calculateFullServiceSubsidyPriceForProduct(price: number | undefined, input: { productName: string; category?: string }) {
  if (!price) return undefined
  const family = getProductFamily(input)
  if (family === '其它') return undefined
  if ((family === '平板' || family === '手机') && price >= 6000) return undefined
  const subsidyAmount = family === '电脑'
    ? (price >= 10000 ? 1500 : price * 0.15)
    : Math.min(price * 0.15, 500)
  return Number((price - subsidyAmount).toFixed(2))
}

function getProductSeries(input: { productName: string; category?: string; recommendedPreSubsidyPrice?: number; displayPrice?: number; jdPrice?: number; lenovoOfficialPrice?: number; taobaoPrice?: number; graySuggestedRetailPrice?: number; agentPrice?: number; salesCostPrice?: number }) {
  if (isTabletAccessoryUnder500(input)) return '平板配件'
  const text = `${input.category ?? ''} ${input.productName}`
  if (/配件|键盘|手写笔|触控笔|保护套|保护壳|钢化膜|贴膜|支架|KB\b|套装/i.test(text)) {
    if (/平板|\bTAB\b|\bPAD\b|Y700(?!0)|Y900/i.test(text)) return '平板配件'
    return '其它配件'
  }
  if (/平板|\bTAB\b|\bPAD\b|(?<![0-9A-Z])TB\d+|(?:拯救者\s*)?Y700(?!0)/i.test(text)) {
    if (/拯救者|Y700(?!0)/i.test(text)) return '拯救者平板'
    if (/YOGA/i.test(text)) return 'YOGA平板'
    return '小新平板'
  }
  if (/手机|moto|razr|edge|PHN|XT\d+|折叠机|直板机/i.test(text)) {
    return /razr|折叠/i.test(text) ? 'moto折叠屏' : 'moto手机'
  }
  if (/拯救者|LEGION|R7000|R9000|Y7000|Y9000/i.test(text)) return '拯救者电脑'
  if (/来酷|LECOO|斗战者|战7000/i.test(text)) return '来酷电脑'
  if (/小新/i.test(text)) return '小新电脑'
  if (/YOGA/i.test(text)) return 'YOGA电脑'
  if (/ThinkPad/i.test(text)) return 'ThinkPad电脑'
  if (/ThinkBook/i.test(text)) return 'ThinkBook电脑'
  if (/GeekPro/i.test(text)) return 'GeekPro台式'
  if (/天逸|台式/i.test(text)) return '天逸台式'
  return '其它电脑'
}

function getSkuSpecDisplay(spec?: string) {
  return spec && spec !== '*' ? spec : '规格待补'
}

function buildSkuDisplayMeta(input: {
  skuKey?: string
  pnMtm?: string
  spec?: string
  category?: string
  productName: string
  jdSubcategory?: string
  sourceCategory?: string
  catalogSource?: string
  includeStandardCatalogSource?: boolean
}) {
  const series = getProductSeries({ productName: input.productName, category: input.category })
  const categoryLine = `${getInventoryCategoryDisplayName(input.category)} · ${series}`
  const identityLine = `SKU：${input.skuKey || '待补'} · PN-MTM：${input.pnMtm || '待补'} · 规格：${getSkuSpecDisplay(input.spec)}`
  const catalogLabel = input.catalogSource || (input.includeStandardCatalogSource === false ? undefined : '标准目录')
  const sourceLine = [
    input.jdSubcategory || input.sourceCategory ? `细分：${input.jdSubcategory || input.sourceCategory}` : undefined,
    catalogLabel ? `目录：${catalogLabel}` : undefined,
  ].filter(Boolean).join(' · ')
  return {
    series,
    categoryLine,
    identityLine,
    sourceLine,
  }
}

function renderUnifiedBlockHead(title: string, description: string, actions?: React.ReactNode) {
  return (
    <div className="block-head unified-block-head">
      <div className="unified-block-head-copy">
        <strong>{title}</strong>
        <span>{description}</span>
      </div>
      {actions ? <div className="unified-block-head-actions">{actions}</div> : null}
    </div>
  )
}

function renderUnifiedFilterHead(title: string, description: string) {
  return (
    <div className="sales-history-date-head unified-filter-head">
      <strong>{title}</strong>
      <span>{description}</span>
    </div>
  )
}

function renderUnifiedEmptyState(message: string) {
  return <div className="empty-state compact-empty-state unified-empty-state">{message}</div>
}

function getProductFreshnessLabel(input?: { serials?: Array<{ stockAgeDays?: number }> }) {
  const stockAges = (input?.serials ?? [])
    .map((item) => item.stockAgeDays)
    .filter((value): value is number => typeof value === 'number' && Number.isFinite(value) && value >= 0)
  if (!stockAges.length) return '老品'
  const newestAge = Math.min(...stockAges)
  return newestAge <= 30 ? '新品' : '老品'
}

function getMarketingPrimaryCategory(input: { productName: string; category?: string; recommendedPreSubsidyPrice?: number; displayPrice?: number; jdPrice?: number; lenovoOfficialPrice?: number; taobaoPrice?: number; graySuggestedRetailPrice?: number; agentPrice?: number; salesCostPrice?: number }) {
  if (isTabletAccessoryUnder500(input)) return '平板配件'
  const text = `${input.category ?? ''} ${input.productName}`
  if (/配件|键盘|手写笔|触控笔|保护套|保护壳|钢化膜|贴膜|支架|KB\b|套装/i.test(text)) {
    if (/平板|\bTAB\b|\bPAD\b|Y700(?!0)|Y900/i.test(text)) return '平板配件'
    return '电脑配件'
  }
  if (/小新\s*PRO\s*16|小新PRO16|PRO\s*16C|PRO16C|PRO\s*16GT|PRO16GT/i.test(text)) return '轻薄笔记本'
  if (/小新\s*PRO\s*14|小新PRO14|PRO\s*14C|PRO14C|PRO\s*14GT|PRO14GT/i.test(text)) return '轻薄笔记本'
  if (/平板|\bTAB\b|\bPAD\b|(?:拯救者\s*)?Y700(?!0)|\bTB[0-9A-Z]{4,}\b/i.test(text)) return '平板电脑'
  if (/手机|moto|razr|edge|PHN|XT\d+|折叠机|直板机/i.test(text)) return '手机'
  if (/一体机/i.test(text)) return '一体机'
  if (/GeekPro|斗战者|战7000|主机/i.test(text)) return '游戏主机'
  if (/扬天|天逸|启天|商务台式|台式/i.test(text)) return '办公电脑'
  if (/拯救者|LEGION|R7000|R9000|Y7000|Y9000/i.test(text)) return '游戏笔记本'
  return '轻薄笔记本'
}

function getMonitorPreset(row: StandardInventorySku) {
  if (isTabletAccessoryUnder500(row)) return '平板配件'
  const text = `${row.category ?? ''} ${row.jdSubcategory ?? ''} ${row.productName}`
  if (!isSubsidyEligibleProduct(row)) {
    if (/电脑配件|键盘|鼠标|适配器|支架|保护夹|钢化膜|背包|耗材|手写笔|散热|贴膜/i.test(text)) return '电脑配件'
    if (/显示器/i.test(text)) return '显示器'
    if (/打印机|喷墨|耗材/i.test(text)) return '打印机'
    if (/耳机|音箱|buds|speaker/i.test(text)) return '耳机音箱'
    if (/手机|moto|razr|edge|PHN|XT\d+/i.test(text)) return '高价手机'
    if (/平板|\bTAB\b|\bPAD\b|Y700(?!0)/i.test(text)) return '高价平板'
    return row.category || row.jdSubcategory || '其它非国补'
  }
  return getProductSeries(row)
}

function getSkuSearchText(row: StandardInventorySku) {
  return `${String(row.productName ?? '')} ${row.spec ?? ''} ${row.category ?? ''} ${row.jdSubcategory ?? ''} ${row.sourceCategory ?? ''}`.toUpperCase()
}

function isSamePriceCategory(row: StandardInventorySku) {
  return /一体机|台式|平板|打印机|电脑配件|耳机音箱|键盘|鼠标|适配器|支架|保护夹|钢化膜|背包|配件|耗材/i.test(getSkuSearchText(row))
}

function isGamingNotebook(row: StandardInventorySku) {
  return /游戏|拯救者|LEGION|斗战者|[RY]\d{4}P?/i.test(getSkuSearchText(row))
}

function isWhiteGamingNotebook(row: StandardInventorySku) {
  return isGamingNotebook(row) && /冰魄白|月幕白|白色|白|WHE/i.test(`${row.productName ?? ''} ${row.spec ?? ''} ${row.pnMtm ?? ''}`)
}

function isThinNotebook(row: StandardInventorySku) {
  return /轻薄|小新|YOGA|AIR|PRO14|PRO16|来酷|LECOO/i.test(getSkuSearchText(row))
}

function isAccessorySku(row: StandardInventorySku) {
  return /电脑配件|耳机音箱|打印机|喷墨|墨仓|打印|复印|扫描|CM408|键盘|鼠标|适配器|支架|保护夹|钢化膜|背包|配件|耗材|手写笔|散热|贴膜/i.test(getSkuSearchText(row))
}

function getAccessoryMarkup(basePrice: number) {
  const retailPrice = normalizeTo9EndingRetailPrice(basePrice * 1.1)
  return retailPrice ? Number((retailPrice - basePrice).toFixed(2)) : 0
}

function getStorePricePolicy(row: StandardInventorySku, basePrice?: number): StorePricePolicy {
  if (isAccessorySku(row)) {
    const markup = getAccessoryMarkup(basePrice ?? 0)
    return {
      label: '配件 ×1.1 取9尾',
      ruleText: '配件零售价按采集价 × 1.1 计算，再取 9 结尾。',
      markup,
      status: 'active',
    }
  }
  if (isSamePriceCategory(row)) {
    const subsidyRuleText = isSubsidyEligibleProduct(row)
      ? '电脑/手机/平板按平台最低价生成99尾门店价'
      : '同价类按平台最低价生成门店价'
    return {
      label: isSubsidyEligibleProduct(row) ? '最低价99尾' : '平台最低价',
      ruleText: subsidyRuleText,
      markup: 0,
      status: 'same',
    }
  }
  if (isGamingNotebook(row)) {
    const baseMarkup = basePrice && basePrice >= 10000 ? 400 : 300
    const whiteExtraMarkup = isWhiteGamingNotebook(row) ? 500 : 0
    const markup = baseMarkup + whiteExtraMarkup
    return {
      label: whiteExtraMarkup ? `游戏本 +${baseMarkup}+白色${whiteExtraMarkup}` : `游戏本 +${markup}`,
      ruleText: '电脑按京东/官旗最低价套门店加价；游戏本 10000 以上加 400，10000 以下加 300；白色游戏笔记本在此基础上额外加 500；有教育补的笔记本再封顶加回 500；以上为叠加关系，最终99尾',
      markup,
      status: 'active',
    }
  }
  if (isThinNotebook(row)) {
    const markup = basePrice && basePrice >= 5000 ? 300 : 200
    return {
      label: `轻薄本 +${markup}`,
      ruleText: '电脑按京东/官旗最低价套门店加价；轻薄本 5000 以上加 300，5000 以下加 200；有教育补的笔记本再封顶加回 500；以上为叠加关系，最终99尾',
      markup,
      status: 'active',
    }
  }
  return {
    label: '待确认',
    ruleText: '未命中当前门店价口径，先完成平台采价后确认',
    markup: 0,
    status: 'pending',
  }
}

function cleanSearchTerm(value?: string) {
  return String(value ?? '')
    .replace(/\*/g, '')
    .replace(/\bWIN(?:DOWS)?\s*11\b/gi, '')
    .replace(/\b11C\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim()
}

function normalizeLookupKey(value?: string) {
  return String(value ?? '')
    .trim()
    .toUpperCase()
    .replace(/\s+/g, '')
}

type CollectionLinkRow = Pick<StandardInventorySku, 'skuKey' | 'productName'> & Partial<StandardInventorySku>

function buildJdSearchKeyword(row: CollectionLinkRow) {
  const text = cleanSearchTerm(`${row.productName} ${row.spec ?? ''}`)
  const model = text.match(/(YOGA|小新|拯救者|LEGION|来酷|LECOO|斗战者|[RY]\d{4}P?|Y\d{4}P?|战\d{4}|N\d{3}[A-Z]?|PRO\d{2}|AIR\s?\d{2})/i)?.[0]
  const cpu = text.match(/(?:ULTRA\s?[579][-\s]?\d{3}[A-Z]*|I[3579][-\s]?\d{4,5}[A-Z]*|R[3579][-\s]?[A-Z]?\d{3,5}[A-Z]*|R7[-\s]?H255|I[3579]\d{4,5}[A-Z]*)/i)?.[0]
  const memory = text.match(/\b(?:8|12|16|24|32|64)G(?:B)?\b/i)?.[0]
  const storage = text.match(/\b(?:512G|1T|2T)(?:SSD|固态)?\b/i)?.[0]
  const gpu = text.match(/RTX\s?(?:3050|4050|4060|4070|5050|5060|5070|5070TI|5080|5090)(?:-\dG)?/i)?.[0]
  const color = text.match(/(钛晶黑|碳晶黑|冰魄白|月幕白|深空灰|曜石金|灰色|白色|黑色|黑|白)/)?.[0]
  const fallbackName = cleanSearchTerm(row.productName).slice(0, 42)
  const tokens = ['联想', model, cpu, memory, storage, gpu, color].filter(Boolean) as string[]
  return tokens.length >= 3 ? cleanSearchTerm(tokens.join(' ')) : fallbackName
}

function isMotoRetailRow(row: CollectionLinkRow) {
  return /moto|motorola|摩托罗拉/i.test(`${row.productName} ${row.category ?? ''} ${row.pnMtm ?? ''}`)
}

function isTabletRetailRow(row: CollectionLinkRow) {
  return /平板|PAD|TAB|TB\d+|Y700|Y900/i.test(`${row.productName} ${row.category ?? ''} ${row.spec ?? ''} ${row.pnMtm ?? ''}`)
}

function isLegionTabletRetailRow(row: CollectionLinkRow) {
  return /拯救者|LEGION|Y700|Y900/i.test(`${row.productName} ${row.category ?? ''} ${row.spec ?? ''}`)
}

function getJdBackupSearchUrl(row: CollectionLinkRow, target: 'tablet' | 'moto' | 'lenovoOfficial' | 'legion') {
  const keyword = buildJdSearchKeyword(row)
  const targetName = {
    tablet: '联想平板京东自营旗舰店',
    moto: '联想moto手机京东自营旗舰店',
    lenovoOfficial: '联想官方旗舰店',
    legion: '联想拯救者官方旗舰店',
  }[target]
  return `https://search.jd.com/Search?keyword=${encodeURIComponent(`${targetName} ${keyword}`)}&enc=utf-8`
}

function getTmallStoreSearchUrl(row: CollectionLinkRow, store: 'lenovo' | 'lecoo' | 'moto') {
  if (store === 'moto') return `https://list.tmall.com/search_product.htm?q=${encodeURIComponent(buildJdSearchKeyword(row))}`
  const host = store === 'lecoo' ? 'lkzsh.tmall.com' : 'lenovo.tmall.com'
  return `https://${host}/search.htm?q=${encodeURIComponent(buildJdSearchKeyword(row))}`
}

function isDirectProductUrl(value?: string) {
  return Boolean(value && (
    /^https:\/\/item\.jd\.com\/\d+\.html(?:[?#].*)?$/i.test(value)
    || /^https:\/\/item\.lenovo\.com\.cn\/product\/\d+\.html(?:[?#].*)?$/i.test(value)
    || /^https:\/\/detail\.tmall\.com\/item\.htm(?:[?#].*)?$/i.test(value)
  ))
}

function getMarketplaceTruthState(record?: MarketplaceRecordItem): MarketplaceTruthState {
  if (!record) return 'missing'
  const directUrl = record.evidence?.evidenceUrl ?? record.configuredUrl
  if (record.collectionStatus === 'unavailable') return 'unavailable'
  if (record.collectionStatus === 'manual_review_required') return 'manual_review'
  if (record.collectionStatus === 'url_configured_only' || record.confidence === 'url_configured_only') return 'placeholder'
  if (record.collectionStatus !== 'captured') return 'manual_review'
  if (!isDirectProductUrl(directUrl)) return 'manual_review'
  if (record.confidence === 'confirmed') return 'confirmed'
  if (record.confidence === 'provisional') return 'provisional'
  return 'manual_review'
}

function buildMarketplaceSourceAudit(source: MarketplaceRecordSource, records: MarketplaceRecordItem[]): MarketplaceSourceAudit {
  const confirmed = new Set<string>()
  const provisional = new Set<string>()
  const manualReview = new Set<string>()
  const placeholder = new Set<string>()
  const unavailable = new Set<string>()
  const totals = new Set<string>()

  for (const record of records) {
    totals.add(record.productId)
    const state = getMarketplaceTruthState(record)
    if (state === 'confirmed') confirmed.add(record.productId)
    else if (state === 'provisional') provisional.add(record.productId)
    else if (state === 'manual_review') manualReview.add(record.productId)
    else if (state === 'placeholder') placeholder.add(record.productId)
    else if (state === 'unavailable') unavailable.add(record.productId)
  }

  const detailParts = [
    confirmed.size ? `${confirmed.size} 已确认` : undefined,
    provisional.size ? `${provisional.size} 待复核` : undefined,
    manualReview.size ? `${manualReview.size} 人工线索` : undefined,
    placeholder.size ? `${placeholder.size} 仅入口` : undefined,
    unavailable.size ? `${unavailable.size} 不可用` : undefined,
  ].filter(Boolean) as string[]

  const statusLabel = confirmed.size
    ? (provisional.size || manualReview.size || placeholder.size ? '部分采集' : '已确认')
    : provisional.size || manualReview.size
      ? '待复核'
      : placeholder.size
        ? '仅入口'
        : '待采集'

  return {
    source,
    confirmedCount: confirmed.size,
    provisionalCount: provisional.size,
    manualReviewCount: manualReview.size,
    placeholderCount: placeholder.size,
    unavailableCount: unavailable.size,
    totalProductCount: totals.size,
    statusLabel,
    detail: detailParts.length ? detailParts.join(' · ') : '暂无真实采价记录',
    note: '仅把详情页/人工快照算作采价结果，入口 URL 不算已采集。',
    tone: confirmed.size ? 'active' : provisional.size || manualReview.size ? 'warn' : 'pending',
  }
}

function getStockRisk(row: StandardInventorySku) {
  if (row.unsellableStock > 0) return '不可售'
  if (row.pendingInboundStock > 0) return '待入库'
  if (row.currentStock >= 20) return '高库存'
  if (row.currentStock <= 1) return '低库存'
  return '正常'
}

function getQuotePriority(row: StandardInventorySku) {
  const text = `${row.category ?? ''}${row.jdSubcategory ?? ''}${row.productName}`
  if (/游戏笔记本|轻薄笔记本|平板电脑|游戏主机|一体机|商务台式/.test(text)) return '高'
  if (/显示器|打印机|手机|智能生活/.test(text)) return '中'
  return '低'
}

function getQuoteCollectionRows(inventory: StandardInventorySnapshot | null) {
  if (!inventory) return []
  return inventory.skus
    .filter((row) => getDisplayTotalStock(row) > 0)
    .map((row) => ({
      ...row,
      priority: getQuotePriority(row),
      stockRisk: getStockRisk(row),
      sources: /电脑配件|耳机音箱/.test(row.category ?? '')
        ? ['京东']
        : ['联想官网', '京东'],
    }))
    .sort((a, b) => {
      const priorityScore = { 高: 3, 中: 2, 低: 1 }
      return priorityScore[b.priority as keyof typeof priorityScore] - priorityScore[a.priority as keyof typeof priorityScore]
        || b.currentStock - a.currentStock
    })
    .slice(0, 12)
}

