function getStoreRetailRuleProtectionState(report?: Record<string, unknown> | null) {
  const steps = Array.isArray(report?.steps) ? report.steps as Array<Record<string, unknown>> : []
  const protectionStep = steps.find((step) => String(step.step ?? '') === 'verify_store_retail_rule_protection')
  const metrics = protectionStep && typeof protectionStep.metrics === 'object' && protectionStep.metrics
    ? protectionStep.metrics as Record<string, unknown>
    : undefined
  const changedCount = Number(metrics?.changedProtectedRuleFileCount ?? 0)
  const protectedCount = Number(metrics?.protectedRuleFileCount ?? 0)
  const stepStatus = String(protectionStep?.status ?? '')
  if (!protectionStep) {
    return {
      state: 'unverified' as const,
      label: '未校验',
      detail: '本轮报告里还没有门店零售价规则保护校验步骤。',
      changedCount,
      protectedCount,
    }
  }
  if (stepStatus === 'completed' && changedCount === 0) {
    return {
      state: 'safe' as const,
      label: '已保护',
      detail: `已校验 ${protectedCount || 0} 个手动门店价规则文件，未发现改写。`,
      changedCount,
      protectedCount,
    }
  }
  return {
    state: 'changed' as const,
    label: '有改写风险',
    detail: protectionStep?.detail ? String(protectionStep.detail) : `检测到 ${changedCount} 个手动门店价规则文件被改写。`,
    changedCount,
    protectedCount,
  }
}

const grayLibraryCategoryOrder = [
  '全部',
  '联想笔记本',
  '联想平板',
  '联想台式机',
  'THINK笔记本',
  'THINK台式机',
  '扬天',
  '瑞天',
  'MOTO',
] as const

function inferQuoteCategoryFromText(productName: string, matchedCategory?: string) {
  if (matchedCategory) return matchedCategory
  const text = String(productName ?? '').toUpperCase()
  if (/小新\\s*PRO\\s*16|小新PRO16|PRO\\s*16C|PRO16C|PRO\\s*16GT|PRO16GT/.test(text)) return '轻薄笔记本'
  if (/小新\\s*PRO\\s*14|小新PRO14|PRO\\s*14C|PRO14C|PRO\\s*14GT|PRO14GT/.test(text)) return '轻薄笔记本'
  if (/一体机|AIO|24-ILL|27-ILL|27-IRH|F0[A-Z0-9]+/.test(text)) return '一体机'
  if (/CE\d{3}[A-Z]?|TZ830|H880|F870|L860|23\.8寸/.test(text)) return '一体机'
  if (/拯救者|LEGION|R7000|Y7000|R9000|Y9000|斗战者/.test(text)) return '游戏笔记本'
  if (/GEEKPRO|天逸|台式|主机|刃7000|THINKCENTRE|THINKSTATION|开天|M630Z|E50Z|M75Z|M70H|K-C4/.test(text)) return '商务台式'
  if (/平板|\bTAB\b|\bPAD\b|Y700(?!0)|\bTB[0-9A-Z]{4,}\b/.test(text)) return '平板电脑'
  if (/MOTO|RAZR|EDGE/.test(text)) return '手机'
  if (/YOGA|小新|THINKBOOK|THINKPAD|来酷|LECOO|AIR|PRO|N\d{3}[A-Z]?|MATEBOOK|HUAWEI/.test(text)) return '轻薄笔记本'
  return '未分类'
}

function getGrayQuoteCategory(productName: string, category?: string, series?: string) {
  const text = `${category ?? ''} ${series ?? ''} ${String(productName ?? '')}`.toUpperCase()
  if (/MATEBOOK|MATEPAD|HUAWEI|华为/.test(text)) return undefined
  if (/锋\s?7000|鋒\s?7000/.test(text)) return '联想台式机'
  if (/MOTO|RAZR|摩托/i.test(text)) return 'MOTO'
  if (/扬天/.test(text)) return '扬天'
  if (/瑞天/.test(text)) return '瑞天'
  if (/THINKPAD|THINKBOOK/.test(text)) return 'THINK笔记本'
  if (/THINKSTATION|THINKCENTRE/.test(text)) return 'THINK台式机'
  if (/\bTHINK\b/.test(text)) {
    return /台式|主机|工作站|STATION|CENTRE|M\d{2,3}|P\d{3}|T\d{3}/.test(text) ? 'THINK台式机' : 'THINK笔记本'
  }
  if (/平板|\bTAB\b|\bPAD\b|Y700(?!0)|TB\d+/i.test(text)) return '联想平板'
  if (/一体机|AIO|台式|主机|GEEKPRO|天逸|刃7000|异能者|擎天|开天|超翔|CE\d{3}[A-Z]?|K-C4|M630Z|E50Z|M75Z|M70H|TZ830|H880|F870|L860|24-ILL|27-ILL|27-IRH|F0[A-Z0-9]+/.test(text)) return '联想台式机'
  if (/小新|YOGA|拯救者|LEGION|来酷|LECOO|斗战者|[RY]\d{4}P?|战\d{4}|N\d{3}[A-Z]?|AIR|PRO\d{2}/i.test(text)) return '联想笔记本'
  return undefined
}

function inferQuoteLibraryCategory(productName: string, category?: string, series?: string) {
  const text = `${category ?? ''} ${series ?? ''} ${String(productName ?? '')}`.toUpperCase()
  if (/MOTO|RAZR|EDGE|XT\d+|PB[A-Z0-9]+/.test(text)) return '手机'
  if (/THINKBOOK|THINKPAD|THINK/.test(text)) return 'THINK系列'
  if (/小新/.test(text)) return '小新系列'
  if (/YOGA/.test(text)) return 'YOGA系列'
  if (/拯救者|LEGION|R7000|Y7000|R9000|Y9000/.test(text)) return '拯救者系列'
  if (/来酷|LECOO|斗战者/.test(text)) return '来酷系列'
  if (/MATEBOOK|HUAWEI/.test(text)) return '华为系列'
  if (/一体机|AIO|24-ILL|27-ILL|27-IRH|F0[A-Z0-9]+/.test(text)) return '一体机'
  if (/CE\d{3}[A-Z]?|TZ830|H880|F870|L860|23\.8寸/.test(text)) return '信创一体机'
  if (/GEEKPRO|天逸|台式|主机|刃7000|THINKCENTRE/.test(text)) return '台式机'
  if (/THINKSTATION|开天|M630Z|E50Z|M75Z|M70H|K-C4/.test(text)) return '信创台式机'
  if (/平板|TAB|PAD|Y700(?!0)/.test(text)) return '平板'
  if (/MOTO|RAZR|EDGE/.test(text)) return '手机'
  return category || '其它'
}

function getDistributorQuoteDisplayKey(quote: DistributorQuoteSnapshot['quotes'][number]) {
  return [
    normalizeLookupKey(quote.pnMtm),
    normalizeLookupKey(quote.productName),
    quote.pickupPrice ?? '',
    quote.subsidyPrice ?? '',
  ].join('|')
}

function inferQuoteModelName(productName: string, pnMtm?: string) {
  if (pnMtm) return pnMtm
  const text = String(productName ?? '').toUpperCase()
  const match = text.match(/(THINKBOOK\s?\d{2}\+?|THINKPAD\s?[A-Z0-9]+|MATEBOOK\s?D1[46](?:\s?SE)?|MATEBOOK\s?14|MATEBOOK\s?16|[RY]\d{4}P?|战\d{4}|N\d{3}[A-Z]?|PRO\d{2}(?:C|GT)?|AIR\s?\d{2}C?|Y700|Y9000|R7000|R9000|14C|16C|24-ILL|27-ILL|27-IRH|F0[A-Z0-9]+|K-C4|CE\d{3}[A-Z]?|M630Z|E50Z|M75Z|M70H|TZ830-V3|H880-T1|F870-F05|L860-T6)/)
  return match?.[1]?.replace(/\s+/g, '') ?? String(productName ?? '').slice(0, 24)
}

function buildProductLibraryLookupText(item: ProductLibraryProductListItem) {
  return [
    item.canonical_name,
    item.configuration_summary,
    item.pn_mtm,
    item.primary_sku_key,
    item.default_category,
    item.source_category,
    item.jd_subcategory,
    item.catalog_source,
  ]
    .filter(Boolean)
    .join(' ')
}

function getProductBrandBucket(value?: string) {
  const text = String(value ?? '').toUpperCase()
  if (/MOTO|RAZR|摩托/.test(text)) return 'moto'
  if (/来酷|LECOO|斗战者|N\d{3}[A-Z]?/.test(text)) return 'lecoo'
  if (/小新|XIAOXIN|PADPRO|TB\d{3}[A-Z]?/.test(text)) return 'xiaoxin'
  if (/YOGA/.test(text)) return 'yoga'
  if (/THINKPAD|THINKBOOK|THINKCENTRE|THINKSTATION|\bTHINK\b/.test(text)) return 'think'
  if (/拯救者|LEGION|Y7000|Y9000|R7000|R9000/.test(text)) return 'legion'
  return undefined
}

function isProductBrandCompatible(quoteText: string, productText: string) {
  const quoteBrand = getProductBrandBucket(quoteText)
  const productBrand = getProductBrandBucket(productText)
  if (!quoteBrand || !productBrand) return true
  return quoteBrand === productBrand
}

type ProductMatchConfig = {
  models: string[]
  cpuCodes: string[]
  cpuFamilies: string[]
  memories: string[]
  storages: string[]
  gpus: string[]
}

function extractProductMatchConfig(value?: string): ProductMatchConfig {
  const text = normalizeLookupKey(
    String(value ?? '')
      .replace(/酷睿|英特尔|INTEL/g, '')
      .replace(/锐龙|AMD/g, '')
      .replace(/GB/g, 'G')
      .replace(/1TB/g, '1T')
      .replace(/2TB/g, '2T'),
  )

  const collect = (pattern: RegExp, mapper = (raw: string) => raw) => Array.from(
    new Set(
      Array.from(text.matchAll(pattern))
        .map((match) => mapper(match[1] ?? match[0]))
        .filter(Boolean),
    ),
  )

  const cpuCodes = [
    ...collect(/(?:ULTRA|CORE|U|I)[3579]-?([0-9]{3,5})(?:HX|H|U|V|P|G|(?=(?:8|12|16|24|32|64)G))/g, (raw) => `CPU${raw}`),
    ...collect(/R[3579]-?H?([0-9]{3,5})(?:HX|H|U|V|P|G|(?=(?:8|12|16|24|32|64)G))/g, (raw) => `CPU${raw}`),
    ...collect(/(?:^|[^0-9])(?:2)?(125|170|225|255)(?:HX|H|U|V|P|G|(?=(?:8|12|16|24|32|64)G))/g, (raw) => `CPU${raw}`),
  ]

  return {
    models: collect(/(THINKBOOK\d{2}\+?|THINKPAD[A-Z0-9]+|小新(?:PRO)?(?:11|12\.?1|14|15|16|24|27)(?:C|GT)?|YOGA(?:27|32|360(?:14)?)|酷\d{3,4}|[RY]\d{4}P?|战\d{4}|锋\d{4}|N\d{3}[A-Z]?|TB\d{3}[A-Z]?|PRO\d{2}(?:C|GT)?|AIR\d{2}C?|Y700|Y9000|R7000|R9000|14C|15C|16C|24-ILL|27-ILL|27-IRH|F0[A-Z0-9]+)/g),
    cpuCodes: Array.from(new Set(cpuCodes)),
    cpuFamilies: collect(/(ULTRA[579]|CORE[3579]|U[3579]|I[3579]|R[3579])/g, (raw) => raw.replace(/^ULTRA/, 'U').replace(/^CORE/, 'U')),
    memories: collect(/(?:^|[^0-9])((?:8|12|16|24|32|64)G)/g),
    storages: collect(/(?:^|[^0-9])((?:128|256|512)G|[12]T)/g),
    gpus: collect(/(?:RTX)?(3050|4060|4070|5060|5070|5070TI|5080|5090)/g),
  }
}

function hasTokenOverlap(left: string[], right: string[]) {
  return left.some((item) => right.includes(item))
}

function isStrictUniqueProductMatch(quoteText: string, product: ProductLibraryProductListItem) {
  const productText = buildProductLibraryLookupText(product)
  if (!isProductBrandCompatible(quoteText, productText)) return false
  const quoteConfig = extractProductMatchConfig(quoteText)
  const productConfig = extractProductMatchConfig(productText)

  if (quoteConfig.models.length && !hasTokenOverlap(quoteConfig.models, productConfig.models)) return false
  if (quoteConfig.cpuCodes.length && !hasTokenOverlap(quoteConfig.cpuCodes, productConfig.cpuCodes)) return false
  if (!quoteConfig.cpuCodes.length && quoteConfig.cpuFamilies.length && !hasTokenOverlap(quoteConfig.cpuFamilies, productConfig.cpuFamilies)) return false
  if (quoteConfig.memories.length && !hasTokenOverlap(quoteConfig.memories, productConfig.memories)) return false
  if (quoteConfig.storages.length && !hasTokenOverlap(quoteConfig.storages, productConfig.storages)) return false
  if (quoteConfig.gpus.length && !hasTokenOverlap(quoteConfig.gpus, productConfig.gpus)) return false

  const requiredKindCount = [
    quoteConfig.models.length,
    quoteConfig.cpuCodes.length || quoteConfig.cpuFamilies.length,
    quoteConfig.memories.length,
    quoteConfig.storages.length,
    quoteConfig.gpus.length,
  ].filter(Boolean).length

  return requiredKindCount >= 2
}

function hasStrongProductConfigMatch(quoteText: string, productText: string) {
  const quoteConfig = extractProductMatchConfig(quoteText)
  const productConfig = extractProductMatchConfig(productText)
  const matchedKinds = [
    quoteConfig.models.length && hasTokenOverlap(quoteConfig.models, productConfig.models),
    quoteConfig.cpuCodes.length && hasTokenOverlap(quoteConfig.cpuCodes, productConfig.cpuCodes),
    !quoteConfig.cpuCodes.length && quoteConfig.cpuFamilies.length && hasTokenOverlap(quoteConfig.cpuFamilies, productConfig.cpuFamilies),
    quoteConfig.memories.length && hasTokenOverlap(quoteConfig.memories, productConfig.memories),
    quoteConfig.storages.length && hasTokenOverlap(quoteConfig.storages, productConfig.storages),
    quoteConfig.gpus.length && hasTokenOverlap(quoteConfig.gpus, productConfig.gpus),
  ].filter(Boolean).length
  return matchedKinds >= 4 || (
    matchedKinds >= 3
    && quoteConfig.models.length > 0
    && hasTokenOverlap(quoteConfig.models, productConfig.models)
  )
}

function buildQuoteLibraryCategoryStats(entries: QuoteLibraryEntry[]) {
  const counts = entries.reduce((map, entry) => {
    map.set(entry.libraryCategory, (map.get(entry.libraryCategory) ?? 0) + 1)
    return map
  }, new Map<string, number>())
  return [
    { label: '全部', count: entries.length },
    ...Array.from(counts.entries())
      .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0], 'zh-CN'))
      .map(([label, count]) => ({ label, count })),
  ] satisfies QuoteLibraryCategoryStat[]
}

function buildGrayLibraryCategoryStats(entries: QuoteLibraryEntry[]) {
  const counts = entries.reduce((map, entry) => {
    map.set(entry.libraryCategory, (map.get(entry.libraryCategory) ?? 0) + 1)
    return map
  }, new Map<string, number>())
  return grayLibraryCategoryOrder.map((label) => ({
    label,
    count: label === '全部' ? entries.length : counts.get(label) ?? 0,
  })) satisfies QuoteLibraryCategoryStat[]
}

function buildQuoteLibraryGroups(entries: QuoteLibraryEntry[]) {
  const categoryMap = entries.reduce((map, entry) => {
    const categoryGroup = map.get(entry.category) ?? {
      category: entry.category,
      itemCount: 0,
      seriesCount: 0,
      latestCollectedAt: entry.collectedAt,
      quoteDates: new Set<string>(),
      seriesMap: new Map<string, {
        series: string
        itemCount: number
        latestCollectedAt?: string
        items: QuoteLibraryEntry[]
      }>(),
    }
    categoryGroup.itemCount += 1
    if (entry.collectedAt && (!categoryGroup.latestCollectedAt || entry.collectedAt > categoryGroup.latestCollectedAt)) {
      categoryGroup.latestCollectedAt = entry.collectedAt
    }
    if (entry.quoteDate) categoryGroup.quoteDates.add(entry.quoteDate)
    const seriesGroup = categoryGroup.seriesMap.get(entry.series) ?? {
      series: entry.series,
      itemCount: 0,
      latestCollectedAt: entry.collectedAt,
      items: [],
    }
    seriesGroup.itemCount += 1
    if (entry.collectedAt && (!seriesGroup.latestCollectedAt || entry.collectedAt > seriesGroup.latestCollectedAt)) {
      seriesGroup.latestCollectedAt = entry.collectedAt
    }
    seriesGroup.items.push(entry)
    categoryGroup.seriesMap.set(entry.series, seriesGroup)
    map.set(entry.category, categoryGroup)
    return map
  }, new Map<string, {
    category: string
    itemCount: number
    seriesCount: number
    latestCollectedAt?: string
    quoteDates: Set<string>
    seriesMap: Map<string, {
      series: string
      itemCount: number
      latestCollectedAt?: string
      items: QuoteLibraryEntry[]
    }>
  }>())

  return Array.from(categoryMap.values()).map((group) => {
    const series = Array.from(group.seriesMap.values())
      .map((item) => ({
        ...item,
        items: [...item.items].sort((left, right) => (right.quotePrice ?? -1) - (left.quotePrice ?? -1) || left.productName.localeCompare(right.productName, 'zh-CN')),
      }))
      .sort((left, right) => right.itemCount - left.itemCount || left.series.localeCompare(right.series, 'zh-CN'))
    return {
      category: group.category,
      itemCount: group.itemCount,
      seriesCount: series.length,
      latestCollectedAt: group.latestCollectedAt,
      quoteDates: Array.from(group.quoteDates).sort(),
      series,
    } as QuoteLibraryCategoryGroup
  }).sort((left, right) => right.itemCount - left.itemCount || left.category.localeCompare(right.category, 'zh-CN'))
}

function getFingerprintTokens(value?: string) {
  const text = String(value ?? '')
    .toUpperCase()
    .replace(/\s+/g, '')
    .replace(/酷睿|英特尔|INTEL/g, '')
    .replace(/锐龙|AMD/g, '')
    .replace(/集成显卡|集显|集\//g, '集')
    .replace(/固态|SSD/g, '')
    .replace(/RTX\s*/g, 'RTX')
    .replace(/GB/g, 'G')
    .replace(/1TB/g, '1T')
    .replace(/2TB/g, '2T')
  const tokens = new Set<string>()

  const addAll = (pattern: RegExp, mapper = (token: string) => token) => {
    for (const match of text.matchAll(pattern)) tokens.add(mapper(match[1] ?? match[0]))
  }
  const addGroup = (pattern: RegExp, groupIndex: number, mapper = (token: string) => token) => {
    for (const match of text.matchAll(pattern)) {
      const token = match[groupIndex]
      if (token) tokens.add(mapper(token))
    }
  }

  addAll(/(YOGA|小新|拯救者|LEGION|来酷|LECOO|斗战者|GEEKPRO|THINKPAD|THINKBOOK|THINKCENTRE|THINKSTATION)/g, (token) => token === 'LECOO' ? '来酷' : token === 'LEGION' ? '拯救者' : token)
  addAll(/(THINKBOOK\d{2}\+?|THINKPAD[A-Z0-9]+|小新(?:PRO)?(?:11|12\.?1|14|15|16|24|27)(?:C|GT)?|YOGA(?:27|32|360(?:14)?)|酷\d{3,4}|[RY]\d{4}P?|战\d{4}|锋\d{4}|N\d{3}[A-Z]?|TB\d{3}[A-Z]?|PRO\d{2}(?:C|GT)?|AIR\d{2}C?|1[456]C)/g)
  addAll(/(PRO\d{2})(?:C|GT)?/g)
  addAll(/(TB\d{3}[A-Z]?)/g)
  if (/N176B?|战7000/.test(text)) tokens.add('战7000')
  addAll(/(ULTRA[579][-]?\d{3}[A-Z]*|CORE[3579][-]?\d{3}[A-Z]*|U[3579][-]?\d{3,4}[A-Z]*|I[3579][-]?\d{4,5}[A-Z]*)/g, (token) => token.replace(/^ULTRA/, 'U').replace(/^CORE/, 'U'))
  addAll(/(ULTRA[579]|CORE[3579]|U[3579]|I[3579]|R[3579])/g, (token) => token.replace(/^ULTRA/, 'U').replace(/^CORE/, 'U'))
  addAll(/(?:ULTRA|CORE|U|I)[3579][-]?([0-9]{5})(?:HX|H|U|V|P)/g, (token) => `CPU${token}`)
  addAll(/(?:ULTRA|CORE|U|I)[3579][-]?([0-9]{3,4})(?:HX|H|U|V|P|(?=(?:8|12|16|24|32|64)G))/g, (token) => `CPU${token}`)
  addAll(/R[3579]-[A-Z]?([0-9]{3,5})(?:HX|H|U|V|P|(?=(?:8|12|16|24|32|64)G))/g, (token) => `CPU${token}`)
  addAll(/(?:^|[^0-9])(?:2)?(125|170|225|255)(?:HX|H|U|V|P|(?=(?:8|12|16|24|32|64)G))/g, (token) => `CPU${token}`)
  addAll(/(?:RTX)?(3050|4060|4070|5060|5070|5070TI|5080|5090)/g)
  addAll(/(?:^|[^0-9])((?:8|12|16|24|32|64)G)/g)
  addGroup(/(?:ULTRA[579][-]?\d{0,4}[A-Z]*|CORE[3579][-]?\d{0,4}[A-Z]*|U[3579][-]?\d{0,4}[A-Z]*|I[3579][-]?\d{0,5}[A-Z]*|R[3579]-[A-Z]?\d{0,5}[A-Z]*)((?:8|12|16|24|32|64)G)/g, 1)
  addAll(/(?:^|[^0-9])((?:128|256|512)G?|[12]T)/g, (token) => /G$|T$/.test(token) ? token : `${token}G`)
  addAll(/(\d{2}(?:\.\d)?寸)/g)

  return tokens
}

function getFingerprintScore(leftText?: string, rightText?: string) {
  const left = getFingerprintTokens(leftText)
  const right = getFingerprintTokens(rightText)
  if (!left.size || !right.size) return 0

  const pick = (tokens: Set<string>, kind: 'series' | 'model' | 'cpu' | 'gpu' | 'memory' | 'storage') => Array.from(tokens).filter((token) => {
    if (kind === 'series') return /^(?:YOGA|小新|拯救者|LEGION|来酷|LECOO|斗战者|GEEKPRO|THINKPAD|THINKBOOK|THINKCENTRE|THINKSTATION)$/i.test(token)
    if (kind === 'model') return /^(?:THINKBOOK\d{2}\+?|THINKPAD[A-Z0-9]+|小新(?:PRO)?(?:11|12\.?1|14|15|16|24|27)(?:C|GT)?|YOGA(?:27|32|360(?:14)?)|酷\d{3,4}|[RY]\d{4}P?|战\d{4}|锋\d{4}|N\d{3}[A-Z]?|TB\d{3}[A-Z]?|PRO\d{2}(?:C|GT)?|AIR\d{2}C?|1[456]C)$/i.test(token)
    if (kind === 'cpu') return /^(?:CPU\d{3,5}|U[3579]|I[3579]|R[3579])/i.test(token)
    if (kind === 'gpu') return /^(?:3050|4060|4070|5060|5070|5070TI|5080|5090)$/i.test(token)
    if (kind === 'memory') return /^(?:8|12|16|24|32|64)G$/i.test(token)
    return /^(?:(?:128|256|512)G|[12]T)$/i.test(token)
  })
  const hasOverlap = (leftTokens: string[], rightTokens: string[]) => leftTokens.some((token) => rightTokens.includes(token))
  const leftSeries = pick(left, 'series')
  const rightSeries = pick(right, 'series')
  const hasSeriesOverlap = hasOverlap(leftSeries, rightSeries)
  if (leftSeries.length && rightSeries.length && !hasSeriesOverlap) return 0
  const leftModels = pick(left, 'model')
  const rightModels = pick(right, 'model')
  const hasModelOverlap = hasOverlap(leftModels, rightModels)
  const hasModelConflict = leftModels.length > 0 && rightModels.length > 0 && !hasModelOverlap
  const hasAnyModel = leftModels.length > 0 || rightModels.length > 0

  const criticalKinds: Array<'model' | 'cpu' | 'gpu' | 'memory' | 'storage'> = ['model', 'cpu', 'gpu', 'memory', 'storage']
  let criticalCompared = 0
  let criticalMatched = 0

  for (const kind of criticalKinds) {
    const leftCritical = pick(left, kind)
    const rightCritical = pick(right, kind)
    if (!leftCritical.length || !rightCritical.length) continue
    criticalCompared += 1
    if (hasOverlap(leftCritical, rightCritical)) criticalMatched += 1
  }
  if (!hasModelConflict && (!hasAnyModel || hasModelOverlap) && criticalCompared >= 4 && criticalMatched >= 4) return 1
  if (!hasModelConflict && hasModelOverlap && criticalCompared >= 3 && criticalMatched >= 3) return 0.92

  let matched = 0
  let totalWeight = 0
  for (const item of left) {
    const weight = /^(?:THINKBOOK\d{2}\+?|THINKPAD[A-Z0-9]+|小新(?:PRO)?(?:11|12\.?1|14|15|16|24|27)(?:C|GT)?|YOGA(?:27|32|360(?:14)?)|酷\d{3,4}|[RY]\d{4}P?|战\d{4}|锋\d{4}|N\d{3}[A-Z]?|TB\d{3}[A-Z]?|PRO\d{2}(?:C|GT)?|AIR\d{2}C?|1[456]C)$/i.test(item)
      ? 4
      : /^(?:ULTRA|CORE|U[3579]|I[3579]|R[3579]|3050|4060|4070|5060|5070|5070TI|5080|5090)/i.test(item)
        ? 3
        : /^(?:8|12|16|24|32|64)G$/i.test(item)
          ? 2
        : 1
    totalWeight += weight
    if (right.has(item)) matched += weight
  }
  const weightedScore = matched / Math.max(totalWeight, 1)
  if (criticalCompared < 2) return Math.min(weightedScore, 0.5)
  if (criticalCompared >= 2 && criticalMatched === criticalCompared && weightedScore >= 0.55) {
    return Math.max(weightedScore, 0.82)
  }
  return weightedScore
}

function isAccessoryOrLowValueSku(row: StandardInventorySku) {
  const text = `${row.category ?? ''} ${row.jdSubcategory ?? ''} ${row.productName}`
  return /电脑配件|耳机音箱|键盘|鼠标|适配器|支架|保护夹|钢化膜|背包|配件|耗材/.test(text)
    || Boolean(row.agentPrice && row.agentPrice <= 2500)
}

function isPlausibleMatchedPrice(row: StandardInventorySku, price?: number) {
  if (!price) return false
  if (isAccessoryOrLowValueSku(row) && price > 2500) return false
  if (row.agentPrice && price > row.agentPrice + 2500) return false
  return true
}

function findRealtimePurchasePrice(row: StandardInventorySku, distributorQuotes: DistributorQuoteSnapshot | null) {
  const quotes = distributorQuotes?.quotes ?? []
  const pnKey = normalizeLookupKey(row.pnMtm)
  const direct = pnKey ? quotes.find((quote) => normalizeLookupKey(quote.pnMtm) === pnKey) : undefined
  if (direct && isPlausibleMatchedPrice(row, direct.pickupPrice)) return direct.pickupPrice
  return undefined
}

function Panel({
  title,
  icon,
  children,
  className = '',
  action,
}: {
  title: string
  icon?: React.ReactNode
  children: React.ReactNode
  className?: string
  action?: React.ReactNode
}) {
  if (!title && !icon && !action) {
    return (
      <section className={`panel ${className}`}>
        {children}
      </section>
    )
  }

  return (
    <section className={`panel ${className}`}>
      <div className="panel-title">
        <span className="panel-title-main">
          {icon}
          {title}
        </span>
        {action}
      </div>
      {children}
    </section>
  )
}

function HeaderBar() {
  return (
    <header className="header-bar">
      <div className="brand">
        <span className="logo-mark">Lenovo</span>
        <span className="brand-cn">联想</span>
      </div>
      <button className="store-picker" type="button">
        <Store size={17} />
        {currentStoreName}
        <ChevronDown size={16} />
      </button>
    </header>
  )
}

