function RetailOpsWorkbench() {
  const [activeModule, setActiveModule] = useState<RetailOpsModuleKey>('pos')
  const [activeAction, setActiveAction] = useState<string>('新建销售单')
  const [coreStatus, setCoreStatus] = useState<RetailCoreStatus | null>(null)
  const [categoryTree, setCategoryTree] = useState<RetailCoreCategoryTree | null>(null)
  const [serialItems, setSerialItems] = useState<RetailCoreSerialItems | null>(null)
  const [coreInventory, setCoreInventory] = useState<StandardInventorySnapshot | null>(null)
  const [coreMovements, setCoreMovements] = useState<RetailCoreMovements | null>(null)
  const [coreSalesOrders, setCoreSalesOrders] = useState<RetailCoreSalesOrders | null>(null)
  const [coreSyncTasks, setCoreSyncTasks] = useState<RetailCoreSyncTasks | null>(null)
  const [priceTagStatus, setPriceTagStatus] = useState<Awaited<ReturnType<typeof getPriceTagStatus>>>(null)
  const [isSaving, setIsSaving] = useState(false)
  const [operationMessage, setOperationMessage] = useState('')
  const [serialSearch, setSerialSearch] = useState('')
  const [salesForm, setSalesForm] = useState({ skuKey: '', serialNumber: '', dealPrice: '', customerName: '散客', operatorId: 'EMP001' })
  const [purchaseForm, setPurchaseForm] = useState({ skuKey: '', productName: '', pnMtm: '', serialNumbers: '', costPrice: '', supplierId: '联想厂家', operatorId: 'EMP001' })
  const [priceTagForm, setPriceTagForm] = useState({ skuKey: '', storePrice: '', subsidyPrice: '', deviceId: '' })
  const selectedModule = retailOpsModules.find((module) => module.key === activeModule) ?? retailOpsModules[0]
  const tableCounts = coreStatus?.tableCounts ?? {}
  const salesOutboundCount = coreMovements?.typeCounts.sales_outbound ?? 0
  const purchaseInboundCount = coreMovements?.typeCounts.purchase_inbound ?? 0
  const transferOutboundCount = coreMovements?.typeCounts.transfer_outbound ?? 0

  async function reloadRetailOpsData() {
    const [status, categories, serials, inventory, movements, orders, tasks, tagStatus] = await Promise.all([
      getRetailCoreStatus(),
      getRetailCoreCategoryTree(),
      getRetailCoreSerialItems(5000),
      getLiveInventorySnapshot({ compact: false }),
      getRetailCoreMovements(5000),
      getRetailCoreSalesOrders(100),
      getRetailCoreSyncTasks(),
      getPriceTagStatus(),
    ])
    setCoreStatus(status)
    setCategoryTree(categories)
    setSerialItems(serials)
    setCoreInventory(inventory)
    setCoreMovements(movements)
    setCoreSalesOrders(orders)
    setCoreSyncTasks(tasks)
    setPriceTagStatus(tagStatus)
  }

  useEffect(() => {
    let active = true
    const refresh = (preserveScroll = false) => {
      Promise.all([
        getRetailCoreStatus(),
        getRetailCoreCategoryTree(),
        getRetailCoreSerialItems(5000),
        getLiveInventorySnapshot({ compact: false }),
        getRetailCoreMovements(5000),
        getRetailCoreSalesOrders(100),
        getRetailCoreSyncTasks(),
        getPriceTagStatus(),
      ]).then(([status, categories, serials, inventory, movements, orders, tasks, tagStatus]) => {
        if (!active) return
        const update = () => {
          setCoreStatus(status)
          setCategoryTree(categories)
          setSerialItems(serials)
          setCoreInventory(inventory)
          setCoreMovements(movements)
          setCoreSalesOrders(orders)
          setCoreSyncTasks(tasks)
          setPriceTagStatus(tagStatus)
        }
        if (preserveScroll) preserveScrollPosition(update)
        else update()
      })
    }
    refresh()
    const timer = window.setInterval(() => refresh(true), cockpitRefreshIntervalMs)
    return () => {
      active = false
      window.clearInterval(timer)
    }
  }, [])

  function parseSerialInput(value: string) {
    return value.split(/[\s,，;；]+/).map((item) => item.trim()).filter(Boolean)
  }

  function showMessage(message: string) {
    setOperationMessage(message)
    window.setTimeout(() => setOperationMessage(''), 5000)
  }

  function findFirstSellableSerial() {
    return (serialItems?.items ?? []).find((item) => item.status === 'in_stock')
  }

  function handleModuleChange(moduleKey: RetailOpsModuleKey) {
    setActiveModule(moduleKey)
    const module = retailOpsModules.find((item) => item.key === moduleKey)
    setActiveAction(module?.actions[0] ?? '')
  }

  function handleActionClick(action: string) {
    setActiveAction(action)
    if (action === '扫码绑定 SN' || action === 'SN 检索') {
      const first = findFirstSellableSerial()
      if (first) {
        setSerialSearch(first.serial_number)
        setSalesForm((form) => ({ ...form, skuKey: form.skuKey || first.sku_key, serialNumber: form.serialNumber || first.serial_number }))
      }
    }
    if (action === '导出分类对照表') exportCategoryMappings()
    if (action === '失败重发') retryFirstSyncTask()
    if (action === '查看分类树' || action === 'SKU 分类映射') showMessage('分类映射已加载，下面列表按智店通原始子类、展示分类、导购子类展示。')
    if (action.includes('审批') || action.includes('打印') || action.includes('保修') || action.includes('状态') || action.includes('员工') || action.includes('角色')) {
      showMessage(`${action} 已进入操作区，当前先记录本地业务事实，外部设备/权限细节后续接入。`)
    }
  }

  async function submitSalesOrder(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!salesForm.skuKey.trim()) return showMessage('销售单缺少 SKU。')
    if (!salesForm.serialNumber.trim()) return showMessage('销售单必须绑定在库 SN，当前不允许无 SN 出库。')
    const dealPrice = Number(salesForm.dealPrice)
    if (!Number.isFinite(dealPrice) || dealPrice <= 0) return showMessage('销售单成交价必须大于 0。')
    const serialNumbers = salesForm.serialNumber.trim() ? [salesForm.serialNumber.trim()] : []
    setIsSaving(true)
    const result = await createRetailSalesOrder({
      storeCode: 'D0186124',
      operatorId: salesForm.operatorId.trim() || 'EMP001',
      customerName: salesForm.customerName.trim() || '散客',
      note: '进销存销售端 UI 创建',
      lines: [{
        skuKey: salesForm.skuKey.trim(),
        quantity: serialNumbers.length,
        serialNumbers,
        dealPrice,
      }],
    })
    setIsSaving(false)
    if (!result) return showMessage('销售单创建失败：请确认 SN 在库且 SKU 匹配。')
    showMessage(`销售单 ${result.orderId} 已创建，已生成智店通同步任务 ${result.pendingSyncTaskId}。`)
    setSalesForm((form) => ({ ...form, serialNumber: '', dealPrice: '' }))
    await reloadRetailOpsData()
  }

  async function submitPurchaseOrder(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!purchaseForm.skuKey.trim()) return showMessage('入库单缺少 SKU。')
    const serialNumbers = parseSerialInput(purchaseForm.serialNumbers)
    if (!serialNumbers.length) return showMessage('采购入库必须填写 SN 清单，当前不允许无 SN 入库。')
    setIsSaving(true)
    const result = await createRetailPurchaseOrder({
      supplierId: purchaseForm.supplierId.trim() || '联想厂家',
      operatorId: purchaseForm.operatorId.trim() || 'EMP001',
      locationCode: 'SALES_FLOOR',
      note: '进销存采购入库 UI 创建',
      lines: [{
        skuKey: purchaseForm.skuKey.trim(),
        productName: purchaseForm.productName.trim() || purchaseForm.skuKey.trim(),
        pnMtm: purchaseForm.pnMtm.trim(),
        quantity: serialNumbers.length,
        serialNumbers,
        costPrice: purchaseForm.costPrice ? Number(purchaseForm.costPrice) : undefined,
      }],
    })
    setIsSaving(false)
    if (!result) return showMessage('采购入库失败：请检查 SKU、SN 清单和后端服务。')
    showMessage(`采购单 ${result.orderId} 已入库 ${result.serialCount} 台，并生成智店通同步任务。`)
    setPurchaseForm((form) => ({ ...form, serialNumbers: '', costPrice: '' }))
    await reloadRetailOpsData()
  }

  async function submitPriceTagUpdate(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!priceTagForm.skuKey.trim()) return showMessage('价签任务缺少 SKU。')
    setIsSaving(true)
    const result = await createRetailPriceTagUpdate({
      skuKey: priceTagForm.skuKey.trim(),
      templateId: 'default-store-price',
      deviceId: priceTagForm.deviceId.trim() || undefined,
      pricePayload: {
        storePrice: priceTagForm.storePrice ? Number(priceTagForm.storePrice) : undefined,
        subsidyPrice: priceTagForm.subsidyPrice ? Number(priceTagForm.subsidyPrice) : undefined,
      },
    })
    setIsSaving(false)
    if (!result) return showMessage('价签任务创建失败：请检查 SKU 和后端服务。')
    showMessage(`价签任务 ${result.taskId} 已创建，等待价签网关同步。`)
    await reloadRetailOpsData()
  }

  async function retryTask(taskId: string) {
    setIsSaving(true)
    const result = await retryRetailSyncTask(taskId)
    setIsSaving(false)
    if (!result) return showMessage(`同步任务 ${taskId} 重试失败。`)
    showMessage(`同步任务 ${taskId} 已重新置为 pending。`)
    await reloadRetailOpsData()
  }

  async function retryFirstSyncTask() {
    const task = (coreSyncTasks?.items ?? []).find((item) => item.status !== 'success') ?? coreSyncTasks?.items?.[0]
    if (!task) return showMessage('当前没有可重试的同步任务。')
    await retryTask(task.id)
  }

  async function deletePlaceholderSalesOrder(orderId: string) {
    const confirmText = `确认删除未在智店通出库的占位销售单 ${orderId}？\n将同时删除 SQL 销售单、库存流水、同步任务，并回收入库 SN 状态。`
    if (!window.confirm(confirmText)) return
    if (!window.confirm('二次确认：这笔单还没有在智店通真实出库，现在立即删除吗？')) return
    setIsSaving(true)
    const result = await deleteRetailSalesOrder(orderId)
    setIsSaving(false)
    if (!result.ok) {
      return showMessage(`删除失败：${result.error}`)
    }
    removePosStagedOrderMirror(orderId)
    showMessage(`占位销售单 ${result.orderId} 已删除，已回收 ${result.revertedSerialCount} 个 SN。`)
    await reloadRetailOpsData()
  }

  function exportCategoryMappings() {
    const rows = categoryTree?.skuMappings ?? []
    if (!rows.length) return showMessage('没有可导出的分类映射。')
    const header = ['sku_key', 'zhidiantong_category', 'smart_retail_category', 'jd_subcategory', 'catalog_source']
    const csv = [
      header.join(','),
      ...rows.map((row) => [
        row.sku_key,
        row.zhidiantong_category,
        row.smart_retail_category,
        row.jd_subcategory,
        row.catalog_source,
      ].map(escapeCsvValue).join(',')),
    ].join('\n')
    const blob = new Blob([`\ufeff${csv}`], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = `zhidiantong-category-mapping-${new Date().toISOString().slice(0, 10)}.csv`
    link.click()
    URL.revokeObjectURL(url)
    showMessage('分类对照表已导出，保持智店通原始子类别口径。')
  }

  function renderActionPanel() {
    if (activeModule === 'pos') {
      const firstSerial = findFirstSellableSerial()
      return (
        <form className="retail-ops-action-panel" onSubmit={submitSalesOrder}>
          <div>
            <span>销售开单</span>
            <strong>创建销售单、扣减 SN 库存、生成智店通同步任务</strong>
          </div>
          <div className="retail-ops-form-grid">
            <label>SKU<input value={salesForm.skuKey} onChange={(event) => setSalesForm({ ...salesForm, skuKey: event.target.value })} placeholder={firstSerial?.sku_key || '输入 SKU'} /></label>
            <label>SN<input value={salesForm.serialNumber} onChange={(event) => setSalesForm({ ...salesForm, serialNumber: event.target.value })} placeholder={firstSerial?.serial_number || '必须填写在库 SN'} /></label>
            <label>成交价<input type="number" min="0.01" step="0.01" value={salesForm.dealPrice} onChange={(event) => setSalesForm({ ...salesForm, dealPrice: event.target.value })} placeholder="请输入成交价" /></label>
            <label>操作员<input value={salesForm.operatorId} onChange={(event) => setSalesForm({ ...salesForm, operatorId: event.target.value })} /></label>
            <label>客户<input value={salesForm.customerName} onChange={(event) => setSalesForm({ ...salesForm, customerName: event.target.value })} /></label>
          </div>
          <button type="submit" disabled={isSaving}>{isSaving ? '提交中' : '创建销售单并同步'}</button>
        </form>
      )
    }

    if (activeModule === 'purchase') {
      return (
        <form className="retail-ops-action-panel" onSubmit={submitPurchaseOrder}>
          <div>
            <span>采购入库</span>
            <strong>批量写入 SN 台账、生成 purchase_inbound 流水和智店通同步任务</strong>
          </div>
          <div className="retail-ops-form-grid">
            <label>SKU<input value={purchaseForm.skuKey} onChange={(event) => setPurchaseForm({ ...purchaseForm, skuKey: event.target.value })} placeholder="新 SKU 或已有 SKU" /></label>
            <label>商品名<input value={purchaseForm.productName} onChange={(event) => setPurchaseForm({ ...purchaseForm, productName: event.target.value })} placeholder="商品名称" /></label>
            <label>PN/MTM<input value={purchaseForm.pnMtm} onChange={(event) => setPurchaseForm({ ...purchaseForm, pnMtm: event.target.value })} /></label>
            <label>成本<input type="number" min="0" value={purchaseForm.costPrice} onChange={(event) => setPurchaseForm({ ...purchaseForm, costPrice: event.target.value })} /></label>
            <label>供应商<input value={purchaseForm.supplierId} onChange={(event) => setPurchaseForm({ ...purchaseForm, supplierId: event.target.value })} /></label>
            <label>操作员<input value={purchaseForm.operatorId} onChange={(event) => setPurchaseForm({ ...purchaseForm, operatorId: event.target.value })} /></label>
          </div>
          <label className="retail-ops-wide-field">SN 清单<textarea value={purchaseForm.serialNumbers} onChange={(event) => setPurchaseForm({ ...purchaseForm, serialNumbers: event.target.value })} placeholder="一行一个 SN，或用空格/逗号分隔" /></label>
          <button type="submit" disabled={isSaving}>{isSaving ? '提交中' : '确认入库并同步'}</button>
        </form>
      )
    }

    if (activeModule === 'serial') {
      return (
        <div className="retail-ops-action-panel">
          <div>
            <span>SN 检索</span>
            <strong>按 SN、SKU、商品名过滤台账；销售和入库会实时改变状态</strong>
          </div>
          <input value={serialSearch} onChange={(event) => setSerialSearch(event.target.value)} placeholder="输入 SN / SKU / 商品名" />
        </div>
      )
    }

    if (activeModule === 'category') {
      return (
        <div className="retail-ops-action-panel">
          <div>
            <span>分类口径</span>
            <strong>智店通原始子类不改名，智慧零售分类只用于展示和导购分析</strong>
          </div>
          <button type="button" onClick={exportCategoryMappings}>导出分类对照 CSV</button>
        </div>
      )
    }

    if (activeModule === 'sync') {
      return (
        <div className="retail-ops-action-panel">
          <div>
            <span>同步队列</span>
            <strong>销售、采购、价签任务都在这里重试；真实智店通回执后再写 success</strong>
          </div>
          <button type="button" onClick={retryFirstSyncTask} disabled={isSaving}>重试第一条待处理任务</button>
        </div>
      )
    }

    if (activeModule === 'priceTag') {
      return (
        <form className="retail-ops-action-panel" onSubmit={submitPriceTagUpdate}>
          <div>
            <span>电子价签任务</span>
            <strong>当前统一发布投影、模板、设备绑定和待同步队列已预接线；云端开通后只切网关状态和设备绑定。</strong>
          </div>
          <div className="retail-ops-form-grid">
            <label>SKU<input value={priceTagForm.skuKey} onChange={(event) => setPriceTagForm({ ...priceTagForm, skuKey: event.target.value })} placeholder="输入 SKU" /></label>
            <label>门店价<input type="number" min="0" value={priceTagForm.storePrice} onChange={(event) => setPriceTagForm({ ...priceTagForm, storePrice: event.target.value })} /></label>
            <label>补贴后价<input type="number" min="0" value={priceTagForm.subsidyPrice} onChange={(event) => setPriceTagForm({ ...priceTagForm, subsidyPrice: event.target.value })} /></label>
            <label>设备 ID<input value={priceTagForm.deviceId} onChange={(event) => setPriceTagForm({ ...priceTagForm, deviceId: event.target.value })} placeholder="可选" /></label>
          </div>
          <button type="submit" disabled={isSaving}>{isSaving ? '提交中' : '生成价签下发任务'}</button>
        </form>
      )
    }

    return (
      <div className="retail-ops-action-panel">
        <div>
          <span>{activeAction}</span>
          <strong>该模块已接入读取和业务承接位，写入接口会按销售、采购、同步、价签优先级继续补齐。</strong>
        </div>
        <button type="button" onClick={() => showMessage(`${activeAction} 当前记录为待细化动作，不会伪造外部系统结果。`)}>记录下一步</button>
      </div>
    )
  }

  function renderModuleBody() {
    if (activeModule === 'pos') {
      const recentSales = coreMovements?.items.filter((item) => item.movement_type === 'sales_outbound').slice(0, 6) ?? []
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{coreSalesOrders?.count ?? tableCounts.sales_order ?? 0}</b>本地销售单</span>
            <span><b>{salesOutboundCount}</b>销售出库流水</span>
            <span><b>{coreInventory?.totals.currentStock ?? 0}</b>库存汇总</span>
            <span><b>{coreInventory?.totals.physicalHoldStock ?? 0}</b>实物仓</span>
            <span><b>{coreInventory?.totals.serialCount ?? 0}</b>在库SN</span>
            <span><b>{coreSyncTasks?.count ?? tableCounts.sync_task ?? 0}</b>待同步/历史任务</span>
          </div>
          {recentSales.map((item) => (
            <div className="retail-ops-data-row" key={item.id}>
              <strong>{item.product_name || item.sku_key}</strong>
              <span>SKU {item.sku_key} · SN {item.serial_number || '未绑定'} · {item.source_category || '智店通子类待补'}</span>
              <em>{item.business_date} · {String(item.note ?? '').includes('本地销售单') ? '收银预占位' : '智店通销售出库'}</em>
              {(() => {
                const orderId = resolvePlaceholderOrderId({
                  sourceRef: item.source_ref,
                  note: item.note,
                })
                return String(item.note ?? '').includes('本地销售单') && orderId ? (
                  <button type="button" onClick={() => deletePlaceholderSalesOrder(orderId)} disabled={isSaving}>删除占位单</button>
                ) : null
              })()}
            </div>
          ))}
          {!recentSales.length && <div className="retail-ops-empty">还没有本地销售单，提交上方表单后会生成 sales_outbound。</div>}
        </div>
      )
    }

    if (activeModule === 'purchase') {
      const recentPurchases = coreMovements?.items.filter((item) => item.movement_type === 'purchase_inbound').slice(0, 6) ?? []
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{purchaseInboundCount}</b>采购入库流水</span>
            <span><b>{tableCounts.purchase_order ?? 0}</b>采购单</span>
            <span><b>{serialItems?.statusCounts.in_stock ?? tableCounts.serial_item ?? 0}</b>在库 SN</span>
          </div>
          {recentPurchases.map((item) => (
            <div className="retail-ops-data-row" key={item.id}>
              <strong>{item.product_name || item.sku_key}</strong>
              <span>SKU {item.sku_key} · SN {item.serial_number || '批量入库'} · {item.note || '入库来源待补'}</span>
              <em>{item.business_date} · {item.source_system}</em>
            </div>
          ))}
        </div>
      )
    }

    if (activeModule === 'serial') {
      const query = serialSearch.trim().toLowerCase()
      const filteredItems = (serialItems?.items ?? []).filter((item) => !query || [item.serial_number, item.sku_key, item.product_name, item.status].join(' ').toLowerCase().includes(query))
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{tableCounts.serial_item ?? 0}</b>SN 台账</span>
            <span><b>{serialItems?.statusCounts.in_stock ?? 0}</b>在库</span>
            <span><b>{serialItems?.statusCounts.sold ?? 0}</b>已售</span>
          </div>
          {filteredItems.slice(0, 12).map((item) => (
            <div className="retail-ops-data-row" key={item.serial_number}>
              <strong>{item.serial_number}</strong>
              <span>{item.product_name} · SKU {item.sku_key} · {item.location_code}</span>
              <em>{item.inbound_date || '入库时间待补'} · {item.status}</em>
            </div>
          ))}
          {!filteredItems.length && <div className="retail-ops-empty">没有匹配的 SN。可以先用采购入库创建新 SN。</div>}
        </div>
      )
    }

    if (activeModule === 'category') {
      const zhidiantongMappings = categoryTree?.skuMappings.slice(0, 10) ?? []
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{categoryTree?.summary.zhidiantongCategoryCount ?? 0}</b>智店通子类</span>
            <span><b>{categoryTree?.summary.smartRetailCategoryCount ?? 0}</b>展示分类</span>
            <span><b>{categoryTree?.summary.jdSubcategoryCount ?? 0}</b>导购子类</span>
          </div>
          {zhidiantongMappings.map((item) => (
            <div className="retail-ops-data-row" key={item.sku_key}>
              <strong>{item.sku_key}</strong>
              <span>智店通：{item.zhidiantong_category || '未分类'} · 展示：{item.smart_retail_category}</span>
              <em>{item.catalog_source} / {item.jd_subcategory}</em>
            </div>
          ))}
        </div>
      )
    }

    if (activeModule === 'stocktake') {
      const rows = coreMovements?.items.filter((item) => item.movement_type === 'transfer_outbound' || item.movement_type === 'stock_adjustment').slice(0, 8) ?? []
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{transferOutboundCount}</b>非零售出库</span>
            <span><b>{coreMovements?.typeCounts.stock_adjustment ?? 0}</b>盘点调整</span>
            <span><b>{coreMovements?.count ?? 0}</b>全部流水</span>
          </div>
          {rows.map((item) => (
            <div className="retail-ops-data-row" key={item.id}>
              <strong>{item.product_name || item.sku_key}</strong>
              <span>SKU {item.sku_key} · SN {item.serial_number || '未绑定'} · 数量 {item.quantity}</span>
              <em>{item.business_date} · {item.note || item.source_system}</em>
            </div>
          ))}
        </div>
      )
    }

    if (activeModule === 'sync') {
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{coreSyncTasks?.count ?? 0}</b>同步任务</span>
            <span><b>{(coreSyncTasks?.items ?? []).filter((item) => item.status === 'pending').length}</b>待处理</span>
            <span><b>{(coreSyncTasks?.items ?? []).filter((item) => item.status === 'dead_letter').length}</b>死信</span>
          </div>
          {(coreSyncTasks?.items ?? []).slice(0, 10).map((item) => (
            <div className="retail-ops-data-row with-action" key={item.id}>
              <strong>{item.task_type}</strong>
              <span>{item.external_system_id} · {item.entity_type} · {item.entity_id}</span>
              <em>{item.status} · 重试 {item.retry_count}</em>
              <button type="button" onClick={() => retryTask(item.id)} disabled={isSaving}>重试</button>
            </div>
          ))}
          {!coreSyncTasks?.items.length && <div className="retail-ops-empty">当前没有待同步任务，销售/入库/价签提交后会自动生成。</div>}
        </div>
      )
    }

    if (activeModule === 'reconcile') {
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{tableCounts.inventory_movement ?? 0}</b>本地流水</span>
            <span><b>{categoryTree?.summary.zhidiantongCategoryCount ?? 0}</b>智店通子类对齐</span>
            <span><b>{serialItems?.statusCounts.in_stock ?? 0}</b>SN 可对账</span>
          </div>
          <div className="retail-ops-empty">当前支持本地事实对账底座；真实智店通回执接入后生成差异复核单。</div>
        </div>
      )
    }

    if (activeModule === 'priceTag') {
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{priceTagStatus?.counts.pendingTaskCount ?? tableCounts.price_tag_update_task ?? 0}</b>待下发</span>
            <span><b>{priceTagStatus?.counts.bindingCount ?? tableCounts.price_tag_binding ?? 0}</b>SKU 绑定</span>
            <span><b>{priceTagStatus?.counts.deviceCount ?? tableCounts.price_tag_device ?? 0}</b>价签设备</span>
          </div>
          <div className="retail-ops-data-row">
            <strong>网关状态</strong>
            <span>{priceTagStatus?.gateway.name ?? '电子价签网关'} · {priceTagStatus?.gateway.status ?? 'planned'}</span>
            <em>{priceTagStatus?.cloudReadiness ?? 'pending_gateway_activation'}</em>
          </div>
          {(priceTagStatus?.bindings ?? []).slice(0, 6).map((item) => (
            <div className="retail-ops-data-row" key={item.id}>
              <strong>{item.sku_key}</strong>
              <span>{item.device_id} · {item.vendor || '未标厂商'} {item.model || ''}</span>
              <em>{item.status} · 门店 {item.store_code}</em>
            </div>
          ))}
          {!priceTagStatus?.bindings?.length && <div className="retail-ops-empty">当前还没有价签设备绑定；但任务已经按统一发布投影自动生成完整价签载荷，后续只需开通云网关并补设备绑定。</div>}
        </div>
      )
    }

    if (activeModule === 'staff') {
      return (
        <div className="retail-ops-data-list">
          <div className="retail-ops-mini-stats">
            <span><b>{tableCounts.staff ?? 0}</b>员工</span>
            <span><b>manager / sales</b>角色种子</span>
            <span><b>待映射</b>智店通员工 ID</span>
          </div>
          <div className="retail-ops-empty">员工权限暂不伪造外部账号；销售/入库接口已记录 operatorId，后续映射智店通员工 ID。</div>
        </div>
      )
    }

    return (
      <div className="retail-ops-data-list">
        <div className="retail-ops-mini-stats">
          <span><b>{salesOutboundCount}</b>销售出库</span>
          <span><b>{purchaseInboundCount}</b>采购入库</span>
          <span><b>{transferOutboundCount}</b>非零售出库</span>
        </div>
        <div className="retail-ops-empty">报表回测读取本地业务中台和智慧零售派生快照；目前先保证业务事实可写入。</div>
      </div>
    )
  }

  return (
    <Panel
      title="进销存销售端工作台"
      icon={<Warehouse size={18} />}
      className="retail-ops-panel"
      action={<span className="retail-ops-stage">可操作原型</span>}
    >
      <section className="retail-ops-hero" aria-label="进销存销售端总览">
        <div className="retail-ops-copy">
          <span>本地业务事实源</span>
          <strong>收银销售、采购入库、SN 台账、智店通同步、电子价签执行统一在这里编排</strong>
          <em>智慧零售网页端负责展示、回测和管理；进销存销售端负责真实业务录入、同步和对账。</em>
        </div>
        <div className="retail-ops-state-grid">
          <div>
            <Database size={17} />
            <span>核心库</span>
            <strong>{tableCounts.sku ?? 0} SKU / {tableCounts.serial_item ?? 0} SN</strong>
          </div>
          <div>
            <Smartphone size={17} />
            <span>销售端</span>
            <strong>{tableCounts.inventory_movement ?? 0} 流水</strong>
          </div>
          <div>
            <BadgeCheck size={17} />
            <span>同步策略</span>
            <strong>{categoryTree?.summary.zhidiantongCategoryCount ?? 0} 子类对齐</strong>
          </div>
        </div>
      </section>

      <div className="retail-ops-layout">
        <nav className="retail-ops-module-nav" aria-label="进销存模块">
          {retailOpsModules.map((module) => (
            <button
              type="button"
              className={module.key === activeModule ? 'active' : ''}
              key={module.key}
              onClick={() => handleModuleChange(module.key)}
            >
              <span className="retail-ops-module-icon">{module.icon}</span>
              <span>
                <strong>{module.title}</strong>
                <em>{module.status}</em>
              </span>
            </button>
          ))}
        </nav>

        <section className="retail-ops-detail" aria-label={`${selectedModule.title}功能骨架`}>
          <div className="retail-ops-detail-head">
            <div>
              <span>{selectedModule.status}</span>
              <strong>{selectedModule.title}</strong>
              <em>{selectedModule.subtitle}</em>
            </div>
            <b>{selectedModule.primaryMetric}</b>
          </div>

          <div className="retail-ops-function-grid">
            {selectedModule.actions.map((action) => (
              <button type="button" className={activeAction === action ? 'active' : ''} key={action} onClick={() => handleActionClick(action)}>
                {action}
              </button>
            ))}
          </div>

          {operationMessage && <div className="retail-ops-action-message">{operationMessage}</div>}

          {renderActionPanel()}

          <div className="retail-ops-module-note">
            <span>{selectedModule.secondaryMetric}</span>
            <strong>{selectedModule.nextDetail}</strong>
          </div>

          {renderModuleBody()}

          <div className="retail-ops-flow">
            {retailOpsTimeline.map((item) => (
              <div className={`retail-ops-flow-step ${item.state}`} key={item.label}>
                <span>{item.label}</span>
                <strong>{item.detail}</strong>
              </div>
            ))}
          </div>
        </section>
      </div>
    </Panel>
  )
}

type AndroidPosProduct = {
  skuKey: string
  productName: string
  displayTitle?: string
  pnMtm?: string
  spec?: string
  category?: string
  stock: number
  physicalHoldStock?: number
  availableSerials: RetailCoreSerialItem[]
  price?: number
  basePrice?: number
  subsidyPrice?: number
  adjustedPreSubsidyPrice?: number
  finalPrice?: number
  marketingPoAmount?: number
  educationDiscountAmount?: number
  storeManualPromotionAmount?: number
  storeManualPromotion?: {
    mode?: string | null
    value?: number | null
  } | null
  activitySummary?: string
  approval?: RetailZoneDecision['approval']
}

type AndroidPosCartLine = {
  lineId: string
  skuKey: string
  productName: string
  displayTitle?: string
  serialNumber: string
  quantity: number
  unitPrice: number
  category?: string
}

type AndroidPosPayment = 'cash' | 'wechat' | 'alipay' | 'card' | 'jd'

const androidPosPaymentOptions: Array<{ key: AndroidPosPayment; label: string; detail: string }> = [
  { key: 'wechat', label: '微信', detail: '扫码收款' },
  { key: 'alipay', label: '支付宝', detail: '扫码收款' },
  { key: 'jd', label: '京东支付', detail: '图片参考口径' },
  { key: 'card', label: '银行卡', detail: '线下刷卡' },
  { key: 'cash', label: '现金', detail: '现金收讫' },
]

type StorePricingView = {
  storeRetailPrice?: number | null
  adjustedPreSubsidyPrice?: number | null
  marketingPoAmount?: number | null
  educationDiscountAmount?: number | null
  storeManualPromotionAmount?: number | null
  storeManualPromotion?: {
    mode?: string | null
    value?: number | null
  } | null
}

function hasActiveStoreManualPromotion(pricing?: StorePricingView | null) {
  if (!pricing) return false
  const manualAmount = Number(pricing.storeManualPromotionAmount ?? 0)
  const promotion = pricing.storeManualPromotion
  if (manualAmount > 0) return true
  if (!promotion) return false
  const mode = String(promotion.mode ?? '').trim()
  const value = Number(promotion.value ?? 0)
  return Boolean(mode === 'fixed_price' && value > 0)
}

function getUnifiedStoreDisplayPrice(pricing?: StorePricingView | null) {
  if (!pricing) return undefined
  const basePrice = Number(pricing.storeRetailPrice ?? 0)
  const adjustedPrice = Number(pricing.adjustedPreSubsidyPrice ?? 0)
  if (hasActiveStoreManualPromotion(pricing) && adjustedPrice > 0) return adjustedPrice
  return basePrice > 0 ? basePrice : adjustedPrice || undefined
}

function getStoreExecutionFormula(pricing?: StorePricingView | null) {
  if (!pricing) return undefined
  const basePrice = Number(pricing.storeRetailPrice ?? 0)
  const adjustedPrice = Number(pricing.adjustedPreSubsidyPrice ?? 0)
  const marketingPoAmount = Number(pricing.marketingPoAmount ?? 0)
  const educationDiscountAmount = Number(pricing.educationDiscountAmount ?? 0)
  const promotion = pricing.storeManualPromotion
  const manualAmount = Number(pricing.storeManualPromotionAmount ?? 0)
  if (basePrice <= 0 || adjustedPrice <= 0) return undefined
  const formulaParts = [`原门店挂牌价 ${formatPrice(basePrice)}`]
  if (promotion?.mode === 'fixed_price' && Number(promotion.value ?? 0) > 0) {
    formulaParts.push(`店面活动价 ${formatPrice(Number(promotion.value))}`)
    if (marketingPoAmount > 0) formulaParts.push(`营销PO ${formatPrice(marketingPoAmount)}`)
    if (educationDiscountAmount > 0) formulaParts.push(`教育补 ${formatPrice(educationDiscountAmount)}`)
  } else {
    if (marketingPoAmount > 0) formulaParts.push(`营销PO ${formatPrice(marketingPoAmount)}`)
    if (educationDiscountAmount > 0) formulaParts.push(`教育补 ${formatPrice(educationDiscountAmount)}`)
    if (manualAmount > 0) formulaParts.push(`店面活动 ${formatPrice(manualAmount)}`)
  }
  if (formulaParts.length <= 1 && Math.abs(basePrice - adjustedPrice) < 0.01) return undefined
  return `活动后国补前执行价 ${formatPrice(adjustedPrice)} = ${formulaParts.join(' - ')}`
}

function AndroidPosTerminal() {
  const [publishedProjection, setPublishedProjection] = useState<PublishedProductProjectionSnapshot | null>(null)
  const [serialItems, setSerialItems] = useState<RetailCoreSerialItems | null>(null)
  const [liveInventorySnapshot, setLiveInventorySnapshot] = useState<StandardInventorySnapshot | null>(null)
  const [syncTasks, setSyncTasks] = useState<RetailCoreSyncTasks | null>(null)
  const [query, setQuery] = useState('')
  const [categoryFilter, setCategoryFilter] = useState('全部')
  const [cart, setCart] = useState<AndroidPosCartLine[]>([])
  const [selectedPayment, setSelectedPayment] = useState<AndroidPosPayment>('wechat')
  const [customerName, setCustomerName] = useState('散客')
  const [operatorId, setOperatorId] = useState('EMP001')
  const [message, setMessage] = useState('安卓收银端已接入统一发布投影、SQL SN 库和同步任务队列。')
  const [syncMetricMessage, setSyncMetricMessage] = useState('正在读取 SQL 实时商品、SN 和同步状态...')
  const [isRefreshingBundle, setIsRefreshingBundle] = useState(false)
  const [offlineBundleUpdatedAt, setOfflineBundleUpdatedAt] = useState<string>('')
  const [lotteryOpen, setLotteryOpen] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)

  useEffect(() => {
    if (typeof window === 'undefined') return
    try {
      const saved = window.localStorage.getItem(androidPosOfflineBundleKey)
      if (!saved) return
      const payload = JSON.parse(saved) as { updatedAt?: string }
      setOfflineBundleUpdatedAt(String(payload.updatedAt ?? ''))
    } catch {
      setOfflineBundleUpdatedAt('')
    }
  }, [])

  useEffect(() => {
    let active = true
    const refresh = (background = false) => {
      if (!background) {
        setSyncMetricMessage(navigator.onLine ? '正在读取 SQL 实时商品、SN 和同步状态...' : '当前离线，正在读取本机最后一次更新数据...')
      }
      Promise.all([
        getPublishedProductProjectionSnapshot(),
        getRetailCoreSerialItems(5000),
        getLiveInventorySnapshot({ compact: false }),
        getRetailCoreSyncTasks(),
      ]).then(([projection, serials, inventory, tasks]) => {
        if (!active) return
        setPublishedProjection(projection)
        setSerialItems(serials)
        setLiveInventorySnapshot(inventory)
        setSyncTasks(tasks)
        const updatedLabel = offlineBundleUpdatedAt ? ` · 本机离线包 ${formatDateTime(offlineBundleUpdatedAt)}` : ''
        setSyncMetricMessage(
          projection && serials && inventory && tasks
            ? `SQL 实时链在线 · 已同步 ${projection.itemCount} 个商品 · 库存 ${inventory.totals.currentStock} 台 · 实物仓 ${inventory.totals.physicalHoldStock ?? 0} 台 · SN ${inventory.totals.serialCount}${updatedLabel}`
            : `SQL 主链未完整返回，当前显示可能是本机最后一次更新数据${updatedLabel}`,
        )
      })
    }
    refresh()
    const timer = window.setInterval(() => refresh(true), cockpitRefreshIntervalMs)
    return () => {
      active = false
      window.clearInterval(timer)
    }
  }, [offlineBundleUpdatedAt])

  const products = useMemo<AndroidPosProduct[]>(() => {
    const serialsBySku = new Map<string, RetailCoreSerialItem[]>()
    for (const item of serialItems?.items ?? []) {
      if (item.status !== 'in_stock') continue
      const list = serialsBySku.get(item.sku_key) ?? []
      list.push(item)
      serialsBySku.set(item.sku_key, list)
    }
    const inventorySkuByKey = new Map((liveInventorySnapshot?.skus ?? []).map((item) => [item.skuKey, item] as const))
    const projectionItems = publishedProjection?.items ?? []
    const projectionProducts = projectionItems.map((item) => {
      const inventorySku = inventorySkuByKey.get(item.skuKey)
      const inventorySerials: RetailCoreSerialItem[] = (inventorySku?.serials ?? []).map((serial) => ({
        serial_number: serial.serialNumber,
        sku_key: item.skuKey,
        product_name: serial.productName || item.displayTitle || item.productName || item.skuKey,
        pn_mtm: serial.pnMtm,
        spec: serial.spec,
        status: 'in_stock',
        warehouse_code: serial.warehouseCode || (serial.isPhysicalHold ? 'PO_HOLD' : 'STORE'),
        location_code: serial.locationName || '',
        cost_amount: serial.purchaseCost,
        inbound_date: serial.inboundDate,
        inbound_document_no: serial.inboundDocumentNumber,
        operator_name: serial.inboundOperatorName,
        supplier_name: serial.supplierName,
        warranty_status: 'unknown',
        updated_at: '',
      }))
      const unifiedStorePrice = getUnifiedStoreDisplayPrice({
        storeRetailPrice: item.pricing?.storeRetailPrice,
        adjustedPreSubsidyPrice: item.pricing?.adjustedPreSubsidyPrice,
        storeManualPromotionAmount: item.pricing?.storeManualPromotionAmount,
        storeManualPromotion: item.storeManualPromotion,
      })
      const activitySummary = [
        item.marketingPoActivity?.amount ? `PO ${formatPrice(item.marketingPoActivity.amount, '')}` : '',
        item.educationActivity?.amount ? `教育补 ${formatPrice(item.educationActivity.amount, '')}` : '',
        item.storeManualPromotion?.value ? `店活 ${formatPrice(item.storeManualPromotion.value, '')}` : '',
      ].filter(Boolean).join(' · ')
      return {
        skuKey: item.skuKey,
        productName: item.displayTitle || item.productName || item.skuKey,
        displayTitle: item.displayTitle || item.productName || item.skuKey,
        pnMtm: item.pnMtm,
        spec: item.spec,
        category: item.category,
        stock: inventorySku?.currentStock ?? item.sellableStock ?? item.currentStock ?? 0,
        physicalHoldStock: Number(inventorySku?.physicalHoldStock ?? item.physicalHoldStock ?? 0),
        availableSerials: inventorySerials.length ? inventorySerials : (serialsBySku.get(item.skuKey) ?? []),
        price: unifiedStorePrice,
        basePrice: item.pricing?.storeRetailPrice,
        subsidyPrice: item.pricing?.nationalSubsidyPrice,
        adjustedPreSubsidyPrice: item.pricing?.adjustedPreSubsidyPrice,
        finalPrice: item.pricing?.finalPrice,
        marketingPoAmount: item.pricing?.marketingPoAmount ?? item.marketingPoActivity?.amount,
        educationDiscountAmount: item.pricing?.educationDiscountAmount ?? item.educationActivity?.amount,
        storeManualPromotionAmount: item.pricing?.storeManualPromotionAmount ?? item.storeManualPromotion?.value,
        storeManualPromotion: item.storeManualPromotion,
        activitySummary,
      }
    })
    const decisionSkuSet = new Set(projectionProducts.map((item) => item.skuKey))
    const serialOnlyProducts = Array.from(new Set([
      ...serialsBySku.keys(),
      ...(liveInventorySnapshot?.skus ?? []).map((item) => item.skuKey),
    ]))
      .filter((skuKey) => !decisionSkuSet.has(skuKey))
      .map((skuKey) => {
        const inventorySku = inventorySkuByKey.get(skuKey)
        const availableSerials = inventorySku?.serials?.length
          ? inventorySku.serials.map((serial) => ({
              serial_number: serial.serialNumber,
              sku_key: skuKey,
              product_name: serial.productName || inventorySku.productName || skuKey,
              pn_mtm: serial.pnMtm,
              spec: serial.spec,
              status: 'in_stock',
              warehouse_code: serial.warehouseCode || (serial.isPhysicalHold ? 'PO_HOLD' : 'STORE'),
              location_code: serial.locationName || '',
              cost_amount: serial.purchaseCost,
              inbound_date: serial.inboundDate,
              inbound_document_no: serial.inboundDocumentNumber,
              operator_name: serial.inboundOperatorName,
              supplier_name: serial.supplierName,
              warranty_status: 'unknown',
              updated_at: '',
            }))
          : (serialsBySku.get(skuKey) ?? [])
        const first = availableSerials[0]
        return {
          skuKey,
          productName: inventorySku?.productName || first?.product_name || skuKey,
          pnMtm: inventorySku?.pnMtm || first?.pn_mtm,
          spec: inventorySku?.spec || first?.spec,
          category: '未映射价区',
          stock: inventorySku?.currentStock ?? availableSerials.length,
          physicalHoldStock: Number(inventorySku?.physicalHoldStock ?? availableSerials.filter((serial) => serial.warehouse_code === 'PO_HOLD').length),
          availableSerials,
          price: first?.cost_amount ? Math.round(first.cost_amount * 1.08) : undefined,
          approval: '店长审批' as const,
        }
      })
    return [...projectionProducts, ...serialOnlyProducts]
      .filter((item) => item.stock > 0 || item.availableSerials.length > 0)
      .sort((a, b) => (b.availableSerials.length || b.stock) - (a.availableSerials.length || a.stock))
  }, [liveInventorySnapshot, publishedProjection, serialItems])

  const categories = useMemo(() => {
    const names = Array.from(new Set(products.map((item) => item.category || '未分类'))).filter(Boolean)
    return ['全部', ...names.slice(0, 12)]
  }, [products])

  const filteredProducts = useMemo(() => {
    const lowered = query.trim().toLowerCase()
    return products.filter((item) => {
      const categoryMatched = categoryFilter === '全部' || (item.category || '未分类') === categoryFilter
      if (!categoryMatched) return false
      if (!lowered) return true
      return [item.skuKey, item.productName, item.pnMtm, item.spec, item.category]
        .join(' ')
        .toLowerCase()
        .includes(lowered)
    }).slice(0, 36)
  }, [categoryFilter, products, query])

  const cartTotal = cart.reduce((sum, item) => sum + item.unitPrice * item.quantity, 0)
  const pendingSyncCount = (syncTasks?.items ?? []).filter((item) => item.status === 'pending').length

  async function refreshOfflineBundle() {
    if (isRefreshingBundle) return
    setIsRefreshingBundle(true)
    setSyncMetricMessage('正在下载正式收银页离线包并固化本机缓存...')
    try {
      const requests = [
        ...androidPosOfflineApiPaths.map((path) => fetch(path, { cache: 'no-store' })),
        ...androidPosOfflineAssets.map((path) => fetch(path, { cache: 'reload' })),
      ]
      const responses = await Promise.allSettled(requests)
      const successCount = responses.filter((item) => item.status === 'fulfilled' && item.value.ok).length
      const updatedAt = new Date().toISOString()
      if (typeof window !== 'undefined') {
        window.localStorage.setItem(androidPosOfflineBundleKey, JSON.stringify({
          updatedAt,
          successCount,
          totalCount: requests.length,
        }))
      }
      setOfflineBundleUpdatedAt(updatedAt)
      setSyncMetricMessage(`正式收银页离线包已更新 ${successCount}/${requests.length} 项 · ${formatDateTime(updatedAt)}`)
    } catch {
      setSyncMetricMessage('正式收银页离线包更新失败，请确认 API、广告机页和本机网络是否正常。')
    } finally {
      setIsRefreshingBundle(false)
    }
  }

  function exitPosApp() {
    if (typeof document !== 'undefined' && document.fullscreenElement && document.exitFullscreen) {
      void document.exitFullscreen().catch(() => undefined)
    }
    window.setTimeout(() => {
      window.close()
      window.setTimeout(() => {
        if (!window.closed) window.location.replace('about:blank')
      }, 180)
    }, 80)
  }

  function addProduct(product: AndroidPosProduct) {
    const usedSerials = new Set(cart.map((item) => item.serialNumber))
    const serial = product.availableSerials.find((item) => !usedSerials.has(item.serial_number))
    if (!serial) {
      setMessage('该 SKU 当前没有可用在库 SN，不能加入购物车。')
      return
    }
    const unitPrice = product.finalPrice ?? product.price ?? product.subsidyPrice ?? 0
    if (unitPrice <= 0) {
      setMessage('该 SKU 缺少可用门店价，请先在智慧零售价格区补价。')
      return
    }
    setCart((items) => [
      ...items,
      {
        lineId: `${product.skuKey}-${serial.serial_number}`,
        skuKey: product.skuKey,
        productName: product.productName,
        displayTitle: product.displayTitle || product.productName,
        serialNumber: serial.serial_number,
        quantity: 1,
        unitPrice,
        category: product.category,
      },
    ])
    setMessage(`已加入：${product.productName} / SN ${serial.serial_number}`)
  }

  function removeCartLine(lineId: string) {
    setCart((items) => items.filter((item) => item.lineId !== lineId))
  }

  function adjustLinePrice(lineId: string, nextPrice: string) {
    const value = Number(nextPrice)
    setCart((items) => items.map((item) => item.lineId === lineId ? { ...item, unitPrice: Number.isFinite(value) ? value : item.unitPrice } : item))
  }

  async function submitOrder() {
    if (!cart.length) {
      setMessage('购物车为空，不能结算。')
      return
    }
    if (cart.some((item) => !item.serialNumber)) {
      setMessage('每个销售行必须绑定 SN。')
      return
    }
    setIsSubmitting(true)
    const result = await createRetailSalesOrder({
      storeCode: 'D0186124',
      operatorId: operatorId.trim() || 'EMP001',
      customerName: customerName.trim() || '散客',
      note: `安卓收银端创建；支付方式=${selectedPayment}`,
      lines: cart.map((item) => ({
        skuKey: item.skuKey,
        quantity: item.quantity,
        serialNumbers: [item.serialNumber],
        dealPrice: item.unitPrice,
      })),
    })
    setIsSubmitting(false)
    if (!result) {
      setMessage('结算失败：请确认后端服务已启动、SN 仍在库且未重复出库。')
      return
    }
    setMessage(`销售单 ${result.orderId} 已生成，同步任务 ${result.pendingSyncTaskId} 已入队。`)
    setCart([])
    const [serials, tasks] = await Promise.all([getRetailCoreSerialItems(5000), getRetailCoreSyncTasks()])
    setSerialItems(serials)
    setSyncTasks(tasks)
  }

  return (
    <main className="android-pos-shell">
      <section className="android-pos-side">
        <div className="android-pos-brand">
          <span>Lenovo</span>
          <strong>智慧收银</strong>
          <em>{currentStoreName}</em>
        </div>
        <nav className="android-pos-nav" aria-label="收银模块">
          <button type="button" className="active"><ShoppingCart size={18} /> 收银台</button>
          <button type="button"><ScanLine size={18} /> 扫码/SN</button>
          <button type="button"><ReceiptText size={18} /> 订单</button>
          <button type="button"><Tags size={18} /> 价签</button>
          <button type="button" onClick={() => setLotteryOpen(true)}><Users size={18} /> 抽奖</button>
          <button type="button" onClick={refreshOfflineBundle}><RefreshCw size={18} /> 更新</button>
          <button type="button" onClick={exitPosApp}><Wifi size={18} /> 退出</button>
        </nav>
        <div className="android-pos-status">
          <span>本地库存</span>
          <strong>{liveInventorySnapshot?.totals.serialCount ?? serialItems?.statusCounts.in_stock ?? 0} 台可售 SN</strong>
          <em>{pendingSyncCount} 条待同步 · {offlineBundleUpdatedAt ? `离线包 ${formatDateTime(offlineBundleUpdatedAt)}` : '离线包未更新'}</em>
        </div>
      </section>

      <section className="android-pos-catalog">
        <div className="android-pos-topbar">
          <div>
            <span>ANDROID POS</span>
            <strong>门店收银销售端</strong>
          </div>
          <div className="android-pos-top-actions">
            <button type="button" className="android-pos-secondary-action" onClick={() => setLotteryOpen(true)}>抽奖</button>
            <button type="button" className="android-pos-secondary-action" onClick={refreshOfflineBundle} disabled={isRefreshingBundle}>{isRefreshingBundle ? '更新中' : '更新'}</button>
            <button type="button" className="android-pos-secondary-action danger" onClick={exitPosApp}>退出</button>
            <a href="/" target="_blank" rel="noreferrer">返回驾驶舱</a>
          </div>
        </div>

        <div className="android-pos-sync-banner">
          <RefreshCw size={16} />
          <span>{syncMetricMessage}</span>
        </div>

        <div className="android-pos-search">
          <Search size={18} />
          <input
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            placeholder="扫码枪输入 SKU / SN / 商品名，或手动搜索"
            autoFocus
          />
        </div>

        <div className="android-pos-category-tabs">
          {categories.map((item) => (
            <button type="button" className={item === categoryFilter ? 'active' : ''} key={item} onClick={() => setCategoryFilter(item)}>
              {item}
            </button>
          ))}
        </div>

        <div className="android-pos-product-grid">
          {filteredProducts.map((item) => (
            <button type="button" className="android-pos-product-card" key={item.skuKey} onClick={() => addProduct(item)}>
              {(() => {
                const baseStorePrice = item.basePrice
                const displayStorePrice = item.price
                const hasManualDelta = Boolean(
                  baseStorePrice
                  && displayStorePrice
                  && Math.abs(baseStorePrice - displayStorePrice) >= 0.01
                )
                const executionFormula = getStoreExecutionFormula({
                  storeRetailPrice: item.basePrice,
                  adjustedPreSubsidyPrice: item.adjustedPreSubsidyPrice ?? item.price,
                  marketingPoAmount: item.marketingPoAmount,
                  educationDiscountAmount: item.educationDiscountAmount,
                  storeManualPromotionAmount: item.storeManualPromotionAmount,
                  storeManualPromotion: item.storeManualPromotion,
                })
                return (
                  <>
              <span>{item.category || '未分类'}</span>
              <strong>{item.displayTitle || item.productName}</strong>
              <em>{item.pnMtm || item.skuKey}</em>
              <div>
                <b>{formatPrice(item.finalPrice ?? item.price ?? item.subsidyPrice, '待补价')}</b>
                <small>
                  {item.price ? `活动后国补前执行价 ${formatPrice(item.price, '')}` : '执行价待补'}
                  {hasManualDelta ? ` · 原门店挂牌价 ${formatPrice(baseStorePrice, '')}` : ''}
                  {' · '}
                  {item.availableSerials.length || item.stock} 台可售
                  {item.physicalHoldStock ? ` · 实物仓 ${item.physicalHoldStock}` : ''}
                </small>
                {executionFormula ? <small>{executionFormula}</small> : null}
                {item.activitySummary ? <small>{item.activitySummary}</small> : <small>{item.approval || '统一发布投影口径'}</small>}
              </div>
                  </>
                )
              })()}
            </button>
          ))}
          {!filteredProducts.length && <div className="android-pos-empty">没有匹配商品。先确认库存/SN 和价格快照是否已同步。</div>}
        </div>
      </section>

      <aside className="android-pos-cart">
        <div className="android-pos-cart-head">
          <div>
            <span>购物车</span>
            <strong>{cart.length} 件商品</strong>
          </div>
          <button type="button" onClick={() => setCart([])} disabled={!cart.length}>清空</button>
        </div>

        <div className="android-pos-cart-list">
          {cart.map((item) => (
            <div className="android-pos-cart-line" key={item.lineId}>
              <div>
                <strong>{item.displayTitle || item.productName}</strong>
                <span>SKU {item.skuKey}</span>
                <em>SN {item.serialNumber}</em>
              </div>
              <div className="android-pos-price-editor">
                <button type="button" onClick={() => adjustLinePrice(item.lineId, String(Math.max(0, item.unitPrice - 100)))}><Minus size={15} /></button>
                <input value={item.unitPrice} inputMode="decimal" onChange={(event) => adjustLinePrice(item.lineId, event.target.value)} />
                <button type="button" onClick={() => adjustLinePrice(item.lineId, String(item.unitPrice + 100))}><Plus size={15} /></button>
                <button type="button" className="danger" onClick={() => removeCartLine(item.lineId)}><Trash2 size={15} /></button>
              </div>
            </div>
          ))}
          {!cart.length && <div className="android-pos-empty">从左侧商品卡点击加入购物车；每行自动锁定一个在库 SN。</div>}
        </div>

        <div className="android-pos-customer">
          <label>客户<input value={customerName} onChange={(event) => setCustomerName(event.target.value)} /></label>
          <label>员工<input value={operatorId} onChange={(event) => setOperatorId(event.target.value)} /></label>
        </div>

        <div className="android-pos-payments">
          {androidPosPaymentOptions.map((item) => (
            <button type="button" className={item.key === selectedPayment ? 'active' : ''} key={item.key} onClick={() => setSelectedPayment(item.key)}>
              <CreditCard size={16} />
              <span>{item.label}</span>
              <em>{item.detail}</em>
            </button>
          ))}
        </div>

        <div className="android-pos-total">
          <span>应收合计</span>
          <strong>{formatPrecisePrice(cartTotal, '￥0.00')}</strong>
          <em>{message}</em>
        </div>

        <button type="button" className="android-pos-checkout" onClick={submitOrder} disabled={isSubmitting || !cart.length}>
          {isSubmitting ? '正在落账...' : '确认收款并生成销售单'}
        </button>

        {lotteryOpen && (
          <div className="android-pos-overlay" role="dialog" aria-modal="true">
            <div className="android-pos-overlay-card">
              <div className="android-pos-overlay-head">
                <div>
                  <span>购机抽奖</span>
                  <strong>收银台现场抽奖页</strong>
                </div>
                <button type="button" className="android-pos-secondary-action" onClick={() => setLotteryOpen(false)}>关闭</button>
              </div>
              <iframe
                className="android-pos-overlay-frame"
                title="购机抽奖"
                src={`/ad-machine/lottery.html?posTerminal=1&embed=1&av=${androidPosServiceWorkerVersion}`}
              />
            </div>
          </div>
        )}
      </aside>
    </main>
  )
}

function getOpenClawStatusLabel(status: OpenClawReceipt['status']) {
  const labels: Record<OpenClawReceipt['status'], string> = {
    completed: '已完成',
    completed_with_warnings: '完成有警告',
    blocked_missing_input: '缺原始输入',
    blocked_page_risk: '页面/风控阻塞',
    executed_not_closed: '执行未收口',
    failed: '失败',
  }
  return labels[status] ?? status
}

function getOpenClawStatusTone(status: OpenClawReceipt['status']) {
  if (status === 'completed') return 'good'
  if (status === 'completed_with_warnings' || status === 'executed_not_closed' || status === 'blocked_missing_input') return 'warn'
  return 'danger'
}

function getOpenClawCommandStatusLabel(status: OpenClawCommand['status']) {
  const labels: Record<OpenClawCommand['status'], string> = {
    drafted: '已起草',
    queued: '已排队',
    steered: '已下发',
    acknowledged: '已确认',
    executing: '执行中',
    completed: '已完成',
    blocked: '已阻塞',
    cancelled: '已取消',
  }
  return labels[status] ?? status
}

function getOpenClawCommandStatusTone(status: OpenClawCommand['status']) {
  if (status === 'completed') return 'good'
  if (status === 'blocked' || status === 'cancelled') return 'danger'
  return 'warn'
}

