  const beginBackgroundRefresh = () => {
    backgroundRefreshCountRef.current += 1
    setIsBackgroundRefreshing(true)
  }

  const finishBackgroundRefresh = () => {
    backgroundRefreshCountRef.current = Math.max(0, backgroundRefreshCountRef.current - 1)
    if (backgroundRefreshCountRef.current === 0) {
      setIsBackgroundRefreshing(false)
      setLastDataRefreshAt(new Date().toISOString())
    }
  }

  const refreshProductLibraryList = (mounted = true) => {
    if (activeBookmark !== 'productLibrary') return
    getProductLibraryOverview().then((data) => {
      if (mounted) setProductLibraryOverview(data)
    })
    getProductLibraryCategories().then((data) => {
      if (mounted) setProductLibraryCategories(data?.items ?? [])
    })
    getProductLibraryProductsByCategory(5000, '', '').then((data) => {
      if (mounted) setProductLibraryBaselineProducts(data?.items ?? [])
    })
    getProductLibraryProductsByCategory(120, productLibrarySearch, selectedProductLibraryCategory).then((data) => {
      if (!mounted) return
      const items = data?.items ?? []
      setProductLibraryProducts(items)
      setSelectedProductLibraryId((current) => {
        if (current && items.some((item) => item.id === current)) return current
        return items[0]?.id ?? null
      })
    })
  }

