  useEffect(() => {
    if ((activeBookmark !== 'adminCenter' && activeBookmark !== 'system') || activeAdminModule !== 'physicalHold') return
    let mounted = true
    setPhysicalHoldModuleLoading(true)
    setPhysicalHoldModuleError('')
    const abortController = new AbortController()
    // 修复：candidates 和 holds 独立 set state，任一成功都立即更新对应字段。
    // 错误信息也按子项独立显示，避免"全空"误报。
    const handleResult = (label: string, result: PromiseSettledResult<unknown>) => {
      if (!mounted) return
      if (result.status === 'rejected') {
        const reason = result.reason as { name?: string; message?: string } | null
        if (reason?.name === 'AbortError') return  // lifecycle abort 忽略
        setPhysicalHoldModuleError(`${label}: ${reason?.message || String(reason || '未知错误')}`)
        return
      }
      const data = result.value
      if (label === '物理 hold 表' && data) setPhysicalStockHolds(data as any)
      if (label === '销售单候选' && data) setPhysicalHoldSalesOrderCandidates(data as any)
    }
    const holdsPromise = getRetailCorePhysicalStockHolds(5000, 'all', abortController.signal)
      .then((data) => ({ status: 'fulfilled' as const, value: data }))
      .catch((reason) => ({ status: 'rejected' as const, reason }))
    const candidatesPromise = getRetailCorePhysicalHoldSalesOrderCandidates(5000, '', 'all', abortController.signal)
      .then((data) => ({ status: 'fulfilled' as const, value: data }))
      .catch((reason) => ({ status: 'rejected' as const, reason }))
    Promise.all([holdsPromise, candidatesPromise]).then(([holdsResult, candidatesResult]) => {
      handleResult('物理 hold 表', holdsResult)
      handleResult('销售单候选', candidatesResult)
      if (mounted) setPhysicalHoldModuleLoading(false)
    })
    return () => {
      mounted = false
      abortController.abort()
    }
  }, [activeBookmark, activeAdminModule])

