  function persistManualPriceOverrides(nextOverrides: ManualPriceOverrides) {
    setManualPriceOverrides(nextOverrides)
    try {
      window.localStorage.setItem(manualPriceOverridesKey, JSON.stringify(nextOverrides))
    } catch (error) {
      console.warn('保存手动校准价格失败', error)
    }
    const syncSeq = manualOverrideSyncSeq.current + 1
    manualOverrideSyncSeq.current = syncSeq
    saveManualPriceOverridesSnapshot(nextOverrides).then((data) => {
      if (syncSeq !== manualOverrideSyncSeq.current) return
      if (!data) {
        console.warn('系统级同步手动校准价格失败，已保留本地即时值')
        return
      }
      setManualPriceOverrides(data.overrides)
      if (data.retailZone) setRetailZone(data.retailZone)
      try {
        window.localStorage.setItem(manualPriceOverridesKey, JSON.stringify(data.overrides))
      } catch (error) {
        console.warn('缓存系统级校准价格失败', error)
      }
    })
  }

  function persistStoreManualPromotions(nextItems: StoreManualPromotion[], successMessage: string) {
    const previousItems = storeManualPromotions
    setStoreManualPromotions(nextItems)
    writeStoredStoreManualPromotions(nextItems)
    setStoreManualPromotionStatusMessage('店面手动活动保存中...')
    const syncSeq = storeManualPromotionSyncSeq.current + 1
    storeManualPromotionSyncSeq.current = syncSeq
    saveStoreManualPromotionsSnapshot(nextItems).then((data) => {
      if (syncSeq !== storeManualPromotionSyncSeq.current) return
      if (!data) {
        setStoreManualPromotions(previousItems)
        writeStoredStoreManualPromotions(previousItems)
        setStoreManualPromotionStatusMessage('店面手动活动保存失败，已回滚到上一次 SQL 结果')
        console.warn('SQL 同步店面手动满减活动库失败，已保留本地即时值')
        return
      }
      const resolved = data.items ?? []
      setStoreManualPromotions(resolved)
      writeStoredStoreManualPromotions(resolved)
      setStoreManualPromotionStatusMessage(successMessage)
    })
  }

  function persistManufacturerManualPromotions(nextItems: ManufacturerManualPromotion[]) {
    setManufacturerManualPromotions(nextItems)
    writeStoredManufacturerManualPromotions(nextItems)
    const syncSeq = manufacturerManualPromotionSyncSeq.current + 1
    manufacturerManualPromotionSyncSeq.current = syncSeq
    saveManufacturerManualPromotionsSnapshot(nextItems).then((data) => {
      if (syncSeq !== manufacturerManualPromotionSyncSeq.current) return
      if (!data) {
        console.warn('SQL 同步厂家产品营销库失败，已保留本地即时值')
        return
      }
      const resolved = data.items ?? []
      setManufacturerManualPromotions(resolved)
      writeStoredManufacturerManualPromotions(resolved)
    })
  }

