  function extendStoreManualPromotion(id: string, extraDays = 7) {
    const next = storeManualPromotions.map((item) => (
      item.id === id
        ? {
          ...item,
          validTo: addDaysToDateString(item.validTo, extraDays),
          updatedAt: new Date().toISOString(),
        }
        : item
    ))
    persistStoreManualPromotions(next, `已延长店面活动 ${extraDays} 天`)
  }

  function handleSaveStoreManualPromotion(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    const value = Number(storeManualPromotionDraft.value)
    if (!storeManualPromotionDraft.skuKey) {
      setStoreManualPromotionStatusMessage('请先选择库存 SKU 再保存店面活动')
      return
    }
    if (!Number.isFinite(value) || value < 0) {
      setStoreManualPromotionStatusMessage(storeManualPromotionDraft.mode === 'fixed_price' ? '请填写有效的门店活动价' : '请填写有效的满减金额')
      return
    }
    if (!storeManualPromotionDraft.validFrom || !storeManualPromotionDraft.validTo) {
      setStoreManualPromotionStatusMessage('请填写完整的生效日期和失效日期')
      return
    }
    if (storeManualPromotionDraft.validFrom > storeManualPromotionDraft.validTo) {
      setStoreManualPromotionStatusMessage('失效日期不能早于生效日期')
      return
    }
    if (storeManualPromotionDraftOverlaps.length) {
      const confirmed = window.confirm(`当前 SKU 已有 ${storeManualPromotionDraftOverlaps.length} 条时间重叠活动，继续保存会并行存在。确认继续吗？`)
      if (!confirmed) return
    }
    const liveSku = liveSkuByKey.get(storeManualPromotionDraft.skuKey)
    const decision = retailDecisionBySkuKey.get(storeManualPromotionDraft.skuKey)
    const item: StoreManualPromotion = {
      id: editingStoreManualPromotionId || `smp-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      skuKey: storeManualPromotionDraft.skuKey,
      productName: liveSku?.productName ?? decision?.productName,
      pnMtm: liveSku?.pnMtm ?? decision?.pnMtm,
      category: liveSku?.category ?? decision?.category,
      mode: storeManualPromotionDraft.mode,
      value,
      validFrom: storeManualPromotionDraft.validFrom,
      validTo: storeManualPromotionDraft.validTo,
      note: storeManualPromotionDraft.note.trim(),
      enabled: true,
      updatedAt: new Date().toISOString(),
    }
    const nextItems = editingStoreManualPromotionId
      ? storeManualPromotions.map((current) => current.id === editingStoreManualPromotionId ? item : current)
      : [item, ...storeManualPromotions]
    persistStoreManualPromotions(nextItems, editingStoreManualPromotionId ? '店面手动活动已保存到 SQL' : '店面手动活动已新增到 SQL')
    resetStoreManualPromotionDraft()
  }

  function toggleStoreManualPromotion(id: string, enabled: boolean) {
    const next = storeManualPromotions.map((item) => (
      item.id === id ? { ...item, enabled, updatedAt: new Date().toISOString() } : item
    ))
    persistStoreManualPromotions(next, enabled ? '店面手动活动已重新启用' : '店面手动活动已停用')
  }

  function removeStoreManualPromotion(id: string) {
    if (!window.confirm('确认删除这条店面手动活动？删除后会同步到 SQL，所有终端都会消失。')) return
    const next = storeManualPromotions.filter((item) => item.id !== id)
    persistStoreManualPromotions(next, '店面手动活动已从 SQL 删除')
    if (editingStoreManualPromotionId === id) resetStoreManualPromotionDraft()
  }

