  function saveManualPriceOverride(skuKey: string, field: ManualPriceField, rawValue: string) {
    const normalizedValue = rawValue.trim()
    const nextPrice = normalizedValue ? Number(normalizedValue) : undefined
    if (nextPrice !== undefined && (!Number.isFinite(nextPrice) || nextPrice < 0)) return

    const nextOverrides = { ...manualPriceOverrides }
    const currentOverride = nextOverrides[skuKey] ?? { updatedAt: new Date().toISOString() }
    const nextOverride: ManualPriceOverride = {
      ...currentOverride,
      updatedAt: new Date().toISOString(),
    }

    if (nextPrice === undefined) {
      delete nextOverride[field]
    } else {
      nextOverride[field] = nextPrice
    }

    if (
      nextOverride.realtimePurchasePrice === undefined
      && nextOverride.marketWholesalePrice === undefined
      && nextOverride.retailPreSubsidyPrice === undefined
      && nextOverride.defensivePostSubsidyPrice === undefined
    ) {
      delete nextOverrides[skuKey]
    } else {
      nextOverrides[skuKey] = nextOverride
    }
    persistManualPriceOverrides(nextOverrides)
  }

  function clearManualPriceOverride(skuKey: string) {
    const nextOverrides = { ...manualPriceOverrides }
    delete nextOverrides[skuKey]
    persistManualPriceOverrides(nextOverrides)
  }

  function persistInventoryAdjustments(nextAdjustments: InventoryAdjustments) {
    setInventoryAdjustments(nextAdjustments)
    const syncSeq = inventoryAdjustmentSyncSeq.current + 1
    inventoryAdjustmentSyncSeq.current = syncSeq
    saveInventoryAdjustmentsSnapshot(nextAdjustments).then((data) => {
      if (syncSeq !== inventoryAdjustmentSyncSeq.current) return
      if (!data) {
        console.warn('系统级同步库存校准失败，页面已保留本地即时值')
        return
      }
      setInventoryAdjustments(data.adjustments)
      if (data.inventory) setLiveInventory(data.inventory)
      if (data.retailZone) setRetailZone(data.retailZone)
    })
  }

