  async function rebuildAfterProductLibraryMutation(
    mutationLabel: string,
    options?: {
      refreshDetail?: boolean
      productId?: string
      scope?: 'detail' | 'pricing' | 'full'
    },
  ) {
    const scope = options?.scope ?? 'full'
    if (scope === 'detail') {
      await Promise.all([
        options?.refreshDetail === false ? Promise.resolve() : refreshProductLibraryDetail(options?.productId ?? selectedProductLibraryId ?? undefined),
        refreshRetailLinkedViews(),
      ])
      setProductLibraryStatusMessage(`${mutationLabel}已保存，并已自动刷新详情`)
      return
    }
    const result = await rebuildProductLibraryLinkedViews(scope === 'pricing' ? 'pricing' : 'full')
    if (!result?.ok) {
      setProductLibraryStatusMessage(`${mutationLabel}已保存，但前端快照自动重建失败`)
      return
    }
    await Promise.all([
      options?.refreshDetail === false ? Promise.resolve() : refreshProductLibraryDetail(options?.productId ?? selectedProductLibraryId ?? undefined),
      refreshRetailLinkedViews(),
    ])
    const [report, failureQueue] = await Promise.all([
      getLocalSyncLatestReport(),
      getLocalSyncFailureQueue(),
    ])
    if (report) setLocalSyncLatestReport(report)
    if (failureQueue) setLocalSyncFailureQueue(failureQueue as Record<string, unknown>)
    setProductLibraryStatusMessage(`${mutationLabel}已保存，并已自动联动前端快照`)
  }

