  function saveInventoryAdjustment(skuKey: string, field: InventoryAdjustmentField | 'note', rawValue: string) {
    const currentAdjustment = inventoryAdjustments[skuKey] ?? { updatedAt: new Date().toISOString() }
    const nextAdjustment: InventoryAdjustment = {
      ...currentAdjustment,
      updatedAt: new Date().toISOString(),
    }

    if (field === 'note') {
      const note = rawValue.trim()
      if (note) {
        nextAdjustment.note = note
      } else {
        delete nextAdjustment.note
      }
    } else {
      const normalizedValue = rawValue.trim()
      const nextValue = normalizedValue ? Number(normalizedValue) : undefined
      if (nextValue !== undefined && (!Number.isFinite(nextValue) || nextValue < 0)) return
      if (nextValue === undefined) {
        delete nextAdjustment[field]
      } else {
        nextAdjustment[field] = Math.round(nextValue)
      }
    }

    const nextAdjustments = { ...inventoryAdjustments }
    if (
      nextAdjustment.currentStock === undefined
      && nextAdjustment.sellableStock === undefined
      && nextAdjustment.unsellableStock === undefined
      && nextAdjustment.pendingInboundStock === undefined
      && !nextAdjustment.note
    ) {
      delete nextAdjustments[skuKey]
    } else {
      nextAdjustments[skuKey] = nextAdjustment
    }
    persistInventoryAdjustments(nextAdjustments)
  }

  function clearInventoryAdjustment(skuKey: string) {
    const nextAdjustments = { ...inventoryAdjustments }
    delete nextAdjustments[skuKey]
    persistInventoryAdjustments(nextAdjustments)
  }

  function isDateWithinRange(dateValue: string, dateFrom: string, dateTo: string) {
    const normalizedDate = formatDateInputValue(dateValue)
    if (!normalizedDate) return !dateFrom && !dateTo
    if (dateFrom && normalizedDate < dateFrom) return false
    if (dateTo && normalizedDate > dateTo) return false
    return true
  }

