  function applyLocalPhysicalHoldTransferResult(orderNumber: string, transferredSerials: string[]) {
    const normalizedOrderNumber = orderNumber.trim()
    const transferredSerialSet = new Set(transferredSerials.map((item) => item.trim()).filter(Boolean))
    if (!normalizedOrderNumber || !transferredSerialSet.size) return
    setPhysicalHoldSalesOrderCandidates((current) => {
      if (!current) return current
      let changed = false
      const nextItems = current.items.map((item) => {
        if (item.orderNumber !== normalizedOrderNumber) return item
        const matchedEligibleSerials = item.eligibleSerialNumbers.filter((serialNumber) => transferredSerialSet.has(serialNumber))
        if (!matchedEligibleSerials.length) return item
        changed = true
        const nextEligibleSerialNumbers = item.eligibleSerialNumbers.filter((serialNumber) => !transferredSerialSet.has(serialNumber))
        const nextTransferredSerialCount = item.serialCount - nextEligibleSerialNumbers.length
        const nextActiveHoldCount = item.activeHoldCount + matchedEligibleSerials.length
        const nextTransferStatus = nextTransferredSerialCount >= item.serialCount
          ? 'transferred'
          : nextTransferredSerialCount > 0
            ? 'partial'
            : 'untransferred'
        const nextTransferStatusLabel = nextTransferStatus === 'transferred'
          ? '已全部转仓'
          : nextTransferStatus === 'partial'
            ? '部分已转仓'
            : '未转仓'
        return {
          ...item,
          eligibleSerialNumbers: nextEligibleSerialNumbers,
          transferredSerialCount: nextTransferredSerialCount,
          eligibleTransferCount: nextEligibleSerialNumbers.length,
          activeHoldCount: nextActiveHoldCount,
          transferStatus: nextTransferStatus,
          transferStatusLabel: nextTransferStatusLabel,
        }
      })
      if (!changed) return current
      const nextSummary: Record<string, number> = {
        all: 0,
        untransferred: 0,
        partial: 0,
        transferred: 0,
        active: 0,
        consumed: 0,
        released: 0,
        revoked: 0,
      }
      nextItems.forEach((item) => {
        nextSummary.all += 1
        nextSummary[item.transferStatus] = (nextSummary[item.transferStatus] ?? 0) + 1
        nextSummary.active += item.activeHoldCount > 0 ? 1 : 0
        nextSummary.consumed += item.consumedHoldCount > 0 ? 1 : 0
        nextSummary.released += item.releasedHoldCount > 0 ? 1 : 0
        nextSummary.revoked += (item.revokedHoldCount ?? 0) > 0 ? 1 : 0
      })
      return {
        ...current,
        generatedAt: new Date().toISOString(),
        summary: nextSummary,
        items: nextItems,
      }
    })
  }

  async function handleExecutePhysicalHoldBatchAction(input: {
    action: PhysicalHoldBatchAction
    orderNumber?: string
    orderNumbers?: string[]
    serialNumbers?: string[]
    serviceOrderNo?: string
    note?: string
  }) {
    const action = input.action
    const orderNumber = String(input.orderNumber ?? '').trim()
    const orderNumbers = Array.from(new Set((input.orderNumbers ?? []).map((item) => String(item ?? '').trim()).filter(Boolean)))
    const serialNumbers = Array.from(new Set((input.serialNumbers ?? []).map((item) => item.trim()).filter(Boolean)))
    const serviceOrderNo = String(input.serviceOrderNo ?? '').trim()
    const note = String(input.note ?? '').trim()

    try {
      if (action === 'transfer') {
        const transferOrderNumbers = orderNumbers.length ? orderNumbers : (orderNumber ? [orderNumber] : [])
        if (!transferOrderNumbers.length) {
          setPhysicalHoldActionMessage('转仓需要先勾选至少 1 张销售单。')
          return
        }
        setPhysicalHoldActionMessage(`实物仓入仓处理中...（${transferOrderNumbers.length} 单）`)
        let totalTransferredCount = 0
        for (const currentOrderNumber of transferOrderNumbers) {
          const result = await transferRetailCorePhysicalStockHold({
            orderNumber: currentOrderNumber,
            serialNumbers: transferOrderNumbers.length === 1 ? serialNumbers : [],
            note,
            operatorName: 'codex-ui',
          })
          const transferredCount = Number((result as Record<string, unknown> | null)?.transferredCount ?? 0)
          const transferredSerials = Array.isArray((result as Record<string, unknown> | null)?.transferredSerials)
            ? ((result as Record<string, unknown>).transferredSerials as unknown[]).map((item) => String(item ?? '').trim()).filter(Boolean)
            : []
          totalTransferredCount += transferredCount
          applyLocalPhysicalHoldTransferResult(currentOrderNumber, transferredSerials)
        }
        setPhysicalHoldCandidateStatus('all')
        setPhysicalHoldActionMessage(`已转入实物仓 ${totalTransferredCount} 个 SN（${transferOrderNumbers.length} 单）`)
      } else if (action === 'finalize') {
        if (!serialNumbers.length || !serviceOrderNo) {
          setPhysicalHoldActionMessage('同步出库需要勾选 SN，并填写智惠服务单号。')
          return
        }
        setPhysicalHoldActionMessage('智惠服务二次出库核销处理中...')
        const result = await finalizeRetailCorePhysicalStockHold({
          serialNumbers,
          serviceOrderNo,
          note,
          operatorName: 'codex-ui',
        })
        const finalizedCount = Number((result as Record<string, unknown> | null)?.finalizedCount ?? 0)
        setPhysicalHoldActionMessage(`已完成二次出库 ${finalizedCount} 个 SN`)
      } else if (action === 'release') {
        if (!serialNumbers.length) {
          setPhysicalHoldActionMessage('库存退出需要先勾选 SN。')
          return
        }
        setPhysicalHoldActionMessage('转回门店处理中...')
        const result = await releaseRetailCorePhysicalStockHold({
          serialNumbers,
          note,
          operatorName: 'codex-ui',
        })
        const releasedCount = Number((result as Record<string, unknown> | null)?.releasedCount ?? 0)
        setPhysicalHoldActionMessage(`已转回门店 ${releasedCount} 个 SN`)
      } else if (action === 'revoke') {
        if (!serialNumbers.length) {
          setPhysicalHoldActionMessage('撤销误转仓需要先勾选 SN。')
          return
        }
        setPhysicalHoldActionMessage('撤销误转仓处理中...')
        const result = await revokeRetailCorePhysicalStockHold({
          serialNumbers,
          note,
          operatorName: 'codex-ui',
        })
        const revokedCount = Number((result as Record<string, unknown> | null)?.revokedCount ?? 0)
        setPhysicalHoldActionMessage(`已撤销误转仓 ${revokedCount} 个 SN`)
      } else if (action === 'reopen') {
        if (!serialNumbers.length) {
          setPhysicalHoldActionMessage('撤销误核销需要先勾选 SN。')
          return
        }
        setPhysicalHoldActionMessage('撤销误核销处理中...')
        const result = await reopenRetailCorePhysicalStockHold({
          serialNumbers,
          note,
          operatorName: 'codex-ui',
        })
        const reopenedCount = Number((result as Record<string, unknown> | null)?.reopenedCount ?? 0)
        setPhysicalHoldActionMessage(`已撤销误核销 ${reopenedCount} 个 SN`)
      } else if (action === 'rebind') {
        if (!serialNumbers.length || !serviceOrderNo) {
          setPhysicalHoldActionMessage('重绑服务单需要勾选 SN，并填写智惠服务单号。')
          return
        }
        setPhysicalHoldActionMessage('重绑智惠服务单处理中...')
        const result = await rebindRetailCorePhysicalStockHold({
          serialNumbers,
          serviceOrderNo,
          note,
          operatorName: 'codex-ui',
        })
        const finalizedCount = Number((result as Record<string, unknown> | null)?.finalizedCount ?? 0)
        setPhysicalHoldActionMessage(`已重绑并重新核销 ${finalizedCount} 个 SN`)
      }

      setPhysicalHoldActionMessage('库存台账自动同步中...')
      await ensureInventoryMasterSync({
        trigger: 'physical_hold_ui_action',
        operator: 'codex-ui',
        source: action,
        force: true,
        waitForCompletion: true,
        minIntervalSeconds: 0,
        maxWaitSeconds: 45,
      })

      await Promise.all([
        refreshPhysicalStockHoldSnapshot(),
        getLiveInventorySnapshot({ compact: false }).then((inventory) => { if (inventory) setLiveInventory(inventory) }),
        getInventoryMasterSnapshot().then((snapshot) => setInventoryMasterSnapshot(snapshot)),
      ])
      setSelectedPhysicalHoldOrderNumbers([])
      setSelectedPhysicalHoldSerialNumbers([])
      setPhysicalHoldBatchDraft((current) => ({ ...current, serviceOrderNo: '', note: '' }))
    } catch (error) {
      setPhysicalHoldActionMessage(`${action} 失败：${error instanceof Error ? error.message : String(error)}`)
    }
  }

  const inStockSkus = useMemo(() => (liveInventory?.skus ?? []).filter((row) => getDisplayTotalStock(row) > 0), [liveInventory])
  const liveSkuByKey = useMemo(() => new Map((liveInventory?.skus ?? []).map((item) => [item.skuKey, item])), [liveInventory])
  const liveSkuByPn = useMemo(() => new Map(
    (liveInventory?.skus ?? [])
      .filter((item) => normalizeLookupKey(item.pnMtm))
      .map((item) => [normalizeLookupKey(item.pnMtm), item]),
  ), [liveInventory])
  const inStockSkuKeys = useMemo(() => new Set(inStockSkus.map((item) => item.skuKey)), [inStockSkus])
  const publishedProjectionBySkuKey = useMemo(() => new Map(
    (publishedProjection?.items ?? []).map((item) => [item.skuKey, item] as const),
  ), [publishedProjection])
  const productLibraryByPn = useMemo(() => new Map(
    productLibraryBaselineProducts
      .filter((item) => normalizeLookupKey(item.pn_mtm))
      .map((item) => [normalizeLookupKey(item.pn_mtm), item]),
  ), [productLibraryBaselineProducts])
  const productLibrarySearchIndex = useMemo(() => (
    productLibraryBaselineProducts.map((item) => ({
      item,
      text: buildProductLibraryLookupText(item),
    }))
  ), [productLibraryBaselineProducts])
  const resolveProductLibraryMatch = (productText: string, pnMtm?: string) => {
    const pnKey = normalizeLookupKey(pnMtm)
    if (pnKey) {
      const direct = productLibraryByPn.get(pnKey)
      if (direct) return direct
    }
    const strictCandidates = productLibrarySearchIndex
      .filter((entry) => isStrictUniqueProductMatch(productText, entry.item))
      .map((entry) => ({
        item: entry.item,
        text: entry.text,
        score: getFingerprintScore(productText, entry.text),
      }))
      .filter((entry) => entry.score >= 0.62 || hasStrongProductConfigMatch(productText, entry.text))
      .sort((left, right) => right.score - left.score)

    if (strictCandidates.length !== 1) return undefined
    return strictCandidates[0]?.item
  }
  const grayWholesaleMaterialRows = useMemo(() => (
    (grayWholesale?.quotes ?? []).map((quote) => {
      const matchedProduct = resolveProductLibraryMatch(quote.productText)
      const matchedSkuKey = matchedProduct?.primary_sku_key
      const pnKey = normalizeLookupKey(matchedProduct?.pn_mtm)
      const inventoryRow = matchedSkuKey
        ? liveSkuByKey.get(matchedSkuKey)
        : pnKey
          ? liveSkuByPn.get(pnKey)
          : undefined
      return {
        quote,
        matchedProduct,
        matchedSkuKey,
        pnMtm: matchedProduct?.pn_mtm,
        inventoryRow,
      }
    })
  ), [grayWholesale, productLibrarySearchIndex, productLibraryByPn, liveSkuByKey, liveSkuByPn])
  const grayWholesalePriceBySkuKey = useMemo(() => {
    const priceBuckets = new Map<string, Set<number>>()
    for (const item of grayWholesaleMaterialRows) {
      const skuKey = item.inventoryRow?.skuKey ?? item.matchedSkuKey
      const wholesalePrice = getGrayWholesaleBasis(item.quote)
      if (!skuKey || !item.inventoryRow?.currentStock) continue
      if (!wholesalePrice) continue
      if (!isPlausibleMatchedPrice(item.inventoryRow, wholesalePrice)) continue
      const bucket = priceBuckets.get(skuKey) ?? new Set<number>()
      bucket.add(wholesalePrice)
      priceBuckets.set(skuKey, bucket)
    }
    const map = new Map<string, number>()
    for (const [skuKey, prices] of priceBuckets.entries()) {
      if (prices.size !== 1) continue
      const [onlyPrice] = Array.from(prices)
      map.set(skuKey, onlyPrice)
    }
    return map
  }, [grayWholesaleMaterialRows])
  const grayWholesalePriceByPn = useMemo(() => {
    const priceBuckets = new Map<string, Set<number>>()
    for (const item of grayWholesaleMaterialRows) {
      const pnKey = normalizeLookupKey(item.pnMtm)
      const wholesalePrice = getGrayWholesaleBasis(item.quote)
      if (!pnKey || !item.inventoryRow?.currentStock) continue
      if (!wholesalePrice) continue
      if (!isPlausibleMatchedPrice(item.inventoryRow, wholesalePrice)) continue
      const bucket = priceBuckets.get(pnKey) ?? new Set<number>()
      bucket.add(wholesalePrice)
      priceBuckets.set(pnKey, bucket)
    }
    const map = new Map<string, number>()
    for (const [pnKey, prices] of priceBuckets.entries()) {
      if (prices.size !== 1) continue
      const [onlyPrice] = Array.from(prices)
      map.set(pnKey, onlyPrice)
    }
    return map
  }, [grayWholesaleMaterialRows])

  const inventoryPriceSignalBySkuKey = useMemo(() => {
    const map = new Map<string, InventoryPriceSignalSnapshot['items'][number]>()
    for (const item of inventoryPriceSignals?.items ?? []) {
      if (!item?.skuKey) continue
      map.set(item.skuKey, item)
    }
    return map
  }, [inventoryPriceSignals])

  const inventoryPriceSignalByPn = useMemo(() => {
    const map = new Map<string, InventoryPriceSignalSnapshot['items'][number]>()
    for (const item of inventoryPriceSignals?.items ?? []) {
      const pnKey = normalizeLookupKey(item?.pnMtm)
      if (!pnKey) continue
      map.set(pnKey, item)
    }
    return map
  }, [inventoryPriceSignals])

  function getInventoryPriceSignal(row: StandardInventorySku) {
    const bySku = inventoryPriceSignalBySkuKey.get(row.skuKey)
    if (bySku) return bySku
    const pnKey = normalizeLookupKey(row.pnMtm)
    return pnKey ? inventoryPriceSignalByPn.get(pnKey) : undefined
  }

  function getEffectiveRealtimePurchasePrice(row: StandardInventorySku) {
    return manualPriceOverrides[row.skuKey]?.realtimePurchasePrice
      ?? getInventoryPriceSignal(row)?.realtimePurchasePrice
      ?? findRealtimePurchasePrice(row, distributorQuotes)
  }

  function getEffectiveMarketWholesalePrice(row: StandardInventorySku) {
    const pnKey = normalizeLookupKey(row.pnMtm)
    return manualPriceOverrides[row.skuKey]?.marketWholesalePrice
      ?? getInventoryPriceSignal(row)?.grayWholesalePrice
      ?? grayWholesalePriceBySkuKey.get(row.skuKey)
      ?? (pnKey ? grayWholesalePriceByPn.get(pnKey) : undefined)
  }

  function getRetailPreSubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    return manualPriceOverrides[row.skuKey]?.retailPreSubsidyPrice ?? row.recommendedPreSubsidyPrice
  }

  function getPlatformSubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    return minDefinedNumber([
      getGeneratedJdSubsidyPrice(row),
      getGeneratedLenovoSubsidyPrice(row),
      row.platformSubsidyPrice,
      row.jdPostSubsidyPrice,
      row.lenovoOfficialPostSubsidyPrice,
    ])
  }

  function getRegularSubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    const publishedFinalPrice = publishedProjectionBySkuKey.get(row.skuKey)?.pricing?.finalPrice
    if (publishedFinalPrice) return publishedFinalPrice
    const retailPreSubsidyPrice = getStoreAdjustedPreSubsidyPrice(row)
    return retailPreSubsidyPrice
      ? calculateFullServiceSubsidyPriceForProduct(retailPreSubsidyPrice, row)
      : row.fullServiceSubsidyPrice ?? row.regularChannelSubsidyPrice
  }

  function getEffectiveGrayWholesalePriceForDecision(row: RetailZoneSnapshot['decisions']['items'][number]) {
    const liveSku = liveSkuByKey.get(row.skuKey)
    return liveSku ? getEffectiveMarketWholesalePrice(liveSku) ?? row.grayWholesalePrice : row.grayWholesalePrice
  }

  function getEffectiveGrayRetailPreSubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    const grayWholesalePrice = getEffectiveGrayWholesalePriceForDecision(row)
    return getGraySuggestedRetailPrice(grayWholesalePrice, row)
  }

  function getEffectiveGraySubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    return getGraySuggestedSubsidyPrice(getEffectiveGrayRetailPreSubsidyPrice(row), row)
  }

  function getDefensiveSubsidyPrice(row: RetailZoneSnapshot['decisions']['items'][number]) {
    const platformSubsidyPrice = getPlatformSubsidyPrice(row)
    const fullServicePrice = getRegularSubsidyPrice(row)
    const platformDefensivePreSubsidyPrice = minDefinedNumber([
      normalizeTo99EndingRetailPrice(row.jdPrice),
      normalizeTo99EndingRetailPrice(row.taobaoPrice),
    ])
    const platformDefensivePrice = platformDefensivePreSubsidyPrice
      ? calculateFullServiceSubsidyPriceForProduct(platformDefensivePreSubsidyPrice, row)
      : platformSubsidyPrice
    const grayDefensivePrice = getEffectiveGraySubsidyPrice(row)
    return manualPriceOverrides[row.skuKey]?.defensivePostSubsidyPrice
      ?? minDefinedNumber([platformDefensivePrice, grayDefensivePrice, fullServicePrice])
      ?? row.defensiveLowSubsidyPrice
  }

  const serialFallbackBySku = useMemo(() => {
    const map = new Map<string, {
      serials: StandardInventorySku['serials']
      averageCost?: number
      spec?: string
      pnMtm?: string
      productName?: string
    }>()
    for (const item of warrantySerialItems?.items ?? []) {
      if (item.status !== 'in_stock') continue
      const current = map.get(item.sku_key) ?? {
        serials: [] as StandardInventorySku['serials'],
        averageCost: undefined,
        spec: undefined,
        pnMtm: undefined,
        productName: undefined,
      }
      current.serials.push({
        serialNumber: item.serial_number,
        productName: item.product_name,
        pnMtm: item.pn_mtm,
        spec: item.spec,
        inboundDate: item.inbound_date,
        purchaseCost: item.cost_amount,
        inboundDocumentNumber: item.inbound_document_no,
        inboundOperatorName: item.operator_name,
        supplierName: item.supplier_name,
        locationName: item.location_code,
        isPhysicalHold: item.warehouse_code === 'PO_HOLD' || item.location_code === 'PO_EDU_REAL_STOCK',
      })
      if (!current.productName && item.product_name) current.productName = item.product_name
      if (!current.spec && item.spec) current.spec = item.spec
      if (!current.pnMtm && item.pn_mtm) current.pnMtm = item.pn_mtm
      const costCandidates = current.serials
        .map((serial) => serial.purchaseCost)
        .filter((value): value is number => typeof value === 'number' && value > 0)
      current.averageCost = costCandidates.length
        ? Math.round((costCandidates.reduce((sum, value) => sum + value, 0) / costCandidates.length) * 100) / 100
        : current.averageCost
      map.set(item.sku_key, current)
    }
    return map
  }, [warrantySerialItems])
  const serialPurchaseCostByNumber = useMemo(() => {
    const map = new Map<string, number>()
    for (const item of warrantySerialItems?.items ?? []) {
      const serialNumber = String(item.serial_number ?? '').trim()
      const cost = Number(item.cost_amount)
      if (!serialNumber || !Number.isFinite(cost) || cost <= 0) continue
      map.set(serialNumber, Math.round(cost * 100) / 100)
    }
    return map
  }, [warrantySerialItems])

  const patchedCrossOutboundCheckHistory = useMemo(() => {
    return crossOutboundCheckHistory.map((item) => {
      const serialCosts = Array.isArray(item.serialCosts) && item.serialCosts.length
        ? item.serialCosts.filter((value): value is number => Number.isFinite(value) && value > 0)
        : item.serialNumbers
            .map((serialNumber) => serialPurchaseCostByNumber.get(serialNumber))
            .filter((value): value is number => typeof value === 'number' && Number.isFinite(value) && value > 0)
      const quantity = Math.max(1, Number(item.quantity ?? 1) || 1)
      if (!serialCosts.length) {
        if (item.costSource === 'serialActual') return item
        if (item.costUnitPrice === undefined && item.costTotalAmount === undefined && Array.isArray(item.serialCosts) && item.serialCosts.length === 0) return item
        return {
          ...item,
          serialCosts: [] as number[],
          costUnitPrice: undefined,
          costTotalAmount: undefined,
          costSource: 'unknown' as const,
        }
      }
      const derivedCostTotal = Math.round(serialCosts.reduce((sum, value) => sum + value, 0) * 100) / 100
      const derivedCostUnit = serialCosts.length === 1 ? serialCosts[0] : undefined
      let derivedCrossCheckAmount = Number(item.totalCrossCheckAmount ?? 0)
      if (item.settlementMode === 'priceDiff') {
        if (item.calculationBasis === 'salesPrice') {
          derivedCrossCheckAmount = Math.max(0, Number((((Number(item.salesUnitPrice ?? 0) - Number(item.settlementPrice ?? 0)) * quantity)).toFixed(2)))
        } else {
          derivedCrossCheckAmount = Math.max(0, Number(((derivedCostTotal - Number(item.settlementPrice ?? 0) * quantity)).toFixed(2)))
        }
      } else {
        derivedCrossCheckAmount = Number((Number(item.perUnitAmount ?? 0) * quantity).toFixed(2))
      }
      const needsPatch = (
        item.costSource !== 'serialActual'
        || item.costTotalAmount !== derivedCostTotal
        || item.costUnitPrice !== derivedCostUnit
        || !Array.isArray(item.serialCosts)
        || item.serialCosts.length !== serialCosts.length
        || Number(item.totalCrossCheckAmount ?? 0) !== derivedCrossCheckAmount
      )
      if (!needsPatch) return item
      return {
        ...item,
        serialCosts,
        costUnitPrice: derivedCostUnit,
        costTotalAmount: derivedCostTotal,
        costSource: 'serialActual' as const,
        totalCrossCheckAmount: derivedCrossCheckAmount,
      }
    })
  }, [crossOutboundCheckHistory, serialPurchaseCostByNumber])

  useEffect(() => {
    if (!patchedCrossOutboundCheckHistory.length) return
    const changed = patchedCrossOutboundCheckHistory.some((item, index) => item !== crossOutboundCheckHistory[index])
    if (!changed) return
    setCrossOutboundCheckHistory(patchedCrossOutboundCheckHistory)
  }, [crossOutboundCheckHistory, patchedCrossOutboundCheckHistory])

  const inStockSerialCount = inStockSkus.reduce((sum, item) => sum + item.serialCount, 0)
  const inStockDisplaySellableCount = inStockSkus.reduce((sum, item) => sum + getDisplaySellableStock(item), 0)
  const inStockSkusWithLedgerCategory = useMemo(
    () => inStockSkus.map((row) => {
      const fallback = serialFallbackBySku.get(row.skuKey)
      const fallbackSerials = fallback?.serials ?? []
      const fallbackSerialByNumber = new Map(fallbackSerials.map((serial) => [serial.serialNumber, serial]))
      const mergedSerialByNumber = new Map<string, StandardInventorySku['serials'][number]>()
      for (const serial of row.serials) {
        const fallbackSerial = fallbackSerialByNumber.get(serial.serialNumber)
        mergedSerialByNumber.set(serial.serialNumber, {
          ...serial,
          productName: serial.productName || fallbackSerial?.productName,
          pnMtm: serial.pnMtm || fallbackSerial?.pnMtm,
          spec: serial.spec || fallbackSerial?.spec,
          inboundDate: serial.inboundDate || fallbackSerial?.inboundDate,
          purchaseCost: serial.purchaseCost ?? fallbackSerial?.purchaseCost,
          inboundDocumentNumber: serial.inboundDocumentNumber || fallbackSerial?.inboundDocumentNumber,
          inboundOperatorName: serial.inboundOperatorName || fallbackSerial?.inboundOperatorName,
          supplierName: serial.supplierName || fallbackSerial?.supplierName,
          locationName: serial.locationName || fallbackSerial?.locationName,
          stockAgeDays: serial.stockAgeDays ?? fallbackSerial?.stockAgeDays,
          warrantyStart: serial.warrantyStart || fallbackSerial?.warrantyStart,
          warrantyEnd: serial.warrantyEnd || fallbackSerial?.warrantyEnd,
        })
      }
      for (const fallbackSerial of fallbackSerials) {
        // Physical-hold-only SKUs may have no primary row.serials entry yet. Keep the
        // fallback serial so the ledger's SN count and expandable SN detail stay aligned.
        if (!mergedSerialByNumber.has(fallbackSerial.serialNumber)) {
          mergedSerialByNumber.set(fallbackSerial.serialNumber, fallbackSerial)
        }
      }
      const mergedSerials = Array.from(mergedSerialByNumber.values())
      const mergedSerialCount = mergedSerials.length || row.serialCount
      return {
        ...row,
        pnMtm: row.pnMtm || fallback?.pnMtm,
        spec: row.spec || fallback?.spec,
        salesCostPrice: row.salesCostPrice ?? fallback?.averageCost,
        serials: mergedSerials,
        serialCount: mergedSerialCount,
        ledgerCategory: getInventoryLedgerCategory(row),
      }
    }),
    [inStockSkus, serialFallbackBySku],
  )

  const filteredSkus = useMemo(() => {
    const keyword = skuSearch.trim().toLowerCase()
    return inStockSkusWithLedgerCategory
      .filter((row) => selectedCategory === '全部' || row.ledgerCategory === selectedCategory)
      .filter((row) => {
        if (!keyword) return true
        return [row.productName, row.pnMtm, row.skuCode, row.productCode, row.spec, row.jdSubcategory, row.sourceCategory]
          .filter(Boolean)
          .join(' ')
          .toLowerCase()
          .includes(keyword)
      })
      .sort((a, b) => getDisplayTotalStock(b) - getDisplayTotalStock(a))
  }, [inStockSkusWithLedgerCategory, selectedCategory, skuSearch])
  const inventoryTruthSkuByKey = useMemo(
    () => new Map(inStockSkusWithLedgerCategory.map((item) => [item.skuKey, item] as const)),
    [inStockSkusWithLedgerCategory],
  )

  const activeCategorySummary = useMemo(() => {
    if (!liveInventory) return null
    const rows = selectedCategory === '全部'
      ? inStockSkusWithLedgerCategory
      : inStockSkusWithLedgerCategory.filter((item) => item.ledgerCategory === selectedCategory)
    const summary = rows.reduce((acc, item) => {
      acc.skuCount += 1
      acc.currentStock += getDisplayTotalStock(item)
      acc.sellableStock += getDisplaySellableStock(item)
      acc.unsellableStock += item.unsellableStock
      acc.pendingInboundStock += item.pendingInboundStock
      return acc
    }, {
      skuCount: 0,
      currentStock: 0,
      sellableStock: 0,
      unsellableStock: 0,
      pendingInboundStock: 0,
    })
    if (selectedCategory === '全部') {
      return {
        category: '全部',
        ...summary,
      }
    }
    return { category: selectedCategory, ...summary }
  }, [inStockSkusWithLedgerCategory, liveInventory, selectedCategory])

  const inStockCategorySummaries = useMemo(() => Array.from(inStockSkusWithLedgerCategory.reduce((map, item) => {
    const category = item.ledgerCategory || '未分类'
    const current = map.get(category) ?? {
      category,
      skuCount: 0,
      currentStock: 0,
      sellableStock: 0,
      unsellableStock: 0,
    }
    current.skuCount += 1
    current.currentStock += getDisplayTotalStock(item)
    current.sellableStock += getDisplaySellableStock(item)
    current.unsellableStock += item.unsellableStock
    map.set(category, current)
    return map
  }, new Map<string, {
    category: string
    skuCount: number
    currentStock: number
    sellableStock: number
    unsellableStock: number
  }>()).values()).sort((a, b) => {
    const categoryOrder = compareInventoryCategoryPriority(a.category, b.category)
    if (categoryOrder !== 0) return categoryOrder
    return b.currentStock - a.currentStock || b.sellableStock - a.sellableStock
  }), [inStockSkusWithLedgerCategory])
  const sortedInventoryCategories = useMemo(() => (
    [...inStockCategorySummaries].sort((a, b) => {
      const categoryOrder = compareInventoryCategoryPriority(a.category, b.category)
      if (categoryOrder !== 0) return categoryOrder
      return b.currentStock - a.currentStock || b.sellableStock - a.sellableStock || b.skuCount - a.skuCount
    })
  ), [inStockCategorySummaries])

  useEffect(() => {
    if (!sortedInventoryCategories.length) return
    if (selectedCategory === '全部') return
    const exists = sortedInventoryCategories.some((item) => item.category === selectedCategory)
    if (exists) return
    setSelectedCategory(sortedInventoryCategories[0]?.category ?? '游戏笔记本')
  }, [selectedCategory, sortedInventoryCategories])

  useEffect(() => {
    if (typeof window === 'undefined') return
    try {
      const sales = JSON.parse(window.localStorage.getItem('sales-protection-payment-confirmed-map') || window.localStorage.getItem('sales-protection-payment-confirmed-ids') || '{}')
      const marketing = JSON.parse(window.localStorage.getItem('marketing-protection-payment-confirmed-map') || window.localStorage.getItem('marketing-protection-payment-confirmed-ids') || '{}')
      const marketingAmountOverride = JSON.parse(window.localStorage.getItem('marketing-history-amount-override-map') || '{}')
      const educationAgentScan = JSON.parse(window.localStorage.getItem('education-agent-scan-payment-confirmed-map') || '{}')
      const normalizeLegacy = (value: unknown): Record<string, string> => {
        if (Array.isArray(value)) {
          return Object.fromEntries(
            value
              .filter((item): item is string => typeof item === 'string' && item.trim().length > 0)
              .map((item) => [item, new Date().toISOString()]),
          ) as Record<string, string>
        }
        if (value && typeof value === 'object') {
          return Object.fromEntries(
            Object.entries(value as Record<string, unknown>)
              .filter(([key, confirmedAt]) => key.trim().length > 0 && typeof confirmedAt === 'string' && confirmedAt.trim().length > 0),
          ) as Record<string, string>
        }
        return {}
      }
      setSalesProtectionPaymentConfirmedAtMap(normalizeLegacy(sales))
      setMarketingProtectionPaymentConfirmedAtMap(normalizeLegacy(marketing))
      if (marketingAmountOverride && typeof marketingAmountOverride === 'object') {
        setMarketingHistoryAmountOverrideMap(marketingAmountOverride as Record<string, { boostAmount?: number; educationAmount?: number }>)
      }
      setEducationAgentScanPaymentConfirmedAtMap(normalizeLegacy(educationAgentScan))
    } catch {
      setSalesProtectionPaymentConfirmedAtMap({})
      setMarketingProtectionPaymentConfirmedAtMap({})
      setMarketingHistoryAmountOverrideMap({})
      setEducationAgentScanPaymentConfirmedAtMap({})
    }
  }, [])

  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem('sales-protection-payment-confirmed-map', JSON.stringify(salesProtectionPaymentConfirmedAtMap))
  }, [salesProtectionPaymentConfirmedAtMap])

  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem('marketing-protection-payment-confirmed-map', JSON.stringify(marketingProtectionPaymentConfirmedAtMap))
  }, [marketingProtectionPaymentConfirmedAtMap])
  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem('marketing-history-amount-override-map', JSON.stringify(marketingHistoryAmountOverrideMap))
  }, [marketingHistoryAmountOverrideMap])

  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem('education-agent-scan-payment-confirmed-map', JSON.stringify(educationAgentScanPaymentConfirmedAtMap))
  }, [educationAgentScanPaymentConfirmedAtMap])

  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem(crossOutboundCheckRulesKey, JSON.stringify(crossOutboundCheckRules))
  }, [crossOutboundCheckRules])

  useEffect(() => {
    if (typeof window === 'undefined') return
    window.localStorage.setItem(crossOutboundCheckHistoryKey, JSON.stringify(crossOutboundCheckHistory))
  }, [crossOutboundCheckHistory])

  useEffect(() => {
    if (!crossOutboundCheckApiHydrated) return
    const fingerprint = JSON.stringify({
      rules: crossOutboundCheckRules,
      history: crossOutboundCheckHistory,
    })
    if (crossOutboundCheckSyncFingerprintRef.current === fingerprint) return
    const timer = window.setTimeout(() => {
      Promise.allSettled([
        saveCrossOutboundCheckRulesSnapshot(crossOutboundCheckRules as unknown as Parameters<typeof saveCrossOutboundCheckRulesSnapshot>[0]),
        saveCrossOutboundCheckHistorySnapshot(crossOutboundCheckHistory as unknown as Parameters<typeof saveCrossOutboundCheckHistorySnapshot>[0]),
      ]).then((results) => {
        if (results.some((item) => item.status === 'fulfilled' && item.value)) {
          crossOutboundCheckSyncFingerprintRef.current = fingerprint
        }
      })
    }, 250)
    return () => window.clearTimeout(timer)
  }, [crossOutboundCheckApiHydrated, crossOutboundCheckHistory, crossOutboundCheckRules])

  function confirmSalesProtectionPayment(id: string) {
    setSalesProtectionPaymentConfirmedAtMap((current) => {
      if (current[id]) return current
      return { ...current, [id]: new Date().toISOString() }
    })
  }

  function confirmMarketingProtectionPayment(id: string) {
    setMarketingProtectionPaymentConfirmedAtMap((current) => {
      if (current[id]) return current
      return { ...current, [id]: new Date().toISOString() }
    })
  }

  function confirmEducationAgentScanPayment(id: string) {
    setEducationAgentScanPaymentConfirmedAtMap((current) => {
      if (current[id]) return current
      return { ...current, [id]: new Date().toISOString() }
    })
  }

  function isEducationAgentScanPaid(item: { id: string; paymentReceived?: boolean }) {
    return Boolean(educationAgentScanPaymentConfirmedAtMap[item.id] || item.paymentReceived)
  }

  function canConfirmEducationAgentScanPayment(item: { id: string; status: string; paymentReceived?: boolean }) {
    return item.status !== '待出库同步' && !isEducationAgentScanPaid(item)
  }

  function confirmSelectedEducationAgentScanPayments(ids: string[]) {
    const payableIds = ids.filter((id) => {
      const row = educationAgentAllRows.find((item) => item.id === id)
      return row && canConfirmEducationAgentScanPayment(row)
    })
    if (!payableIds.length) return
    const confirmedAt = new Date().toISOString()
    setEducationAgentScanPaymentConfirmedAtMap((current) => ({
      ...current,
      ...Object.fromEntries(payableIds.map((id) => [id, confirmedAt])),
    }))
  }

  function exportEducationAgentScanRows() {
    const headers = [
      '扫码日期',
      '采集群',
      '采集来源',
      '付款状态',
      '出库匹配状态',
      '出库日期',
      '销售单号',
      '商品名称',
      'SKU',
      'PN-MTM',
      '规格',
      '数量',
      'SN/箱码',
      '单台教育补',
      '教育补合计',
      '单台服务费',
      '服务费合计',
      '门店',
      '经手人',
      '来源文件',
      '备注',
    ]
    const rows = filteredEducationAgentScanRows.map((item) => {
      const paid = isEducationAgentScanPaid(item)
      return [
        item.scanDate,
        item.sourceGroupName || '未标注来源',
        item.collectionSource || item.sourceGroupName || '未标注来源',
        paid ? '已付' : item.status === '待出库同步' ? '待出库后付款' : '未付',
        item.status,
        item.outboundDate || '',
        item.orderNumber || '',
        item.productName,
        item.skuKey,
        item.pnMtm || '',
        item.spec || '',
        item.quantity,
        item.serialNumbers.join(' / '),
        item.educationDiscountAmount,
        item.totalEducationDiscountAmount,
        item.serviceFeePerUnit,
        item.totalServiceFee,
        item.outboundStoreName || currentStoreName,
        item.outboundOperatorName || '',
        item.sourceFile ? shortFileName(item.sourceFile) : '',
        item.ruleText || '',
      ]
    })
    const csv = [headers, ...rows]
      .map((row) => row.map((cell) => escapeCsvValue(cell)).join(','))
      .join('\n')
    const blob = new Blob([`\uFEFF${csv}`], { type: 'text/csv;charset=utf-8;' })
    const url = window.URL.createObjectURL(blob)
    const anchor = document.createElement('a')
    anchor.href = url
    anchor.download = `education-agent-scan-${new Date().toISOString().slice(0, 10)}.csv`
    document.body.append(anchor)
    anchor.click()
    anchor.remove()
    window.URL.revokeObjectURL(url)
  }

  const abnormalSkus = useMemo(() => {
    return inStockSkus
      .filter((row) => row.unsellableStock > 0 || row.pendingInboundStock > 0 || row.currentStock <= 1 || row.currentStock >= 20)
      .sort((a, b) => b.unsellableStock - a.unsellableStock || b.currentStock - a.currentStock)
      .slice(0, 8)
  }, [inStockSkus])
  const priceProtectionCards = useMemo(() => {
    if (!priceProtection) return []
    if (priceProtection.quoteDate !== getBeijingTodayDateString()) return []
    return priceProtection.candidates
      .filter((item) => item.matchMethod === 'pn_mtm')
      .filter((item) => (
        item.inventoryAverageCost > 0
        && item.realtimePurchasePrice > 0
        && item.inventoryAverageCost > item.realtimePurchasePrice
        && item.unitDiff > 0
        && item.estimatedProtectionAmount > 0
      ))
      .map((item) => {
      const sku = liveSkuByKey.get(item.skuKey)
      const inboundDates = (sku?.serials ?? [])
        .map((serial) => serial.inboundDate)
        .filter((value): value is string => Boolean(value))
        .sort()
      const earliestInboundDate = inboundDates[0]
      const latestInboundDate = inboundDates[inboundDates.length - 1]
      const gapDays = diffDays(latestInboundDate, item.quoteDate)
      const oldestStockAgeDays = Math.max(...(sku?.serials ?? []).map((serial) => serial.stockAgeDays ?? 0), 0)
      const urgency = item.estimatedProtectionAmount >= 1000 || item.unitDiff >= 500
        ? 'high'
        : item.estimatedProtectionAmount >= 300 || item.unitDiff >= 150
          ? 'medium'
          : 'low'
      const headline = urgency === 'high'
        ? '优先处理价保'
        : urgency === 'medium'
          ? '建议当日复核'
          : '列入今日跟进'
      const actionLine = item.currentStock >= 3
        ? '库存台数较多，优先申请价保并同步销售话术。'
        : '库存不大，但已有倒挂，建议先核对渠道价并锁定销售口径。'
      const timeLine = latestInboundDate
        ? `最近进货 ${formatDate(latestInboundDate)}，距本次价保日 ${gapDays ?? '待补'} 天`
        : '最近进货时间待补，建议先核对入库时间后再申请价保'
      const narrative = item.unitDiff >= 500
        ? `当前库存进货价明显高于当日实时进货价，每台高出 ${formatPrice(item.unitDiff)}。`
        : `当前库存进货价已高于当日实时进货价，每台高出 ${formatPrice(item.unitDiff)}。`
      const prompt = oldestStockAgeDays >= staleStockThresholdDays
        ? `最老库存已达 ${oldestStockAgeDays} 天，建议优先销售老库存并同步申请价保。`
        : oldestStockAgeDays >= 60
          ? `库存周期已拉长到 ${oldestStockAgeDays} 天，建议尽快完成价保复核。`
          : '库存周期仍可控，建议先完成价保登记，再统一调整销售策略。'
      const actionType = item.estimatedProtectionAmount >= 1000 || item.unitDiff >= 500
        ? 'apply_protection'
        : oldestStockAgeDays >= staleStockThresholdDays || item.currentStock >= 3
          ? 'prioritize_sales'
          : 'verify_purchase_price'
      const actionLabel = actionType === 'apply_protection'
        ? '申请价保'
        : actionType === 'prioritize_sales'
          ? '优先销售'
          : '先核对进货价'
      const actionSummary = actionType === 'apply_protection'
        ? '价差已经拉大，优先整理凭证并发起价保。'
        : actionType === 'prioritize_sales'
          ? '库存和周期压力同时存在，优先把这批货推到销售前排。'
          : '先确认最近一笔进货价和渠道报价，再决定是否申请价保。'
      const quoteEvidenceTitle = item.evidenceCaption
        ? item.evidenceCaption
        : `${item.quoteDate} 价保凭证`
      const quoteEvidenceNote = item.evidenceImagePath
        ? '已挂截图，可直接用于价保说明。'
        : item.quoteSourceFile
          ? `当前已挂当日报价文件：${shortFileName(item.quoteSourceFile)}`
          : '当前缺少价保截图，先保留文件证据位。'
      return {
        ...item,
        earliestInboundDate,
        latestInboundDate,
        gapDays,
        oldestStockAgeDays,
        urgency,
        headline,
        actionLine,
        timeLine,
        narrative,
        prompt,
        actionType,
        actionLabel,
        actionSummary,
        quoteEvidenceTitle,
        quoteEvidenceNote,
      }
      })
      .sort((a, b) => b.estimatedProtectionAmount - a.estimatedProtectionAmount || b.unitDiff - a.unitDiff)
  }, [liveSkuByKey, priceProtection])
  const topPriceProtectionCards = useMemo(() => priceProtectionCards.slice(0, 2), [priceProtectionCards])

  const quoteCollectionRows = useMemo(() => getQuoteCollectionRows(liveInventory), [liveInventory])
  type MarketplaceRecord = NonNullable<MarketplacePriceSnapshot['records']>[number]
  type ProductUrlLock = ProductUrlLockSnapshot['locks'][number]
  const marketplaceRecordsBySkuSource = new Map<string, MarketplaceRecord[]>()
  for (const item of marketplacePrices?.records ?? []) {
    const key = `${item.productId}:${item.source}`
    marketplaceRecordsBySkuSource.set(key, [...(marketplaceRecordsBySkuSource.get(key) ?? []), item])
  }
  const marketplaceSourceAudits = useMemo(() => ({
    jd: buildMarketplaceSourceAudit('jd', (marketplacePrices?.records ?? []).filter((item) => item.source === 'jd' && inStockSkuKeys.has(item.productId))),
    lenovo_official: buildMarketplaceSourceAudit('lenovo_official', (marketplacePrices?.records ?? []).filter((item) => item.source === 'lenovo_official' && inStockSkuKeys.has(item.productId))),
    taobao_subsidy: buildMarketplaceSourceAudit('taobao_subsidy', (marketplacePrices?.records ?? []).filter((item) => item.source === 'taobao_subsidy' && inStockSkuKeys.has(item.productId))),
  }), [inStockSkuKeys, marketplacePrices])
  const productUrlLocksBySkuSource = new Map<string, ProductUrlLock[]>()
  for (const lock of productUrlLocks?.locks ?? []) {
    if (!lock || typeof lock.source !== 'string' || typeof lock.url !== 'string' || typeof lock.skuKey !== 'string') continue
    const normalizedSource = lock.source === 'lenovo_official'
      ? 'lenovo_official'
      : lock.source.startsWith('jd_') ? 'jd' : undefined
    if (!normalizedSource || !isDirectProductUrl(lock.url) || lock.matchStatus === 'unavailable') continue
    const key = `${lock.skuKey}:${normalizedSource}`
    productUrlLocksBySkuSource.set(key, [...(productUrlLocksBySkuSource.get(key) ?? []), lock])
  }
  function getMarketplaceRecords(row: CollectionLinkRow, source: MarketplaceRecord['source']) {
    return marketplaceRecordsBySkuSource.get(`${row.skuKey}:${source}`) ?? []
  }
  function getMarketplaceRecordsBySkuKey(skuKey: string, source: MarketplaceRecord['source']) {
    return marketplaceRecordsBySkuSource.get(`${skuKey}:${source}`) ?? []
  }
  function normalizeMarketplaceColorSignal(value?: string) {
    const text = String(value ?? '')
    if (!text) return undefined
    if (/冰魄白|月幕白|白色|白/i.test(text)) return 'white'
    if (/碳晶黑|钛晶黑|幻影黑|黑色|黑/i.test(text)) return 'black'
    if (/深空灰|卷云灰|灰色|灰/i.test(text)) return 'gray'
    if (/霜雪银|银色|银/i.test(text)) return 'silver'
    return undefined
  }
  function getSkuMarketplaceColorSignal(row: CollectionLinkRow) {
    return normalizeMarketplaceColorSignal(`${getUnifiedItemDisplayTitle(row)} ${row.spec ?? ''} ${row.pnMtm ?? ''}`)
  }
  function isFreshMarketplaceRecord(record: MarketplaceRecord) {
    const capturedAt = record.evidence?.capturedAt
    if (!capturedAt) return false
    const parsed = Date.parse(capturedAt)
    if (!Number.isFinite(parsed)) return false
    return (Date.now() - parsed) / 36e5 <= marketplaceFreshnessHours
  }
  function getMarketplaceInspectionText(record: MarketplaceRecord) {
    return [
      record.matchTitle,
      record.query,
      record.priceBasis,
      record.evidence?.note,
      record.evidence?.evidenceUrl,
      record.configuredUrl,
      record.raw ? JSON.stringify(record.raw) : '',
    ].filter(Boolean).join(' ')
  }
  function isUsableMarketplaceRecord(row: CollectionLinkRow, record: MarketplaceRecord) {
    if (record.collectionStatus !== 'captured') return false
    if (!isFreshMarketplaceRecord(record)) return false
    const price = record.preSubsidyPrice ?? record.price
    const evidenceUrl = record.evidence.evidenceUrl ?? record.configuredUrl
    if (!price || !isDirectProductUrl(evidenceUrl)) return false
    const inspectionText = getMarketplaceInspectionText(record)
    if (/已下架|下架|待发布|待公布|暂不销售|无货|缺货|售罄|已抢光|到货通知|不可购买|停止销售|商品不存在/i.test(inspectionText)) return false
    const skuColor = getSkuMarketplaceColorSignal(row)
    const recordColor = normalizeMarketplaceColorSignal(inspectionText)
    if (skuColor && recordColor && skuColor !== recordColor) return false
    return !record.confidence
      || record.confidence === 'confirmed'
      || record.confidence === 'provisional'
      || record.confidence.startsWith('confirmed_')
      || record.confidence.startsWith('manual_review')
  }
  function getConfirmedMarketplaceRecordBySkuKey(skuKey: string, source: MarketplaceRecord['source']) {
    return getMarketplaceRecordsBySkuKey(skuKey, source)
      .slice()
      .sort((left, right) => Date.parse(right.evidence?.capturedAt ?? '') - Date.parse(left.evidence?.capturedAt ?? ''))
      .find((record) => {
        const row = liveSkuByKey.get(skuKey)
        return row ? isUsableMarketplaceRecord(row, record) : false
      })
  }
  function getConfirmedMarketplaceRecord(row: CollectionLinkRow, source: MarketplaceRecord['source']) {
    return getConfirmedMarketplaceRecordBySkuKey(row.skuKey, source)
  }
  function getDistributorQuoteHeroTitle(row: RetailZoneSnapshot['decisions']['items'][number], liveSku?: StandardInventorySku) {
    const rowSkuKey = row.skuKey?.trim()
    const candidatePnMtms = Array.from(new Set([
      row.pnMtm,
      liveSku?.pnMtm,
    ].map((value) => normalizeLookupKey(value)).filter(Boolean)))
    const quote = (distributorQuotes?.quotes ?? []).find((item) => {
      const quoteSkuKey = item.libraryMatch?.primarySkuKey?.trim()
      if (rowSkuKey && quoteSkuKey && quoteSkuKey === rowSkuKey) return true
      const quotePnMtm = normalizeLookupKey(item.pnMtm)
      return quotePnMtm && candidatePnMtms.includes(quotePnMtm)
    })
    const title = quote?.productName?.replace(/\s+/g, ' ').trim()
    return title || undefined
  }
  function getRetailHeroTitleParts(row: RetailZoneSnapshot['decisions']['items'][number], liveSku?: StandardInventorySku) {
    type TitleParts = { mainTitle: string; subtitle?: string; combinedTitle: string; evidenceState: 'structured' | 'parsed' | 'fallback' }
    const cleanPart = (value: unknown) => String(value ?? '').replace(/\s+/g, ' ').trim()
    const normalizeComparableTitle = (value: string) => value
      .toLowerCase()
      .replace(/[·/／｜|（）()【】\[\]\s,，、:-]/g, '')
      .replace(/gb/g, 'g')
      .replace(/tb/g, 't')
      .replace(/酷睿/g, '')
      .replace(/冰魄白|白色/g, '白')
      .replace(/碳晶黑|钛晶黑|黑色/g, '黑')
      .replace(/霜雪银|银色/g, '银')
      .replace(/凝雾灰|卷云灰|深空灰|信风灰|灰色/g, '灰')
      .replace(/天青色/g, '青')
      .replace(/浅海贝/g, '贝')
    const isUsefulSubtitle = (subtitle: string, mainTitle: string) => {
      const normalizedSubtitle = normalizeComparableTitle(subtitle)
      const normalizedMain = normalizeComparableTitle(mainTitle)
      if (!normalizedSubtitle || normalizedSubtitle === normalizedMain) return false
      return !normalizedMain.includes(normalizedSubtitle)
    }
    const mergeTitle = (mainTitle: string, subtitle?: string) => {
      const cleanMain = cleanPart(mainTitle)
      const cleanSubtitle = cleanPart(subtitle)
      if (!cleanMain) return cleanSubtitle
      if (!cleanSubtitle || !isUsefulSubtitle(cleanSubtitle, cleanMain)) return cleanMain
      return `${cleanMain} · ${cleanSubtitle}`
    }
    const toUnifiedTitleParts = (
      mainTitle: string,
      subtitle: string | undefined,
      evidenceState: TitleParts['evidenceState'],
    ): TitleParts => {
      const combinedTitle = mergeTitle(mainTitle, subtitle)
      return {
        mainTitle: combinedTitle,
        subtitle: undefined,
        combinedTitle,
        evidenceState,
      }
    }
    const canonicalRetailTitle = cleanPart(row.productName)
    if (canonicalRetailTitle) {
      return toUnifiedTitleParts(canonicalRetailTitle, undefined, 'structured')
    }
    const deriveTitlePartsFromMatchTitle = (value: string) => {
      const title = cleanPart(value)
      if (!title) return undefined
      const parentheticalMatch = title.match(/^(.*?)[(（]([^()（）]+)[)）]\s*([^\s()（）]+)?$/)
      if (parentheticalMatch) {
        const mainTitle = cleanPart(parentheticalMatch[1])
        const configText = cleanPart(parentheticalMatch[2])
        const tailText = cleanPart(parentheticalMatch[3])
        const subtitle = [configText, tailText].filter(Boolean).join(' / ')
        if (mainTitle && isUsefulSubtitle(subtitle, mainTitle)) {
          return toUnifiedTitleParts(mainTitle, subtitle, 'parsed')
        }
      }
      const configStartPattern = /(酷睿|锐龙|Ultra\s*\d|U\d{3,4}[A-Z]?|R\d{3,4}[A-Z]?|i[3579]-?\d{4,5}|R[3579]-?\d{3,5}|RTX\s*\d{4}|\d+\s*G(?:B)?\s+\d+\s*T(?:B)?|\d+\s*T(?:B)?\s+\d+\s*G(?:B)?|\d+(?:\.\d+)?K\s*\d+Hz|黑色|白色|灰色|深灰色|云影色|碳晶黑|冰魄白|钛晶黑|幻影黑|深空灰|霜雪银)/i
      const match = configStartPattern.exec(title)
      if (!match || match.index < 8) return undefined
      const mainTitle = cleanPart(title.slice(0, match.index))
      const subtitle = cleanPart(title.slice(match.index))
      if (!mainTitle || !isUsefulSubtitle(subtitle, mainTitle)) return undefined
      return toUnifiedTitleParts(mainTitle, subtitle, 'parsed')
    }
    const partsFromRaw = (
      matchTitle: string | undefined,
      raw: Record<string, unknown> | undefined,
      fallbackState: TitleParts['evidenceState'],
    ): TitleParts | undefined => {
      const parsedFromMatchTitle = deriveTitlePartsFromMatchTitle(cleanPart(matchTitle))
      const mainTitle = cleanPart(raw?.platformMainTitle)
        || cleanPart(raw?.mainTitle)
        || cleanPart(raw?.productTitle)
        || cleanPart(raw?.searchTitle)
        || parsedFromMatchTitle?.mainTitle
        || cleanPart(matchTitle)
      if (!mainTitle) return undefined
      const subtitleCandidates = [
        raw?.configSubtitle,
        raw?.selectedSpecText,
        raw?.visibleConfig,
        raw?.matchedConfig,
        raw?.configurationTitle,
        raw?.specTitle,
        raw?.subTitle,
        raw?.subtitle,
        raw?.subheading,
        raw?.viceTitle,
        raw?.sellingPoint,
        parsedFromMatchTitle?.subtitle,
      ].map(cleanPart).filter(Boolean)
      const subtitle = subtitleCandidates.find((item) => isUsefulSubtitle(item, mainTitle))
      const hasStructuredSubtitle = Boolean(cleanPart(raw?.platformMainTitle) && subtitle)
      return toUnifiedTitleParts(
        mainTitle,
        subtitle,
        hasStructuredSubtitle ? 'structured' : parsedFromMatchTitle?.subtitle ? 'parsed' : fallbackState,
      )
    }
    const getCapturedParts = (source: MarketplaceRecord['source']) => {
      const record = getConfirmedMarketplaceRecordBySkuKey(row.skuKey, source)
        ?? getMarketplaceRecordsBySkuKey(row.skuKey, source).find((item) => {
          const evidenceUrl = item.evidence.evidenceUrl ?? item.configuredUrl
          return item.collectionStatus === 'captured' && Boolean(item.matchTitle?.trim()) && isDirectProductUrl(evidenceUrl)
        })
      return partsFromRaw(record?.matchTitle, record?.raw as Record<string, unknown> | undefined, record ? 'fallback' : 'fallback')
    }
    const getLockedParts = (source: 'jd' | 'lenovo_official') => {
      const lock = (productUrlLocksBySkuSource.get(`${row.skuKey}:${source}`) ?? [])
        .sort((left, right) => {
          const leftLocked = left.matchStatus === 'locked' ? 1 : 0
          const rightLocked = right.matchStatus === 'locked' ? 1 : 0
          return rightLocked - leftLocked || right.priority - left.priority
        })
        .find((item) => Boolean(item.matchTitle?.trim()) && isDirectProductUrl(item.url))
      return partsFromRaw(lock?.matchTitle, lock?.raw as Record<string, unknown> | undefined, lock ? 'fallback' : 'fallback')
    }
    const preferred = [
      getCapturedParts('jd'),
      getLockedParts('jd'),
      getCapturedParts('lenovo_official'),
      getLockedParts('lenovo_official'),
    ].filter(Boolean) as TitleParts[]
    const bestStructured = preferred.find((item) => item.evidenceState === 'structured')
    if (bestStructured) return bestStructured
    const bestParsed = preferred.find((item) => item.evidenceState === 'parsed')
    if (bestParsed) return bestParsed
    const distributorTitle = getDistributorQuoteHeroTitle(row, liveSku)
    const fallbackMainTitle = preferred[0]?.mainTitle
      || cleanPart(distributorTitle)
      || cleanPart(liveSku?.productName)
      || cleanPart(row.productName)
      || row.skuKey
    const fallbackSubtitle = preferred[0]?.subtitle
      || cleanPart(liveSku?.spec)
      || cleanPart(row.pnMtm || liveSku?.pnMtm)
    return toUnifiedTitleParts(
      fallbackMainTitle,
      fallbackSubtitle && isUsefulSubtitle(fallbackSubtitle, fallbackMainTitle) ? fallbackSubtitle : undefined,
      preferred[0]?.evidenceState ?? 'fallback',
    )
  }
  function getRetailHeroDisplayTitle(row: RetailZoneSnapshot['decisions']['items'][number], liveSku?: StandardInventorySku) {
    const isEvidenceOnlyTitle = (value: unknown) => /系列家族页|可见子配置|家族详情页/.test(String(value ?? ''))
    const normalizeForTitleCompare = (value: string) => value
      .toLowerCase()
      .replace(/[·/／｜|（）()【】\[\]\s,，、:-]/g, '')
      .replace(/gb/g, 'g')
      .replace(/tb/g, 't')
      .replace(/酷睿/g, '')
      .replace(/冰魄白|白色/g, '白')
      .replace(/碳晶黑|钛晶黑|黑色/g, '黑')
      .replace(/霜雪银|银色/g, '银')
      .replace(/凝雾灰|卷云灰|深空灰|信风灰|灰色/g, '灰')
      .replace(/天青色/g, '青')
      .replace(/浅海贝/g, '贝')
    const looksLikeSpecOnlyPart = (value: string) => (
      /(?:ultra|i[3579]|r[579]|锐龙|酷睿).*(?:\d+g|1t|2t|rtx|uhd|oled|k屏|hz|黑|白)/i.test(value)
      || /(?:\d+g|1t|2t).*(?:rtx|uhd|oled|k屏|hz|黑|白)/i.test(value)
      || value.split(/[\/／]/).length >= 4
    )
    const isInventoryShorthandTitle = (title?: string) => {
      const normalizedTitle = normalizeForTitleCompare(String(title ?? ''))
      if (!normalizedTitle) return true
      const inventoryTitles = [row.productName, liveSku?.productName]
        .map((value) => normalizeForTitleCompare(String(value ?? '')))
        .filter(Boolean)
      return inventoryTitles.some((inventoryTitle) => inventoryTitle === normalizedTitle)
    }
    const normalizeHeroTitleParts = (parts: Array<unknown>) => {
      const normalizedParts = parts
      .flatMap((part) => String(part ?? '').replace(/\s+/g, ' ').trim().split(/\s+[·]\s+/g))
      .map((part) => part.trim())
      .filter(Boolean)
      .filter((part) => !isEvidenceOnlyTitle(part))
      .filter((part) => !/^(undefined|null|待补)$/i.test(part))
      const accepted: string[] = []
      const extractStorageTokens = (value: string) => Array.from(value.matchAll(/(?:\d+\s*(?:g|gb|t|tb)\s*[+＋/／]\s*)?\d+\s*(?:g|gb|t|tb)/gi))
        .map((match) => normalizeForTitleCompare(match[0]))
        .filter((token) => /\d/.test(token))
      const extractColorTokens = (value: string) => ['黑', '白', '灰', '银', '青', '贝', '粉', '绿', '蓝', '紫', '金']
        .filter((token) => normalizeForTitleCompare(value).includes(token))
      const hasOverlappingConfig = (left: string, right: string) => {
        const leftStorage = extractStorageTokens(left)
        const rightStorage = extractStorageTokens(right)
        const storageOverlaps = leftStorage.some((leftToken) => rightStorage.some((rightToken) => leftToken === rightToken || leftToken.includes(rightToken) || rightToken.includes(leftToken)))
        const leftColors = extractColorTokens(left)
        const rightColors = extractColorTokens(right)
        const colorOverlaps = !leftColors.length || !rightColors.length || leftColors.some((token) => rightColors.includes(token))
        return storageOverlaps && colorOverlaps
      }
      for (const part of normalizedParts) {
        const normalizedPart = normalizeForTitleCompare(part)
        if (accepted.some((existing) => {
          const normalizedExisting = normalizeForTitleCompare(existing)
          if (normalizedExisting.includes(normalizedPart) || normalizedPart.includes(normalizedExisting)) return true
          if (hasOverlappingConfig(existing, part) && (looksLikeSpecOnlyPart(part) || looksLikeSpecOnlyPart(existing))) return true
          return looksLikeSpecOnlyPart(part) && /(?:ultra|i[3579]|r[579]|锐龙|酷睿).*(?:rtx|uhd|oled|k屏|hz|黑|白)/i.test(existing)
        })) continue
        accepted.push(part)
      }
      return Array.from(new Set(accepted)).join(' · ')
    }
    const splitHeroTitleParts = (parts: Array<unknown>) => parts
      .flatMap((part) => String(part ?? '').replace(/\s+/g, ' ').trim().split(/\s+[·]\s+/g))
      .map((part) => part.trim())
      .filter(Boolean)
      .filter((part) => !isEvidenceOnlyTitle(part))
      .filter((part) => !/^(undefined|null|待补)$/i.test(part))
    const hasStorageToken = (value: string) => /(?:\d+\s*(?:G|GB|T|TB)\s*[+＋/／]\s*)?\d+\s*(?:G|GB|T|TB)/i.test(value)
    const hasColorToken = (value: string) => /(黑|白|灰|银|青|贝|粉|绿|蓝|紫|金|午夜|苍蓝|甘草|即墨|霜雪|凝雾|卷云|深空|天青|浅海|碳晶|冰魄)/i.test(value)
    const pickTabletPhoneDetailTitle = (title: string, parts: Array<unknown>) => {
      const normalizedTitle = normalizeForTitleCompare(title)
      const candidates = splitHeroTitleParts(parts)
        .filter((part) => !normalizeForTitleCompare(part) || !normalizedTitle.includes(normalizeForTitleCompare(part)))
        .filter((part) => hasStorageToken(part) || hasColorToken(part) || /TB\d|TAB|moto|Y700|Y900|Pad/i.test(part))
      const withStorageAndColor = candidates.find((part) => hasStorageToken(part) && hasColorToken(part))
      const withStorage = candidates.find((part) => hasStorageToken(part))
      const withModel = candidates.find((part) => /TB\d|TAB|Y700|Y900|Pad/i.test(part))
      return normalizeHeroTitleParts([withStorageAndColor ?? withStorage ?? withModel])
    }
    const distributorTitle = getDistributorQuoteHeroTitle(row, liveSku)
    const isTabletOrPhoneHero = /平板|手机|moto|智能生活/i.test([
      row.category,
      row.productName,
      liveSku?.productName,
      distributorTitle,
    ].filter(Boolean).join(' '))
    const enrichTabletPhoneTitle = (title?: string) => {
      if (!title) return undefined
      if (!isTabletOrPhoneHero) return title
      const titleAlreadyHasConfig = /(?:\d+\s*(?:G|GB|T|TB)\s*[+＋/／]\s*)?\d+\s*(?:G|GB|T|TB)/i.test(title)
        && /(黑|白|灰|银|青|贝|粉|绿|蓝|紫|金|午夜|苍蓝|甘草|即墨|霜雪|凝雾|卷云|深空|天青|浅海)/i.test(title)
      if (titleAlreadyHasConfig) return normalizeHeroTitleParts([title])
      const detailTitle = pickTabletPhoneDetailTitle(title, [
        distributorTitle,
        liveSku?.spec,
        liveSku?.productName,
        row.productName,
      ])
      if (!detailTitle) return title
      return normalizeHeroTitleParts([title, detailTitle])
    }
    const useCapturedTitle = (title?: string) => (title && !isInventoryShorthandTitle(title) ? enrichTabletPhoneTitle(title) : undefined)
    const composeMarketplaceTitle = (record?: MarketplaceRecord) => {
      if (!record) return undefined
      const raw = (record.raw ?? {}) as Record<string, unknown>
      const title = normalizeHeroTitleParts([
        record.matchTitle,
        raw.mainTitle,
        raw.productTitle,
        raw.searchTitle,
        raw.subTitle,
        raw.subtitle,
        raw.subheading,
        raw.viceTitle,
        raw.sellingPoint,
        raw.configurationTitle,
        raw.specTitle,
        raw.matchedConfig,
      ])
      return title || undefined
    }
    const composeLockTitle = (lock?: ProductUrlLock) => {
      if (!lock) return undefined
      const raw = (lock.raw ?? {}) as Record<string, unknown>
      const title = normalizeHeroTitleParts([
        lock.matchTitle,
        raw.mainTitle,
        raw.productTitle,
        raw.searchTitle,
        raw.subTitle,
        raw.subtitle,
        raw.subheading,
        raw.viceTitle,
        raw.sellingPoint,
        raw.configurationTitle,
        raw.specTitle,
        raw.matchedConfig,
      ])
      return title || undefined
    }
    const getCapturedTitle = (source: MarketplaceRecord['source']) => composeMarketplaceTitle(getConfirmedMarketplaceRecordBySkuKey(row.skuKey, source))
    const getFallbackCapturedTitle = (source: MarketplaceRecord['source']) => {
      const record = getMarketplaceRecordsBySkuKey(row.skuKey, source).find((record) => {
        const evidenceUrl = record.evidence.evidenceUrl ?? record.configuredUrl
        return record.collectionStatus === 'captured' && Boolean(record.matchTitle?.trim()) && isDirectProductUrl(evidenceUrl)
      })
      return composeMarketplaceTitle(record)
    }
    const getLockedTitle = (source: 'jd' | 'lenovo_official') => {
      const lock = (productUrlLocksBySkuSource.get(`${row.skuKey}:${source}`) ?? [])
      .sort((left, right) => {
        const leftLocked = left.matchStatus === 'locked' ? 1 : 0
        const rightLocked = right.matchStatus === 'locked' ? 1 : 0
        return rightLocked - leftLocked || right.priority - left.priority
      })
      .find((lock) => Boolean(lock.matchTitle?.trim()) && isDirectProductUrl(lock.url))
      return composeLockTitle(lock)
    }
    const structuredTitleParts = getRetailHeroTitleParts(row, liveSku)
    if (structuredTitleParts.evidenceState === 'structured') return structuredTitleParts.combinedTitle
    const jdTitle = useCapturedTitle(getCapturedTitle('jd')) ?? useCapturedTitle(getFallbackCapturedTitle('jd')) ?? useCapturedTitle(getLockedTitle('jd'))
    if (jdTitle) return jdTitle
    const lenovoTitle = useCapturedTitle(getCapturedTitle('lenovo_official')) ?? useCapturedTitle(getFallbackCapturedTitle('lenovo_official')) ?? useCapturedTitle(getLockedTitle('lenovo_official'))
    if (lenovoTitle) return lenovoTitle
    if (distributorTitle) return normalizeHeroTitleParts([distributorTitle])
    const inventoryFallbackTitle = normalizeHeroTitleParts([liveSku?.productName, row.productName, liveSku?.spec])
    if (isTabletOrPhoneHero && inventoryFallbackTitle) return inventoryFallbackTitle
    return liveSku?.productName?.trim() || row.productName
  }
  function getUnifiedSkuDisplayTitle(input: {
    skuKey: string
    productName?: string
    pnMtm?: string
    spec?: string
    category?: string
  }) {
    const publishedEntry = publishedProjectionBySkuKey.get(input.skuKey)
    const liveSku = liveSkuByKey.get(input.skuKey)
    const publishedDisplayTitle = publishedEntry?.displayTitle?.trim()
    const publishedProductName = publishedEntry?.productName?.trim()
    const preferPublishedDisplayTitle = publishedDisplayTitle && !/^\d{8}$/.test(publishedDisplayTitle)
      ? publishedDisplayTitle
      : undefined
    const preferPublishedProductName = publishedProductName && !/^\d{8}$/.test(publishedProductName)
      ? publishedProductName
      : undefined
    return preferPublishedDisplayTitle
      || preferPublishedProductName
      || liveSku?.productName?.trim()
      || input.productName?.trim()
      || input.pnMtm?.trim()
      || input.skuKey
  }
  function getUnifiedItemDisplayTitle(input: {
    skuKey?: string
    productName?: string
    pnMtm?: string
    spec?: string
    category?: string
  }) {
    if (input.skuKey) {
      return getUnifiedSkuDisplayTitle({
        skuKey: input.skuKey,
        productName: input.productName,
        pnMtm: input.pnMtm,
        spec: input.spec,
        category: input.category,
      })
    }
    return input.productName?.trim() || input.pnMtm?.trim() || '待补商品'
  }
  function getSourceUnavailableStatus(row: CollectionLinkRow | { skuKey: string }, source: MarketplaceRecord['source']) {
    const record = getMarketplaceRecordsBySkuKey(row.skuKey, source).find((item) => item.collectionStatus === 'unavailable')
    if (!record) return undefined
    const evidenceUrl = record.evidence.evidenceUrl ?? record.configuredUrl
    const raw = (record.raw ?? {}) as Record<string, unknown>
    const detail = [record.evidence.note, record.priceBasis, String(raw.blockingReason ?? '')].filter(Boolean).join(' ')
    const confirmedNoExactMatch = /no_exact_match_after_spec_check|确无同配|无目标同配/.test(detail)
    const sourceText = source === 'jd' || source === 'lenovo_official'
      ? (confirmedNoExactMatch ? '无同配' : '待同配复核')
      : '不可用'
    return {
      text: sourceText,
      detail: record.evidence.note ?? record.priceBasis,
      url: evidenceUrl,
    }
  }
  function getDirectCollectionUrl(row: CollectionLinkRow, source: MarketplaceRecord['source']) {
    const confirmedRecordUrl = getMarketplaceRecords(row, source)
      .filter((record) => record.collectionStatus === 'captured' && (!record.confidence || record.confidence === 'confirmed' || record.confidence === 'provisional' || record.confidence.startsWith('confirmed_')))
      .map((record) => record.evidence.evidenceUrl ?? record.configuredUrl)
      .find(isDirectProductUrl)
    if (confirmedRecordUrl) return confirmedRecordUrl
    const directRetailUrl = (
      source === 'jd'
        ? [((row as Partial<RetailZoneDecision>).jdUrl)]
        : source === 'lenovo_official'
          ? [((row as Partial<RetailZoneDecision>).lenovoUrl), ((row as Partial<RetailZoneDecision>).lenovoOfficialUrl)]
          : [((row as Partial<RetailZoneDecision>).tmallUrl)]
    ).find(isDirectProductUrl)
    if (directRetailUrl) return directRetailUrl
    const lockedUrl = (productUrlLocksBySkuSource.get(`${row.skuKey}:${source}`) ?? [])
      .sort((a, b) => {
        const aStatus = a.matchStatus === 'locked' ? 1 : 0
        const bStatus = b.matchStatus === 'locked' ? 1 : 0
        return bStatus - aStatus || b.priority - a.priority
      })
      .map((lock) => lock.url)
      .find(isDirectProductUrl)
    if (lockedUrl) return lockedUrl
    return getMarketplaceRecords(row, source)
      .map((record) => record.evidence.evidenceUrl ?? record.configuredUrl)
      .find(isDirectProductUrl)
  }
  function getFallbackCollectionUrl(row: CollectionLinkRow, source: MarketplaceRecord['source']) {
    const retailUrl = source === 'jd'
      ? (row as Partial<RetailZoneDecision>).jdUrl
      : source === 'lenovo_official'
        ? (row as Partial<RetailZoneDecision>).lenovoUrl ?? (row as Partial<RetailZoneDecision>).lenovoOfficialUrl
        : (row as Partial<RetailZoneDecision>).tmallUrl
    if (retailUrl) return retailUrl
    const lockedUrl = (productUrlLocksBySkuSource.get(`${row.skuKey}:${source}`) ?? [])
      .sort((a, b) => b.priority - a.priority)
      .map((lock) => lock.url)
      .find(Boolean)
    if (lockedUrl) return lockedUrl
    return getMarketplaceRecords(row, source)
      .map((record) => record.evidence.evidenceUrl ?? record.configuredUrl)
      .find((url): url is string => Boolean(url))
  }
  function getCollectionLinks(row: CollectionLinkRow) {
    const jdUrl = getDirectCollectionUrl(row, 'jd')
    const lenovoUrl = getDirectCollectionUrl(row, 'lenovo_official')
    const tmallUrl = getDirectCollectionUrl(row, 'taobao_subsidy')
    const jdFallbackUrl = jdUrl ? undefined : getFallbackCollectionUrl(row, 'jd')
    const lenovoFallbackUrl = lenovoUrl ? undefined : getFallbackCollectionUrl(row, 'lenovo_official')
    const tmallFallbackUrl = tmallUrl ? undefined : getFallbackCollectionUrl(row, 'taobao_subsidy')
    const shouldShowTmallBackup = Boolean(tmallUrl || tmallFallbackUrl || !jdUrl || !lenovoUrl)
    const isMoto = isMotoRetailRow(row)
    const isTablet = isTabletRetailRow(row)
    const isLegionTablet = isLegionTabletRetailRow(row)
    const shouldShowJdBackup = !jdUrl
    return {
      jd: {
        url: jdUrl ?? jdFallbackUrl,
        label: jdUrl ? '数据来源 直达详情页' : jdFallbackUrl ? '京东 仅入口' : '京东待锁定',
        locked: Boolean(jdUrl),
        title: jdUrl
          ? '京东数据来源：直达详情页'
          : jdFallbackUrl
            ? '京东当前只有搜索入口或候选页，仍可打开继续补锁详情页'
            : '京东还没有锁定真实商品详情页',
      },
      jdTablet: {
        url: shouldShowJdBackup && isTablet ? getJdBackupSearchUrl(row, 'tablet') : undefined,
        label: '平板京东补充',
        locked: false,
        title: '平板缺京东详情页时，先从联想/京东平板自营相关入口低频手工检索；只能写入同型号同配置详情页。',
      },
      jdMoto: {
        url: shouldShowJdBackup && isMoto ? getJdBackupSearchUrl(row, 'moto') : undefined,
        label: 'MOTO京东补充',
        locked: false,
        title: 'MOTO 手机缺京东详情页时，进入 MOTO 京东自营/官方自营相关入口低频手工检索；只能写入同型号同配置详情页。',
      },
      jdOfficial: {
        url: shouldShowJdBackup && (isTablet || isMoto) ? getJdBackupSearchUrl(row, 'lenovoOfficial') : undefined,
        label: '联想京东官店补充',
        locked: false,
        title: '联想官方旗舰店京东备用入口；默认店铺缺同配时再打开，不能把错配商品写入价格。',
      },
      jdLegion: {
        url: shouldShowJdBackup && isLegionTablet ? getJdBackupSearchUrl(row, 'legion') : undefined,
        label: '拯救者京东补充',
        locked: false,
        title: '拯救者官方旗舰店京东备用入口；Y700/Y900 等平板缺默认详情页时再打开核对。',
      },
      lenovo: {
        url: lenovoUrl ?? lenovoFallbackUrl,
        label: lenovoUrl ? '数据来源 直达详情页' : lenovoFallbackUrl ? '联想 仅入口' : '联想待锁定',
        locked: Boolean(lenovoUrl),
        title: lenovoUrl
          ? '联想官网数据来源：直达详情页'
          : lenovoFallbackUrl
            ? '联想官网当前只有搜索入口或候选页，仍可打开继续补锁详情页'
            : '联想官网还没有锁定真实商品详情页',
      },
      tmallLenovo: {
        url: tmallUrl ?? tmallFallbackUrl ?? (shouldShowTmallBackup ? getTmallStoreSearchUrl(row, 'lenovo') : undefined),
        label: tmallUrl ? '天猫补充 直达详情页' : tmallFallbackUrl ? '天猫补充 仅入口' : '联想天猫补充',
        locked: Boolean(tmallUrl),
        title: tmallUrl
          ? '天猫/淘宝补充来源：直达详情页'
          : tmallFallbackUrl
            ? '天猫/淘宝当前只有候选页，仍可打开继续补锁详情页'
            : '联想官方旗舰店天猫补充采集入口；仅采库存大于 0 且京东/官旗缺型号的 SKU',
      },
      tmallLecoo: {
        url: shouldShowTmallBackup ? getTmallStoreSearchUrl(row, 'lecoo') : undefined,
        label: '来酷天猫补充',
        locked: true,
        title: '来酷智生活旗舰店天猫补充采集入口；仅采库存大于 0 且京东/官旗缺型号的 SKU',
      },
      tmallMoto: {
        url: shouldShowTmallBackup && isMoto ? getTmallStoreSearchUrl(row, 'moto') : undefined,
        label: 'MOTO天猫补充',
        locked: true,
        title: 'MOTO 手机天猫/淘宝补充采集入口；京东 MOTO 自营或联想官旗缺同配时打开，不写错配价格。',
      },
    }
  }
  function renderSourceLink(
    link: { url?: string; label: string; locked: boolean; title: string },
    sourceClass: string,
    mark: string,
    compact = false,
    showDisabled = false,
  ) {
    const content = (
      <>
        <span>{mark}</span>
        {!compact && <em>{link.label}</em>}
        {link.url && <ExternalLink size={11} />}
      </>
    )
    return link.url ? (
      <a className={`source-icon-link ${sourceClass} ${link.locked ? 'locked' : 'pending'} ${compact ? 'compact' : ''}`} href={link.url} target="_blank" rel="noreferrer" title={link.title}>
        {content}
      </a>
    ) : showDisabled ? (
      <span className={`source-icon-link ${sourceClass} disabled ${compact ? 'compact' : ''}`} title={link.title}>
        {content}
      </span>
    ) : null
  }
  function renderSummaryTextLink(
    link: { url?: string; label: string; locked: boolean; title: string },
    fallbackLabel?: string,
  ) {
    if (!link.url) return null
    return (
      <a
        className={`summary-text-link ${link.locked ? 'locked' : 'pending'}`}
        href={link.url}
        target="_blank"
        rel="noreferrer"
        title={link.title}
      >
        {fallbackLabel || link.label}
      </a>
    )
  }
  function getEffectiveJdSelfPrice(row: StandardInventorySku) {
    const jdRecord = getConfirmedMarketplaceRecord(row, 'jd')
    return jdPriceMonitor[row.skuKey]?.jdSelfPrice
      ?? jdRecord?.preSubsidyPrice
      ?? jdRecord?.price
  }
  function getEffectiveLenovoOfficialPrice(row: StandardInventorySku) {
    const lenovoRecord = getConfirmedMarketplaceRecord(row, 'lenovo_official')
    return lenovoRecord?.preSubsidyPrice ?? lenovoRecord?.price
  }
  function getEffectiveTaobaoBackupPrice(row: CollectionLinkRow) {
    const taobaoRecord = getMarketplaceRecords(row, 'taobao_subsidy')
      .slice()
      .sort((left, right) => Date.parse(right.evidence?.capturedAt ?? '') - Date.parse(left.evidence?.capturedAt ?? ''))
      .find((record) => isUsableMarketplaceRecord(row, record))
    return taobaoRecord?.preSubsidyPrice ?? taobaoRecord?.price
  }
  const jdMonitorRows = useMemo(() => {
    return (liveInventory?.skus ?? [])
      .filter((row) => getDisplayTotalStock(row) > 0)
      .sort((a, b) => {
        const aHasCoreSource = getEffectiveJdSelfPrice(a) || getEffectiveLenovoOfficialPrice(a) ? 1 : 0
        const bHasCoreSource = getEffectiveJdSelfPrice(b) || getEffectiveLenovoOfficialPrice(b) ? 1 : 0
        return aHasCoreSource - bHasCoreSource || getDisplayTotalStock(b) - getDisplayTotalStock(a)
      })
  }, [liveInventory, jdPriceMonitor, marketplacePrices])
  function isMonitorRowSubsidyEligible(row: StandardInventorySku) {
    const jdPrice = getEffectiveJdSelfPrice(row)
    const lenovoOfficialPrice = getEffectiveLenovoOfficialPrice(row)
    return isSubsidyEligibleProduct({
      ...row,
      jdPrice,
      lenovoOfficialPrice,
    })
  }
  const subsidyMonitorRows = jdMonitorRows.filter(isMonitorRowSubsidyEligible)
  const nonSubsidyMonitorRows = jdMonitorRows.filter((row) => !isMonitorRowSubsidyEligible(row))
  const monitorCatalogBaseRows = activeMonitorCatalog === 'all'
    ? jdMonitorRows
    : activeMonitorCatalog === 'subsidy' ? subsidyMonitorRows : nonSubsidyMonitorRows
  const monitorCategoryOptions = Array.from(new Set(monitorCatalogBaseRows.map((row) => row.category || getProductFamily(row) || '未分类'))).sort()
  const effectiveMonitorCategory = monitorCategoryOptions.includes(selectedMonitorCategory) ? selectedMonitorCategory : '全部'
