      const salesDate = String(item.salesDate || item.outboundDate || '')
      const day = salesDate.slice(0, 10)
      if (salesComplianceDateFrom && day && day < salesComplianceDateFrom) return false
      if (salesComplianceDateTo && day && day > salesComplianceDateTo) return false
      if (salesComplianceProductLineFilter !== 'all' && item.productLine !== salesComplianceProductLineFilter) return false
      if (salesComplianceStatusFilter === 'pass' && item.status !== 'compliant_pass') return false
      if (salesComplianceStatusFilter === 'warning' && !String(item.status).startsWith('warning')) return false
      if (salesComplianceStatusFilter === 'blocked' && !String(item.status).startsWith('blocked')) return false
      if (salesComplianceActivityFilter === 'po' && !item.validation?.poEligible) return false
      if (salesComplianceActivityFilter === 'education' && !item.validation?.educationEligible) return false
      if (salesComplianceActivityFilter === 'priceProtection' && !item.validation?.priceProtectionReady) return false
      if (salesComplianceActivityFilter === 'claimable' && !Number(item.claimableAmount ?? 0)) return false
