  function handleAdminLogout() {
    setAdminAuth({ authenticated: true, username: 'admin', displayName: '系统管理直达' })
    setAdminStatusMessage('系统管理当前为免密直达模式，已保留设置页可见。')
  }

  function getActivityCardDraft(
    activityId: string,
    skuKey: string,
    defaults: {
      marketingPoEnabled: boolean
      marketingPoAmount: number | null
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: number | null
    },
  ) {
    const draftKey = buildFrontendActivityOverrideKey(activityId, skuKey)
    const existing = activityCardDrafts[draftKey]
    if (existing) return existing
    const override = frontendActivityDisplayOverrideMap.get(draftKey) ?? frontendActivityDisplayOverrideMap.get(skuKey)
    return {
      marketingPoEnabled: override?.marketingPoEnabled ?? defaults.marketingPoEnabled,
      marketingPoAmount: override?.marketingPoAmount != null
        ? String(override.marketingPoAmount)
        : defaults.marketingPoAmount != null
          ? String(defaults.marketingPoAmount)
          : '',
      educationSubsidyEnabled: override?.educationSubsidyEnabled ?? defaults.educationSubsidyEnabled,
      educationSubsidyAmount: override?.educationSubsidyAmount != null
        ? String(override.educationSubsidyAmount)
        : defaults.educationSubsidyAmount != null
          ? String(defaults.educationSubsidyAmount)
          : '',
      note: override?.note ?? '',
    }
  }

  function patchActivityCardDraft(
    activityId: string,
    skuKey: string,
    defaults: {
      marketingPoEnabled: boolean
      marketingPoAmount: number | null
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: number | null
    },
    patch: Partial<{
      marketingPoEnabled: boolean
      marketingPoAmount: string
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: string
      note: string
    }>,
  ) {
    const draftKey = buildFrontendActivityOverrideKey(activityId, skuKey)
    setActivityCardDrafts((current) => ({
      ...current,
      [draftKey]: {
        ...getActivityCardDraft(activityId, skuKey, defaults),
        ...(current[draftKey] ?? {}),
        ...patch,
      },
    }))
  }

  async function handleSaveInlineActivityCard(
    activityId: string,
    skuKey: string,
    defaults: {
      marketingPoEnabled: boolean
      marketingPoAmount: number | null
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: number | null
    },
  ) {
    const draft = getActivityCardDraft(activityId, skuKey, defaults)
    await persistActivityCardDraft(activityId, skuKey, draft)
  }

  async function refreshFrontendActivityDisplayViews() {
    const [retailZoneSnapshot, projectionSnapshot, marketingSnapshot] = await Promise.all([
      getRetailZoneSnapshot({ compact: true }),
      getPublishedProductProjectionSnapshot(),
      getMarketingBoostHeroSnapshot(),
    ])
    if (retailZoneSnapshot) setRetailZone(retailZoneSnapshot)
    if (projectionSnapshot) setPublishedProjection(projectionSnapshot)
    if (marketingSnapshot) setMarketingBoost(marketingSnapshot)
  }

  async function persistActivityCardDraft(
    activityId: string,
    skuKey: string,
    draft: {
      marketingPoEnabled: boolean
      marketingPoAmount: string
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: string
      note: string
    },
  ) {
    const marketingAmount = draft.marketingPoAmount.trim() ? Number(draft.marketingPoAmount) : null
    const educationAmount = draft.educationSubsidyAmount.trim() ? Number(draft.educationSubsidyAmount) : null
    if (marketingAmount !== null && (!Number.isFinite(marketingAmount) || marketingAmount < 0)) {
      setAdminStatusMessage(`SKU ${skuKey} 的营销PO金额格式不正确。`)
      return false
    }
    if (educationAmount !== null && (!Number.isFinite(educationAmount) || educationAmount < 0)) {
      setAdminStatusMessage(`SKU ${skuKey} 的教育补金额格式不正确。`)
      return false
    }
    const result = await saveFrontendActivityDisplayOverride({
      activityId,
      skuKey,
      marketingPoEnabled: draft.marketingPoEnabled,
      marketingPoAmount: marketingAmount,
      educationSubsidyEnabled: draft.educationSubsidyEnabled,
      educationSubsidyAmount: educationAmount,
      note: draft.note.trim(),
    })
    if (!result) {
      setAdminStatusMessage(`SKU ${skuKey} 前端展示控制保存失败。`)
      return false
    }
    setFrontendActivityDisplayOverrides(result)
    setAdminStatusMessage(`SKU ${skuKey} 前端展示控制已更新。`)
    await refreshFrontendActivityDisplayViews()
    return true
  }

  function setActivityCardSavingState(activityId: string, skuKey: string, saving: boolean) {
    const draftKey = buildFrontendActivityOverrideKey(activityId, skuKey)
    setActivityCardSavingKeys((current) => {
      if (saving) {
        return {
          ...current,
          [draftKey]: true,
        }
      }
      if (!current[draftKey]) return current
      const next = { ...current }
      delete next[draftKey]
      return next
    })
  }

  function queueActivityCardAutoSave(
    activityId: string,
    skuKey: string,
    defaults: {
      marketingPoEnabled: boolean
      marketingPoAmount: number | null
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: number | null
    },
    patch: Partial<{
      marketingPoAmount: string
      educationSubsidyAmount: string
      note: string
    }>,
  ) {
    patchActivityCardDraft(activityId, skuKey, defaults, patch)
    const draftKey = buildFrontendActivityOverrideKey(activityId, skuKey)
    const existingTimer = activityCardAutoSaveTimersRef.current[draftKey]
    if (existingTimer) clearTimeout(existingTimer)
    setActivityCardSavingState(activityId, skuKey, true)
    activityCardAutoSaveTimersRef.current[draftKey] = setTimeout(async () => {
      delete activityCardAutoSaveTimersRef.current[draftKey]
      const latestDraft = getActivityCardDraft(activityId, skuKey, defaults)
      const saved = await persistActivityCardDraft(activityId, skuKey, latestDraft)
      setActivityCardSavingState(activityId, skuKey, false)
      if (!saved) return
    }, 450)
  }

  async function handleToggleInlineActivityCard(
    activityId: string,
    skuKey: string,
    defaults: {
      marketingPoEnabled: boolean
      marketingPoAmount: number | null
      educationSubsidyEnabled: boolean
      educationSubsidyAmount: number | null
    },
    patch: Partial<{
      marketingPoEnabled: boolean
      educationSubsidyEnabled: boolean
    }>,
  ) {
    const previousDraft = getActivityCardDraft(activityId, skuKey, defaults)
    const nextDraft = {
      ...previousDraft,
      ...patch,
    }
    patchActivityCardDraft(activityId, skuKey, defaults, patch)
    const saved = await persistActivityCardDraft(activityId, skuKey, nextDraft)
    if (!saved) {
      setActivityCardDrafts((current) => ({
        ...current,
        [buildFrontendActivityOverrideKey(activityId, skuKey)]: previousDraft,
      }))
    }
  }

  useEffect(() => () => {
    Object.values(activityCardAutoSaveTimersRef.current).forEach((timer) => clearTimeout(timer))
    activityCardAutoSaveTimersRef.current = {}
  }, [])


